class TestJointGraphDeviceTags:
    """PF.1 / B1' regression — the joint graph reaching the AOT-autograd
    partitioner must carry vulkan device tags on every Tensor val whose
    ancestors are vulkan inputs. The narrow factory-op rewrite (P8.1.a)
    fixed device kwargs but left downstream consumer vals stamped meta —
    the partitioner's ``get_device`` (`partitioners.py:1721`) then read
    those meta vals and produced an empty backward graph (canonical 0.5×
    wrong-gradient symptom).

    Stage tag: ``BUG_ROOT="partitioner"``.
    """

    _BUG_ROOT_COMPONENT = "partitioner"

    def _capture_joint_graph(self, fn, *inputs):
        """Run the chained joint_custom_pass for ``fn`` and return the
        joint FX graph as observed AFTER our pass runs (i.e. the graph
        the partitioner sees)."""
        import torch._functorch.config as _fc

        captured = {}
        prev = _fc.joint_custom_pass

        def _capture(fx_g, joint_inputs):
            # Let our installed pass run first (chains existing).
            if callable(prev):
                fx_g = prev(fx_g, joint_inputs)
            captured["fx_g"] = fx_g
            return fx_g

        _fc.joint_custom_pass = _capture
        try:
            out = fn(*inputs)
            if hasattr(out, "sum"):
                out.sum().backward(retain_graph=False)
            elif hasattr(out, "backward"):
                out.backward()
        except Exception:
            # We only care that the joint pass fired; downstream Inductor
            # JIT failures are not the target of this graph-state test.
            pass
        finally:
            _fc.joint_custom_pass = prev
        return captured.get("fx_g")

    def _assert_no_meta_consumers(self, fx_g):
        """Every node whose Tensor inputs are vulkan must itself produce
        vulkan vals — no meta-device FakeTensors from interior nodes."""
        import torch._subclasses.fake_tensor as _ft

        def _has_vulkan(val):
            if isinstance(val, torch.Tensor):
                return val.device.type == "vulkan"
            if isinstance(val, (list, tuple)):
                return any(_has_vulkan(v) for v in val)
            return False

        def _has_meta(val):
            if isinstance(val, torch.Tensor):
                return val.device.type == "meta"
            if isinstance(val, (list, tuple)):
                return any(_has_meta(v) for v in val)
            return False

        offenders = []
        for node in fx_g.graph.nodes:
            if node.op != "call_function":
                continue
            val = node.meta.get("val")
            if not _has_meta(val):
                continue
            for inp in node.all_input_nodes:
                if _has_vulkan(inp.meta.get("val")):
                    offenders.append((node.name, str(node.target)))
                    break
        assert not offenders, (
            f"PF.1 regression: {len(offenders)} consumer nodes still carry "
            f"meta-device vals despite vulkan inputs. First few: {offenders[:5]}"
        )

    def test_sum_of_square_plus_one_joint_graph_is_vulkan(self):
        """``(x*x+1).sum()`` joint graph must be entirely vulkan post-pass."""

        @torch.compile(backend="inductor", dynamic=False, fullgraph=True)
        def fn(x):
            return (x * x + 1.0).sum()

        x = torch.randn(8, 16, device="vulkan:0", requires_grad=True)
        fx_g = self._capture_joint_graph(fn, x)
        if fx_g is None:
            pytest.skip("joint_custom_pass did not fire (no joint graph captured)")
        self._assert_no_meta_consumers(fx_g)

    def test_linear_relu_joint_graph_is_vulkan(self):
        """Linear+ReLU joint graph must be entirely vulkan post-pass."""
        import torch.nn.functional as F

        @torch.compile(backend="inductor", dynamic=False, fullgraph=True)
        def fn(x, w, b):
            return F.relu(F.linear(x, w, b)).sum()

        x = torch.randn(4, 32, device="vulkan:0", requires_grad=True)
        w = torch.randn(16, 32, device="vulkan:0", requires_grad=True)
        b = torch.randn(16, device="vulkan:0", requires_grad=True)
        fx_g = self._capture_joint_graph(fn, x, w, b)
        if fx_g is None:
            pytest.skip("joint_custom_pass did not fire (no joint graph captured)")
        self._assert_no_meta_consumers(fx_g)


