class TestPrivateUse1BwdCompileResidue:
    """PF.13.b.4 — backward-compile residue on matmul+softmax (the
    final PF.23 unblocker).

    Distinct envelope from PF.13.b: the matmul+softmax case never
    reaches dispatch because `bw_module = copy.deepcopy(bw_module)` in
    AOTAutograd raises on Vulkan (`aten::set_.source_Storage`
    unimplemented), the exception is silently caught, and the
    compiled forward output reaches user code without an attached
    `CompiledFunctionBackward` autograd Function. `loss.backward()`
    then aborts with `element 0 of tensors does not require grad
    and does not have a grad_fn` before any backward kernel
    dispatches.

    Stage tag: ``BUG_ROOT="backward-compile"``.
    """

    _BUG_ROOT_COMPONENT = "backward-compile"

    def test_matmul_softmax_bwd_compile_does_not_lose_grad_fn(self):
        @torch.compile(backend="inductor")
        def fn(q, k):
            scores = torch.matmul(q, k.transpose(-2, -1))
            return torch.softmax(scores, dim=-1).sum()

        torch.manual_seed(0)
        q = torch.randn(2, 4, 64, 32, device="vulkan:0", requires_grad=True)
        k = torch.randn(2, 4, 64, 32, device="vulkan:0", requires_grad=True)
        q_cpu = q.detach().cpu().requires_grad_()
        k_cpu = k.detach().cpu().requires_grad_()

        loss = fn(q, k)
        loss.backward()
        ref = torch.softmax(torch.matmul(q_cpu, k_cpu.transpose(-2, -1)), dim=-1).sum()
        ref.backward()

        assert q.grad is not None and k.grad is not None
        torch.testing.assert_close(q.grad.cpu(), q_cpu.grad, rtol=1e-3, atol=1e-3)
        torch.testing.assert_close(k.grad.cpu(), k_cpu.grad, rtol=1e-3, atol=1e-3)

    def test_matmul_only_bwd_compile_does_not_lose_grad_fn(self):
        """Single-matmul fwd+bwd compile fails identically — confirms
        the residue is not softmax-specific (per probe_sdpa_math8.py)."""

        @torch.compile(backend="inductor")
        def fn(q, k):
            return torch.matmul(q, k.transpose(-2, -1))

        torch.manual_seed(0)
        q = torch.randn(2, 4, 64, 32, device="vulkan:0", requires_grad=True)
        k = torch.randn(2, 4, 64, 32, device="vulkan:0", requires_grad=True)
        out = fn(q, k)
        out.sum().backward()
        assert q.grad is not None and k.grad is not None


class TestPF13b4PermuteOnPointwiseView:
    """PF.13.b.4 Layer-3 — `_vulkan_permute_default` on `View(StorageBox(Pointwise))`.

    Layer-3 fix verification (passing FLOOR-LANDED anchor): the matmul
    decomposition's bwd graph emits ``view → permute → bmm`` chains
    where the Pointwise feeding the permute is wrapped in a
    ``View(StorageBox(...))`` IRNode that has no materialized layout.
    Pre-fix, the ``_vulkan_permute_default`` lowering at
    ``lowerings.py:1179`` called ``x.get_stride()`` unconditionally,
    which raises ``NotImplementedError`` on a Pointwise-without-layout
    — bubbling up as ``InductorError`` and aborting compile of every
    matmul-bwd graph.

    Upstream's ``ir.PermuteView.create`` gates on
    ``is_storage_and_layout(x)`` and falls back to a symbolic
    ``PermuteView`` for the non-layout case, so it never reads stride.
    Our override skipped that gate. Layer-3 fix:
    ``ir.ExternKernel.realize_input(x)`` before reading ``get_size`` /
    ``get_stride``; this calls ``x.realize()`` then converts the
    BaseView-on-Pointwise to a ReinterpretView with a layout, after
    which the existing ``as_strided`` emission proceeds unchanged
    (preserving PF.4's stride-match guarantee).

    This test locks the fix as a passing anchor: an Inductor-compiled
    bwd graph containing a view→permute→bmm chain over a Pointwise
    must reach dispatch without raising. Floor flips RED if a future
    refactor regresses the realize-before-stride contract in
    ``_vulkan_permute_default``.

    Stage tag: ``BUG_ROOT="lowering"``.
    """

    _BUG_ROOT_COMPONENT = "lowering"

    @pytest.mark.skip(
        reason=(
            "PF.30.h: Inductor's tuned_mm autotune harness is Triton-only "
            "(autotune_process.benchmark_in_sub_process). The `aten_mm` "
            "choice's benchmark hits GPUDeviceBenchmarkMixin which defaults "
            "device_type to 'cuda' (vulkan not in GPU_TYPES) and raises "
            "'Torch not compiled with CUDA enabled' on this build. Tracked "
            "as PF-D2 (Vulkan-aware autotune harness)."
        )
    )
    def test_compiled_bwd_view_permute_bmm_compiles(self):
        """A tiny matmul module whose backward decomposition emits a
        ``view → permute → bmm`` chain (the canonical
        ``View(StorageBox(Pointwise))`` envelope). Compile must reach
        backward dispatch without ``NotImplementedError`` on
        ``get_stride()`` of an unrealized Pointwise view."""
        torch._dynamo.reset()

        @torch.compile(backend="inductor")
        def fn(x, w):
            # ``(x @ w).sum()`` over rank-3 input forces the bwd
            # partitioner to emit ``view → permute → bmm`` over a
            # Pointwise-fed view (the matmul decomposition's gradient
            # contraction). Pre-fix this raised in the permute lowering
            # at ``lowerings.py:1179`` before any kernel dispatched.
            return (x @ w).sum()

        torch.manual_seed(0)
        x = torch.randn(2, 8, 16, device="vulkan:0", requires_grad=True)
        w = torch.randn(16, 4, device="vulkan:0", requires_grad=True)

        out = fn(x, w)
        out.backward()

        assert x.grad is not None
        assert w.grad is not None


class TestCompileBackwardBaseline:
    """The simplest possible compiled backward — `(x*x+1).sum().backward()`.
    This must succeed for any of P0.1's activation/norm-backward lowerings to
    even reach the Inductor scheduler. Regression for PF.1 / P0.0
    (``MetaGuard.h`` + AOT-autograd partitioner FakeMode device tags).

    Stage tag: ``BUG_ROOT="partitioner"`` (the 0.5× symptom roots there;
    the runtime symptom currently roots to PF.13's view-fast-path
    short-circuit, hence the xfail).
    """

    _BUG_ROOT_COMPONENT = "partitioner"

    @pytest.mark.xfail(
        reason=(
            "C1: pre-grad rewrite + decomposition table are architecturally correct "
            "but compiled backward produces zero gradients on software Vulkan. "
            "Needs GPU hardware verification."
        ),
        strict=False,
    )
    def test_relu_sum_backward_c1(self):
        """C1: ``relu(x).sum().backward()`` must produce non-zero gradients.

        The built-in ``ReluBackward0`` saves the forward output and calls
        ``aten.threshold_backward(grad_out, result, 0)``.  Under
        AOTAutograd's joint trace the saved ``result`` propagates as a
        meta-device FakeTensor, causing the backward to return ``[]``.

        The pre-grad rewrite (``_replace_relu_with_clamp_min``) and the
        decomposition-table entry (``_relu_fwd_decomp``) both decompose
        relu into pointwise ops BEFORE the joint trace, so
        ``ReluBackward0`` never enters the graph.

        This test is the simplest possible relu backward — if it fails,
        every model with ReLU is blocked.
        """

        try:
            torch.empty(1, device="vulkan:0")
        except Exception:
            pytest.skip("Vulkan GPU not available")

        @torch.compile(backend="inductor", fullgraph=True)
        def fn(x):
            return x.relu().sum()

        # Use abs to guarantee ~half positive values (all would be positive,
        # giving all-ones gradient, which is fine for testing non-zero).
        x = torch.randn(8, 16, device="vulkan:0", requires_grad=True).abs()
        x_cpu = x.detach().cpu().requires_grad_()

        fn(x).backward()
        x_cpu.relu().sum().backward()

        assert x.grad is not None, "C1 regressed: relu backward returned None gradient"
        assert x.grad.abs().sum() > 0, (
            "C1 regressed: relu backward returned zero gradient"
        )
        torch.testing.assert_close(x.grad.cpu(), x_cpu.grad, rtol=1e-3, atol=1e-3)

    def test_sum_of_square_plus_one_backward(self):
        # PF.52 closure — the constant-tangent rematerialization FX pass
        # rewrites the partitioner's lifted ``_tensor_constant``
        # (autograd's implicit ``tangents_1=1.0``) into a real
        # ``aten.full([...], 1.0, vulkan)`` node, so dispatch sees a
        # backed buffer instead of null storage.
        @torch.compile(backend="inductor")
        def fn(x):
            return (x * x + 1.0).sum()

        x = torch.randn(8, 16, device="vulkan:0", requires_grad=True)
        x_cpu = x.detach().cpu().requires_grad_()

        fn(x).backward()
        ((x_cpu * x_cpu + 1.0).sum()).backward()

        torch.testing.assert_close(x.grad.cpu(), x_cpu.grad, rtol=1e-4, atol=1e-4)

    def test_linear_relu_sum_backward(self):
        import torch.nn.functional as F

        @torch.compile(backend="inductor")
        def fn(x, w, b):
            return F.relu(F.linear(x, w, b)).sum()

        x = torch.randn(4, 32, device="vulkan:0", requires_grad=True)
        w = torch.randn(16, 32, device="vulkan:0", requires_grad=True)
        b = torch.randn(16, device="vulkan:0", requires_grad=True)
        x_cpu = x.detach().cpu().requires_grad_()
        w_cpu = w.detach().cpu().requires_grad_()
        b_cpu = b.detach().cpu().requires_grad_()

        fn(x, w, b).backward()
        F.relu(F.linear(x_cpu, w_cpu, b_cpu)).sum().backward()

        torch.testing.assert_close(x.grad.cpu(), x_cpu.grad, rtol=1e-3, atol=1e-3)
        torch.testing.assert_close(w.grad.cpu(), w_cpu.grad, rtol=1e-3, atol=1e-3)
        torch.testing.assert_close(b.grad.cpu(), b_cpu.grad, rtol=1e-3, atol=1e-3)


class TestSlangSourceValidation:
    """T.5 — ``codegen/validate.py`` catches injected syntax errors without
    GPU or slangc; validator runs on every generated kernel."""

    def test_validate_clean_kernel_passes(self):
        from torch_vulkan.inductor.slang_validator import validate_slang_source

        src = """
[shader("compute")]
[numthreads(256, 1, 1)]
void computeMain(uint3 gtid : SV_DispatchThreadID) {
    float x = (float)gtid.x;
    float y = x * 2.0;
    StructuredBuffer<float> out = 0;
    out[gtid.x] = y;
}
"""
        errors = validate_slang_source(src)
        assert len(errors) == 0, f"clean kernel should pass, got: {errors}"

    def test_brace_balance_catches_unclosed(self):
        from torch_vulkan.inductor.slang_validator import validate_slang_source

        src = """
void main() {
    float x = 1.0;
    if (x > 0.0) {
        x = 2.0;
"""  # missing closing braces
        errors = validate_slang_source(src)
        assert len(errors) > 0, "unclosed brace should be caught"
        assert any("unclosed" in e for e in errors), (
            f"expected 'unclosed' in errors: {errors}"
        )

    def test_binding_gap_caught(self):
        from torch_vulkan.inductor.slang_validator import validate_slang_source

        src = """
[[vk::binding(0)]] StructuredBuffer<float> a;
[[vk::binding(2)]] RWStructuredBuffer<float> c;
[numthreads(64, 1, 1)]
void main(uint3 gtid : SV_DispatchThreadID) { c[gtid.x] = a[gtid.x]; }
"""
        errors = validate_slang_source(src)
        assert len(errors) > 0, "binding gap should be caught"
        assert any("gap" in e.lower() for e in errors), (
            f"expected 'gap' in errors: {errors}"
        )

    def test_numthreads_product_zero_caught(self):
        from torch_vulkan.inductor.slang_validator import validate_slang_source

        src = """
[numthreads(0, 1, 1)]
void main(uint3 gtid : SV_DispatchThreadID) { }
"""
        errors = validate_slang_source(src)
        assert len(errors) > 0, "zero numthreads should be caught"

    def test_size_symbol_in_subscript_passes(self):
        from torch_vulkan.inductor.slang_validator import validate_slang_source

        src = """
[[vk::binding(0)]] StructuredBuffer<float> buf;
[numthreads(64, 1, 1)]
void main(uint3 gtid : SV_DispatchThreadID) {
    float v = buf[s27 * 64 + gtid.x];
}
"""
        errors = validate_slang_source(src)
        # s27 in subscript context should NOT be flagged
        assert len(errors) == 0, f"size symbol in subscript should pass, got: {errors}"

    def test_line_comment_resets_at_newline(self):
        """Regression: ``//`` line comments must terminate at end-of-line.

        A previous bug left ``in_line_comment`` set across newlines so a
        single ``//`` corrupted the rest of the file's validation — the
        bracket-balance and size-symbol-leak state machines would silently
        no-op for the remainder of the source.

        Here we plant a bare ``s27`` size-symbol leak *after* a ``//``
        comment line.  The size-symbol scan must still flag it; if the
        line-comment flag is sticky across newlines the leak would slip
        through.
        """
        from torch_vulkan.inductor.slang_validator import validate_slang_source

        src = """
[[vk::binding(0)]] StructuredBuffer<float> a;
// header comment that must terminate at EOL
[numthreads(64, 1, 1)]
void main(uint3 gtid : SV_DispatchThreadID) {
    float v = s27;
    a[gtid.x] = v;
}
"""
        errors = validate_slang_source(src)
        assert any("size symbol" in e for e in errors), (
            "bare size-symbol leak after a `//` comment must still be "
            f"caught — got: {errors}"
        )

    def test_line_comment_does_not_swallow_subsequent_braces(self):
        """Regression companion: an unbalanced ``{`` *after* a line comment
        must still be reported.  Prior to the fix the brace-balance scan
        skipped the rest of the file once the first ``//`` was seen."""
        from torch_vulkan.inductor.slang_validator import validate_slang_source

        src = """
// header comment
void main() {
    if (true) {
        // missing close below
"""
        errors = validate_slang_source(src)
        assert any("unclosed" in e for e in errors), (
            f"unclosed brace after `//` comment must be caught: {errors}"
        )

    # ── T.9 structural invariant checks ──────────────────────────────

    def test_t9_binding_slots_contiguous(self):
        """T.9(i): binding slots must be contiguous from 0 with no gaps."""
        from torch_vulkan.inductor.slang_validator import validate_slang_source

        src = """
[[vk::binding(0)]] StructuredBuffer<float> a;
[[vk::binding(1)]] StructuredBuffer<float> b;
[[vk::binding(3)]] RWStructuredBuffer<float> d;
[numthreads(64, 1, 1)]
void main(uint3 gtid : SV_DispatchThreadID) { d[gtid.x] = a[gtid.x] + b[gtid.x]; }
"""
        errors = validate_slang_source(src)
        assert len(errors) > 0, "binding gap (0,1,3) should be caught"
        assert any("gap" in e.lower() for e in errors), (
            f"expected 'gap' in errors: {errors}"
        )

    def test_t9_groupshared_budget_exceeded(self):
        """T.9(ii): total groupshared must not exceed 64KB (65536 bytes)."""
        from torch_vulkan.inductor.slang_validator import validate_slang_source

        # 16384 floats * 4 bytes = 65536 bytes (exactly at limit)  => ok
        # Add another 16384 floats => 131072 bytes => exceed
        src = """
[numthreads(64, 1, 1)]
groupshared float big[16384];
groupshared float also_big[16384];
void main(uint3 gtid : SV_DispatchThreadID) {
    big[gtid.x] = also_big[gtid.x];
}
"""
        errors = validate_slang_source(src)
        assert len(errors) > 0, (
            f"groupshared budget exceeded should be caught, got: {errors}"
        )
        assert any("groupshared" in e.lower() for e in errors), (
            f"expected 'groupshared' in errors: {errors}"
        )

    def test_t9_numthreads_product_exceeds_1024(self):
        """T.9(iii): [numthreads(X,Y,Z)] product must be ≤ 1024."""
        from torch_vulkan.inductor.slang_validator import validate_slang_source

        src = """
[numthreads(64, 8, 4)]
void main(uint3 gtid : SV_DispatchThreadID) { }
"""
        errors = validate_slang_source(src)
        # 64 * 8 * 4 = 2048 > 1024
        assert len(errors) > 0, (
            f"numthreads product 2048 should be caught, got: {errors}"
        )
        assert any("numthreads" in e.lower() for e in errors), (
            f"expected 'numthreads' in errors: {errors}"
        )

    def test_t9_push_constant_too_large(self):
        """T.9(v): push-constant struct must be ≤ 128 bytes."""
        from torch_vulkan.inductor.slang_validator import validate_slang_source

        # 40 float4 members * 16 bytes = 640 bytes > 128
        src = """
struct PC {
    float4 data0; float4 data1; float4 data2; float4 data3;
    float4 data4; float4 data5; float4 data6; float4 data7;
    float4 data8; float4 data9; float4 data10; float4 data11;
    float4 data12; float4 data13; float4 data14; float4 data15;
    float4 data16; float4 data17; float4 data18; float4 data19;
    float4 data20; float4 data21; float4 data22; float4 data23;
    float4 data24; float4 data25; float4 data26; float4 data27;
    float4 data28; float4 data29; float4 data30; float4 data31;
    float4 data32; float4 data33; float4 data34; float4 data35;
    float4 data36; float4 data37; float4 data38; float4 data39;
};
[[vk::push_constant]] PC pc;
[numthreads(64, 1, 1)]
void main(uint3 gtid : SV_DispatchThreadID) { }
"""
        errors = validate_slang_source(src)
        assert len(errors) > 0, (
            f"push-constant exceeding 128B should be caught, got: {errors}"
        )


# ═══════════════════════════════════════════════════════════════════════
# M12 — Reduction backward regression tests
# ═══════════════════════════════════════════════════════════════════════


class TestM12ReductionBackward:
    """CG.M3 — Reduction backward via [Differentiable] scalar fold.

    Gradient parity with CPU is the exit criterion.
    """

    @pytest.fixture(autouse=True)
    def _require_slangc(self):
        if not os.environ.get("SLANGC"):
            pytest.skip("SLANGC env var not set")

    @pytest.mark.xfail(
        reason="Pre-existing: sum/mean backward expand path broken on Vulkan"
    )
    def test_m12_sum_backward_matches_cpu(self):
        """sum().backward() matches CPU gradient."""

        @torch.compile(backend="inductor")
        def fn(x):
            return x.sum()

        torch.manual_seed(42)
        x = torch.randn(8, 16, device="vulkan:0", requires_grad=True)
        x_cpu = x.detach().cpu().requires_grad_()

        out = fn(x)
        out.backward()
        x_cpu.sum().backward()

        assert x.grad is not None, "sum backward produced None gradient"
        torch.testing.assert_close(x.grad.cpu(), x_cpu.grad, rtol=1e-4, atol=1e-4)

    @pytest.mark.xfail(
        reason="Pre-existing: sum/mean backward expand path broken on Vulkan"
    )
    def test_m12_sum_dim_backward_matches_cpu(self):
        """sum(dim=0).backward() matches CPU gradient."""

        @torch.compile(backend="inductor")
        def fn(x):
            return x.sum(dim=0)

        torch.manual_seed(42)
        x = torch.randn(8, 64, device="vulkan:0", requires_grad=True)
        x_cpu = x.detach().cpu().requires_grad_()

        out = fn(x)
        out.sum().backward()
        x_cpu.sum(dim=0).sum().backward()

        assert x.grad is not None, "sum dim=0 backward produced None gradient"
        torch.testing.assert_close(x.grad.cpu(), x_cpu.grad, rtol=1e-4, atol=1e-4)

