class TestForeachCompiles:
    """Foreach ops (used heavily by optimizers) fuse into one combo kernel:
    N tensors merged into a single Slang shader with a gtid-based dispatch
    if-ladder. Combo kernel rewritten in P1.4 to globally rename subkernel
    buffers and locals — see `vulkan_combo_kernel.py`.
    """

    def test_foreach_mul_add_dispatch_count(self):
        import torch_vulkan

        ts = [torch.randn(64, 64, device="vulkan:0") for _ in range(4)]
        gs = [torch.randn(64, 64, device="vulkan:0") for _ in range(4)]

        @torch.compile(backend="inductor")
        def step(ts, gs):
            torch._foreach_mul_(ts, 0.9)
            torch._foreach_add_(ts, gs, alpha=0.1)
            return ts

        with torch.no_grad():
            step(list(ts), list(gs))
            torch_vulkan._c_ext._reset_perf_counters()
            step(list(ts), list(gs))
            d = torch_vulkan._c_ext._get_dispatch_count()
        assert d <= 30, (
            f"foreach mul+add combo: expected ≤30 dispatches, got {d}"
        )  # P1.6 baseline

    def test_foreach_mul_add_correctness(self):
        ts = [torch.randn(8, 16, device="vulkan:0") for _ in range(4)]
        gs = [torch.randn(8, 16, device="vulkan:0") for _ in range(4)]
        ts_cpu = [t.cpu().clone() for t in ts]
        gs_cpu = [g.cpu().clone() for g in gs]

        @torch.compile(backend="inductor")
        def step(ts, gs):
            torch._foreach_mul_(ts, 0.9)
            torch._foreach_add_(ts, gs, alpha=0.1)
            return ts

        with torch.no_grad():
            step(ts, gs)
            torch._foreach_mul_(ts_cpu, 0.9)
            torch._foreach_add_(ts_cpu, gs_cpu, alpha=0.1)

        for vk, cpu in zip(ts, ts_cpu):
            torch.testing.assert_close(vk.cpu(), cpu, rtol=1e-4, atol=1e-4)


class TestForeachOptimizerTemplate:
    """T4.8 — foreach optimizer template (re-enabled after M24 fix).

    The ``foreach_optimizer.py.jinja`` template collapses an N-parameter
    optimizer step into a single 2D dispatch (X = element index, Y =
    parameter index). For AdamW with 4 parameters, this drops the dispatch
    count from ~28 (7 ops × 4 params, the per-param-update flow) to ~1
    for the foreach call. With prewarm + buffer setup, total ≤ 10.

    M24 was unblocked by switching the custom_op schemas from
    ``float | list[float]`` (PEP 604 union, rejected by ``infer_schema``)
    to ``list[float]`` with length-1 broadcast normalization at the
    boundary.
    """

    def test_adamw_batched_compile(self):
        """One step of AdamW on 4 small parameters issues ≤10 dispatches
        total (1 for the foreach template + bookkeeping)."""
        import torch_vulkan

        N = 4
        torch.manual_seed(0)
        params = [torch.randn(8, 8, device="vulkan:0") for _ in range(N)]
        grads = [torch.randn(8, 8, device="vulkan:0") for _ in range(N)]
        m_bufs = [torch.zeros_like(p) for p in params]
        v_bufs = [torch.zeros_like(p) for p in params]

        # Warmup (template render + slangc compile happens here).
        torch.ops.torch_vulkan.foreach_adamw_step(
            params,
            grads,
            m_bufs,
            v_bufs,
            [0.001],
            [0.0],
            [0.9],
            [0.999],
            [1e-8],
        )

        # Steady-state dispatch count.
        torch_vulkan._c_ext._reset_perf_counters()
        torch.ops.torch_vulkan.foreach_adamw_step(
            params,
            grads,
            m_bufs,
            v_bufs,
            [0.001],
            [0.0],
            [0.9],
            [0.999],
            [1e-8],
        )
        d = torch_vulkan._c_ext._get_dispatch_count()
        # Pre-T4.8 baseline: ~7 dispatches per param × N = ~28. Target: 1.
        assert d <= 10, (
            f"T4.8: expected ≤10 Vulkan dispatches for AdamW step on "
            f"{N} params (target ~1 via foreach template), got {d}."
        )

    def test_adamw_correctness_vs_cpu(self):
        """Numerical: AdamW step on Vulkan matches the CPU reference
        (no bias correction; matches the template's single-step formula)."""
        N = 4
        torch.manual_seed(0)
        p_init = [torch.randn(8, 8) for _ in range(N)]
        g_init = [torch.randn(8, 8) for _ in range(N)]

        # Vulkan path.
        params_v = [p.clone().to("vulkan:0") for p in p_init]
        grads_v = [g.clone().to("vulkan:0") for g in g_init]
        m_v = [torch.zeros_like(p) for p in params_v]
        v_v = [torch.zeros_like(p) for p in params_v]
        torch.ops.torch_vulkan.foreach_adamw_step(
            params_v,
            grads_v,
            m_v,
            v_v,
            [0.001],
            [0.0],
            [0.9],
            [0.999],
            [1e-8],
        )

        # CPU reference (matches template formula exactly).
        params_c = [p.clone() for p in p_init]
        grads_c = [g.clone() for g in g_init]
        m_c = [torch.zeros_like(p) for p in params_c]
        v_c = [torch.zeros_like(p) for p in params_c]
        lr, wd, b1, b2, eps = 0.001, 0.0, 0.9, 0.999, 1e-8
        for p, g, m, v in zip(params_c, grads_c, m_c, v_c):
            m.mul_(b1).add_(g, alpha=1.0 - b1)
            v.mul_(b2).addcmul_(g, g, value=1.0 - b2)
            denom = v.sqrt().add(eps)
            update = m / denom
            if wd != 0.0:
                update = update.add(p, alpha=wd)
            p.add_(update, alpha=-lr)

        for vk, cpu in zip(params_v, params_c):
            torch.testing.assert_close(vk.cpu(), cpu, rtol=1e-5, atol=1e-5)

    def test_sgd_batched_one_dispatch(self):
        """Sanity check for the SGD variant — also 1 dispatch."""
        import torch_vulkan

        N = 4
        torch.manual_seed(1)
        params = [torch.randn(16, device="vulkan:0") for _ in range(N)]
        grads = [torch.randn(16, device="vulkan:0") for _ in range(N)]
        # Warmup.
        torch.ops.torch_vulkan.foreach_sgd_step(params, grads, [0.01], [0.0])
        torch_vulkan._c_ext._reset_perf_counters()
        torch.ops.torch_vulkan.foreach_sgd_step(params, grads, [0.01], [0.0])
        d = torch_vulkan._c_ext._get_dispatch_count()
        assert d <= 5, f"foreach SGD: expected ≤5 dispatches, got {d}"

    def test_custom_ops_registered(self):
        """All four T4.8 custom_ops register without infer_schema rejection."""
        for name in (
            "foreach_sgd_step",
            "foreach_sgd_momentum_step",
            "foreach_adamw_step",
            "foreach_lion_step",
        ):
            op = getattr(torch.ops.torch_vulkan, name, None)
            assert op is not None and hasattr(op, "default"), (
                f"torch_vulkan::{name} not registered (M24 schema fix lost?)"
            )


class TestTemplateParameterBlockInvariant:
    """N+1.10 — every Jinja/Slang template under
    ``inductor/templates/`` must wrap its buffer bindings in a single
    ``ParameterBlock<KernelArgs>`` and emit zero ``[[vk::binding(N)]]``
    literals.  Locks the migration so a future template author cannot
    silently regress P3.1 (the codegen quality target was 6/6 templates;
    flash_attention was the last outlier and migrated 2026-05-09).
    """

    def _strip_comments(self, src: str) -> str:
        # Remove ``// ...`` line comments and ``/* ... */`` block comments
        # so we count only emitted code.  The Jinja-rendered Slang source
        # we examine has only single-line comments, but be defensive.
        import re

        src = re.sub(r"/\*.*?\*/", "", src, flags=re.DOTALL)
        src = re.sub(r"//[^\n]*", "", src)
        return src

    def test_flash_attention_template_uses_parameter_block(self):
        """Flash attention shader: 0 binding literals + exactly 1
        ``ParameterBlock<KernelArgs>`` declaration in the rendered Slang
        source (across all variants we render).
        """
        from torch_vulkan.inductor.vulkan_template_caller import (
            _render_flash_attention,
        )

        for output_dtype in ("float", "half"):
            for is_causal in (False, True):
                src = _render_flash_attention(
                    head_dim=64,
                    head_layout="bhsd",
                    is_causal=is_causal,
                    num_stages=1,
                    output_dtype=output_dtype,
                    BK=64,
                    BQ=32,
                )
                code = self._strip_comments(src)
                # Zero literal bindings: the ParameterBlock auto-numbers
                # bindings 0..N-1 in struct-field order.
                assert "[[vk::binding" not in code, (
                    f"flash_attention.py.jinja regressed N+1.10 — emits "
                    f"`[[vk::binding(...)]]` literal in rendered code "
                    f"(output_dtype={output_dtype}, "
                    f"is_causal={is_causal})."
                )
                # Exactly one ParameterBlock — anchors the descriptor set
                # the runtime binds against.
                assert code.count("ParameterBlock<") == 1, (
                    f"flash_attention.py.jinja must declare exactly one "
                    f"ParameterBlock<KernelArgs>; got "
                    f"{code.count('ParameterBlock<')}."
                )

    def test_all_templates_zero_binding_literals(self):
        """No template under ``inductor/templates/`` may emit
        ``[[vk::binding(N)]]`` in its source — the canonical pattern is
        ``ParameterBlock<KernelArgs>`` with one struct field per
        descriptorTableSlot in caller-order.
        """
        from pathlib import Path

        templates_dir = (
            Path(__import__("torch_vulkan").__file__).parent / "inductor" / "templates"
        )
        violations: list[str] = []
        for path in sorted(templates_dir.iterdir()):
            if path.suffix not in (".jinja", ".slang"):
                continue
            text = self._strip_comments(path.read_text())
            if "[[vk::binding" in text:
                violations.append(path.name)
        assert not violations, (
            f"Templates emit `[[vk::binding(N)]]` literals (must use "
            f"ParameterBlock<KernelArgs> instead): {violations}"
        )

    def test_dynamic_pointwise_n_pc_arg_slice_d_2_b(self):
        """D.2.b — `make_vulkan_kernel`'s n_pc>0 dispatch closure must
        derive `wg_x/y/z` from the *last 3* args, NOT from positions
        `args[-(3+n_pc)..]`.  The wrapper emits `[bufs..., sizevars...,
        dyn_numels..., wg_x, wg_y, wg_z]` (sizevars + dyn_numels come
        BEFORE wg dims).  Prior to the fix, the closure tried to read
        wg dims from PC positions and the PC-bytes slice
        `args[-n_pc:-3]` evaluated to empty for n_pc≤3, so every dynamic
        pointwise kernel crashed at dispatch with
        ``struct.error: pack expected N items for packing (got 0)``.

        Probe the closure surface directly with a synthetic kernel and
        a stub dispatch_fn — sidesteps test-isolation issues with the
        full torch.compile path while still locking the slice math.
        """
        from unittest.mock import patch

        from torch_vulkan.inductor.runtime import make_vulkan_kernel

        # A trivial Slang shader with a 3-uint PC — n_pc=3 reproduces
        # the original bug scenario (slice `args[-3:-3]` was empty).
        src = """\
struct PC { uint a; uint b; uint c; };
[[vk::push_constant]] PC pc;
[[vk::binding(0)]] StructuredBuffer<float> in_ptr0;
[[vk::binding(1)]] RWStructuredBuffer<float> out_ptr0;
[shader("compute")]
[numthreads(64, 1, 1)]
void computeMain(uint3 gtid : SV_DispatchThreadID) {
    if (gtid.x >= pc.a) return;
    out_ptr0[gtid.x] = in_ptr0[gtid.x] * float(pc.b) + float(pc.c);
}
"""
        captured: dict = {}

        def stub_dispatch(key, spv, tensors, wg_x, wg_y, wg_z, pc_bytes, n_outputs):
            captured["wg_x"] = wg_x
            captured["wg_y"] = wg_y
            captured["wg_z"] = wg_z
            captured["pc_bytes"] = pc_bytes
            captured["n_buffers"] = len(tensors)

        # Patch `_get_jit_dispatch` to return our stub so we can inspect
        # what the closure passes through without actually launching a
        # GPU kernel.  This isolates the slice-math contract.
        with patch(
            "torch_vulkan.inductor.runtime._get_jit_dispatch",
            return_value=stub_dispatch,
        ):
            kernel = make_vulkan_kernel(
                src,
                "test_d_2_b_pc_slice",
                n_buffers=2,
                pc_size_bytes=12,
                n_pc=3,
                n_outputs=1,
            )
            # ordered_args layout matches the wrapper's emission:
            # [in_buf, out_buf, pc_a, pc_b, pc_c, wg_x, wg_y, wg_z].
            in_buf = torch.zeros(64, device="vulkan:0")
            out_buf = torch.zeros(64, device="vulkan:0")
            kernel(in_buf, out_buf, 64, 7, 11, 1, 1, 1)

        # The closure must have unpacked wg dims from the LAST three slots
        # and the PC bytes from the n_pc slots immediately before.
        assert captured["wg_x"] == 1, captured
        assert captured["wg_y"] == 1, captured
        assert captured["wg_z"] == 1, captured
        # PC bytes: pack(64, 7, 11) into 3 little-endian uint32 = 12 bytes.
        import struct

        expected_pc = struct.pack("3I", 64, 7, 11)
        assert captured["pc_bytes"] == expected_pc, (
            f"PC slice math regressed — expected {expected_pc.hex()!r}, "
            f"got {captured['pc_bytes'].hex()!r}"
        )
        assert captured["n_buffers"] == 2, captured

    def test_mm_template_uses_slang_generic_for_epilogue_cg_1(self):
        """CG.1 (anti-goal #6) — mm template must use Slang generic
        polymorphism for the epilogue, NOT Jinja string substitution.

        Concretely, the rendered Slang source for an addmm+gelu fused
        kernel must contain:
          - `computeMain<Epilogue : IPointwise>` (Slang generic constraint)
          - `Epilogue::apply(` (generic-typed dispatch, NOT a substituted
            concrete struct name like `OpGELU::apply(`)

        And it must NOT contain the literal Jinja substitution
        `{{ epilogue }}::apply` (which would be a pre-resolution artifact
        if the template was ever broken to do string-based dispatch).

        The concrete struct (e.g. `OpGELU`) is supplied as the Slang
        generic type argument via the ``entry`` parameter of
        ``compile_and_dispatch`` (`computeMain<OpGELU>`), resolved at
        SPIR-V compile time. Anti-goal #6: no string-based template
        params; the audit's earlier CG.1 claim was based on a stale read
        of the template — this test locks the actual contract.
        """
        from torch_vulkan.inductor.vulkan_template_caller import _render_mm_slang

        src = _render_mm_slang(
            tile_m=64,
            tile_n=64,
            tile_k=16,
            num_stages=1,
            has_bias=True,
            epilogue_struct="OpGELU",
            m_per_thread=4,
            n_per_thread=4,
        )
        # Slang generic constraint at entry point
        assert "computeMain<Epilogue : IPointwise>" in src, (
            "mm template must declare `computeMain<Epilogue : IPointwise>` — "
            "Slang generic with IPointwise constraint."
        )
        # Generic dispatch in the body — using the type parameter, not a
        # substituted concrete struct name.
        assert "Epilogue::apply(" in src, (
            "mm template body must dispatch via `Epilogue::apply(...)` "
            "(Slang generic type parameter), not via a substituted "
            "concrete struct name."
        )
        # No Jinja substitution leaked through (pre-rendering artifact).
        assert "{{ epilogue }}" not in src, (
            "Rendered shader must not contain Jinja `{{ epilogue }}` — "
            "epilogue is a Slang generic, not a Jinja string."
        )
        # Concrete struct name MUST NOT appear at the call site (only as a
        # documentation comment elsewhere).  The validated concrete name
        # is supplied separately to slangc as the entry-point generic
        # argument (`entry="computeMain<OpGELU>"`).
        assert "OpGELU::apply(" not in src, (
            "Rendered shader must not bake the concrete `OpGELU::apply(...)` "
            "into the body — anti-goal #6 forbids string-substituted "
            "epilogue names; use the Slang generic type parameter."
        )


class TestCG12PointwiseGenericDispatch:
    """CG.M12 (anti-goal #6) — pointwise dispatch must use Slang generics.

    The generic pointwise dispatch module must NOT use Jinja2 string
    substitution for op selection. Instead it must use Slang generic
    entry points (``computeMain<Op : IPointwise>``) where the concrete
    op struct is resolved at SPIR-V compile time via the ``entry``
    parameter.
    """

    def test_unary_src_uses_slang_generic_not_jinja(self):
        """Unary generic source must declare a Slang generic, not a Jinja var."""
        from torch_vulkan.inductor.generic_dispatch_table import PointwiseEntry
        from torch_vulkan.inductor.generic_pointwise_dispatch import (
            _UNARY_GENERIC_SRC,
            _entry_name,
            _generic_src,
        )

        # The source must declare a Slang generic entry point.
        assert "computeMain<Op : IPointwise>" in _UNARY_GENERIC_SRC, (
            "Unary generic source must declare `computeMain<Op : IPointwise>` — "
            "Slang generic with IPointwise constraint. Anti-goal #6 violation."
        )
        # Must use the proper Slang generic helper (pointwise_unary_apply<Op>).
        assert "pointwise_unary_apply<Op>" in _UNARY_GENERIC_SRC, (
            "Unary source must dispatch via `pointwise_unary_apply<Op>(...)` "
            "(Slang generic), not via a substituted concrete struct name."
        )
        # Must NOT contain any Jinja2 markers.
        assert "{{" not in _UNARY_GENERIC_SRC, (
            "Unary generic source must not contain Jinja2 `{{` markers — "
            "op selection is via Slang generics, not string substitution."
        )
        assert "{%" not in _UNARY_GENERIC_SRC, (
            "Unary generic source must not contain Jinja2 `{%` markers."
        )
        # Must NOT contain a concrete op struct at the call site.
        assert "OpAbs::apply" not in _UNARY_GENERIC_SRC, (
            "Unary generic source must not bake a concrete `OpAbs::apply(...)` "
            "into the body — anti-goal #6 forbids string-substituted op names."
        )

        # Verify _entry_name produces the correct slangc entry-point name.
        entry = PointwiseEntry("OpAbs", 1)
        assert _entry_name(entry) == "computeMain<OpAbs>", (
            "_entry_name must produce `computeMain<OpAbs>` for slangc generic "
            "specialization."
        )

        # Verify _generic_src returns the same source for different ops.
        src_abs = _generic_src(PointwiseEntry("OpAbs", 1))
        src_relu = _generic_src(PointwiseEntry("OpReLU", 1))
        assert src_abs == src_relu, (
            "CG.M12: _generic_src must return the SAME source for all unary ops. "
            "The op struct is resolved at SPIR-V compile time via the entry "
            "parameter, NOT embedded in the source."
        )
        assert "OpAbs" not in src_abs, (
            "Generic source must not contain any concrete op struct name."
        )

    def test_binary_src_uses_slang_generic_not_jinja(self):
        """Binary generic source must declare a Slang generic, not a Jinja var."""
        from torch_vulkan.inductor.generic_dispatch_table import PointwiseEntry
        from torch_vulkan.inductor.generic_pointwise_dispatch import (
            _BINARY_GENERIC_SRC,
            _generic_src,
        )

        assert "computeMain<Op : IPointwiseBinary>" in _BINARY_GENERIC_SRC, (
            "Binary generic source must declare `computeMain<Op : IPointwiseBinary>`."
        )
        assert "pointwise_binary_apply<Op>" in _BINARY_GENERIC_SRC, (
            "Binary source must dispatch via `pointwise_binary_apply<Op>(...)`."
        )
        assert "{{" not in _BINARY_GENERIC_SRC
        assert "{%" not in _BINARY_GENERIC_SRC
        assert "OpAdd::apply" not in _BINARY_GENERIC_SRC

        # Binary sources for different ops must be identical.
        src_add = _generic_src(PointwiseEntry("OpAdd", 2))
        src_mul = _generic_src(PointwiseEntry("OpMul", 2))
        assert src_add == src_mul, (
            "CG.M12: _generic_src must return the SAME source for all binary ops."
        )

    def test_complex_src_uses_slang_generic_not_jinja(self):
        """Complex generic sources must use Slang generics."""
        from torch_vulkan.inductor.generic_dispatch_table import PointwiseEntry
        from torch_vulkan.inductor.generic_pointwise_dispatch import (
            _COMPLEX_BINARY_GENERIC_SRC,
            _COMPLEX_UNARY_GENERIC_SRC,
            _generic_src,
        )

        assert "computeMain<Op : IComplexPointwise>" in _COMPLEX_UNARY_GENERIC_SRC
        assert "pointwise_complex_unary_apply<Op>" in _COMPLEX_UNARY_GENERIC_SRC
        assert "{{" not in _COMPLEX_UNARY_GENERIC_SRC

        assert (
            "computeMain<Op : IComplexPointwiseBinary>" in _COMPLEX_BINARY_GENERIC_SRC
        )
        assert "pointwise_complex_binary_apply<Op>" in _COMPLEX_BINARY_GENERIC_SRC
        assert "{{" not in _COMPLEX_BINARY_GENERIC_SRC

        # Complex sources for different ops must be identical.
        cplx_unary_a = _generic_src(
            PointwiseEntry("OpComplexConj", 1), complex_valued=True
        )
        cplx_unary_b = _generic_src(
            PointwiseEntry("OpComplexAbs", 1), complex_valued=True
        )
        assert cplx_unary_a == cplx_unary_b, (
            "CG.M12: complex generic source must be identical across ops."
        )

        cplx_bin_a = _generic_src(
            PointwiseEntry("OpComplexAdd", 2), complex_valued=True
        )
        cplx_bin_b = _generic_src(
            PointwiseEntry("OpComplexMul", 2), complex_valued=True
        )
        assert cplx_bin_a == cplx_bin_b

    def test_no_jinja_import_in_dispatch_module(self):
        """CG.M12: generic_pointwise_dispatch.py must NOT import jinja2."""
        import ast
        import os

        path = os.path.join(
            os.path.dirname(__file__),
            "..",
            "python",
            "torch_vulkan",
            "inductor",
            "generic_pointwise_dispatch.py",
        )
        with open(path) as f:
            tree = ast.parse(f.read())
        for node in ast.walk(tree):
            if isinstance(node, ast.Import):
                for alias in node.names:
                    assert "jinja" not in alias.name.lower(), (
                        "CG.M12: generic_pointwise_dispatch.py must not import jinja2. "
                        "Op selection is via Slang generics, not Jinja2 templating."
                    )
            elif isinstance(node, ast.ImportFrom):
                if node.module:
                    assert "jinja" not in node.module.lower(), (
                        "CG.M12: generic_pointwise_dispatch.py must not import jinja2."
                    )


class TestSlangcPrewarm:
    """`register()` schedules the standard mm/addmm/bmm tile configs through
    the slangc thread pool so the first user dispatch never blocks on a cold
    compile. P1.4 follow-up: validates the prewarm spec collector renders
    cache keys that match the runtime callers and that submitting them
    populates the SPIR-V cache.
    """

    def test_prewarm_specs_match_runtime_keys(self):
        from torch_vulkan.inductor.vulkan_template import _MM_TILE_CONFIGS
        from torch_vulkan.inductor.vulkan_template_caller import (
            _collect_matmul_prewarm_specs,
        )

        specs = _collect_matmul_prewarm_specs()
        keys = {k for k, _ in specs}

        # Every runtime cache_key shape (mm + addmm + bmm × {f32, f16} ×
        # {1, 2 stages where applicable}) must appear in the prewarm set.
        # `r1x1` is the legacy 1-output-per-thread suffix; register-tile
        # variants use rMxN where M*N > 1.
        for tm, tn, tk in _MM_TILE_CONFIGS:
            for dt in ("float", "half"):
                for ns in (1, 2):
                    assert f"slang_mm_{tm}_{tn}_{tk}_s{ns}_r1x1_{dt}" in keys
                    assert f"slang_addmm_{tm}_{tn}_{tk}_s{ns}_r1x1_{dt}" in keys
                assert f"slang_bmm_{tm}_{tn}_{tk}_r1x1_{dt}" in keys

        # Every spec must render to a non-empty Slang shader.
        for k, src in specs:
            assert src and '[shader("compute")]' in src, (
                f"prewarm spec {k} did not render a compute shader"
            )

    def test_prewarm_populates_cache_sync(self):
        from torch_vulkan.inductor import runtime as _rt
        from torch_vulkan.inductor.vulkan_template_caller import (
            prewarm_matmul_templates,
        )

        # Pick a key that's unlikely to be in the cache after a normal
        # register() call — but if it is we still want to verify the
        # function returns 0 (already-cached short-circuit).
        before = len(_rt._cache_by_key)
        n = prewarm_matmul_templates(sync=True)
        after = len(_rt._cache_by_key)
        # Either we scheduled new work or every key was already cached.
        assert n >= 0
        assert after >= before


class TestSummaryAPI:
    """`inductor_stats.summary()` aggregates per-kernel stats into a single
    dict suitable for use as a Jupyter cell return value.
    """

    def test_summary_empty_when_disabled(self):
        os.environ.pop("TORCH_VULKAN_INDUCTOR_STATS", None)
        from torch_vulkan.inductor.inductor_stats import summary

        s = summary()
        assert s["n_kernels"] == 0
        assert s["total_calls"] == 0
        assert s["top"] == []

    def test_summary_aggregates_compiled_kernels(self):
        # Set env var BEFORE first compile so the kernel wrapper is created
        # with stats enabled (the check is module-load-time in make_vulkan_kernel).
        os.environ["TORCH_VULKAN_INDUCTOR_STATS"] = "1"
        try:
            from torch_vulkan.inductor.inductor_stats import (
                reset_stats,
                summary,
            )

            # Use a body unique to this test so we never collide with a kernel
            # cached by a prior test that ran without stats enabled.
            @torch.compile(backend="inductor")
            def _summary_test_fn(x):
                return torch.tanh(x * 0.317) + 0.42

            x = torch.randn(48, 96, device="vulkan:0")
            _summary_test_fn(x)
            reset_stats()
            _summary_test_fn(x)
            _summary_test_fn(x)

            s = summary(top_n=5)
            assert s["n_kernels"] >= 1, f"summary saw no kernels: {s}"
            assert s["total_calls"] >= 1, f"summary saw no calls: {s}"
            assert s["total_us"] >= 0.0
            # `top` is sorted by total_us descending.
            tops = [t[1] for t in s["top"]]
            assert tops == sorted(tops, reverse=True)
            # P11.11 — Each top row carries the kernel's SPIR-V hash prefix
            # (12 hex chars) so cache-miss debugging can correlate timings
            # back to specific compiled binaries.
            for row in s["top"]:
                spv_hash = row[4]
                assert len(spv_hash) == 12, (
                    f"expected 12-char SPIR-V hash prefix, got {spv_hash!r}"
                )
                int(spv_hash, 16)  # must be valid hex
        finally:
            os.environ.pop("TORCH_VULKAN_INDUCTOR_STATS", None)


class TestWaterfallDump:
    """`inductor_stats.dump_waterfall(path)` writes a sorted per-kernel JSON
    blob with dispatches/total_us/avg_us/percent_total — the "what is the
    bottleneck at a glance" dump for production debugging.
    """

    def test_dump_waterfall_writes_sorted_json(self, tmp_path):
        os.environ["TORCH_VULKAN_INDUCTOR_STATS"] = "1"
        try:
            from torch_vulkan.inductor.inductor_stats import (
                dump_waterfall,
                reset_stats,
            )

            @torch.compile(backend="inductor")
            def _waterfall_test_fn(x):
                return torch.relu(x * 0.31) + 0.42

            x = torch.randn(32, 64, device="vulkan:0")
            _waterfall_test_fn(x)
            reset_stats()
            _waterfall_test_fn(x)
            _waterfall_test_fn(x)

            out = tmp_path / "waterfall.json"
            payload = dump_waterfall(str(out))
            assert out.exists()
            data = json.loads(out.read_text())
            assert data == payload
            assert data["n_kernels"] >= 1
            assert data["total_calls"] >= 1
            us = [k["total_us"] for k in data["kernels"]]
            assert us == sorted(us, reverse=True)
            pct = sum(k["percent_total"] for k in data["kernels"])
            assert 99.0 <= pct <= 101.0  # rounding slack
        finally:
            os.environ.pop("TORCH_VULKAN_INDUCTOR_STATS", None)

    def test_print_full_report_runs(self, capsys):
        os.environ["TORCH_VULKAN_INDUCTOR_STATS"] = "1"
        try:
            from torch_vulkan.inductor.inductor_stats import (
                print_full_report,
                reset_compile_stats,
                reset_stats,
            )

            @torch.compile(backend="inductor")
            def _full_report_test(x):
                return torch.tanh(x * 0.5) + 0.1

            x = torch.randn(16, 32, device="vulkan:0")
            _full_report_test(x)
            reset_stats()
            reset_compile_stats()
            _full_report_test(x)
            _full_report_test(x)

            print_full_report(top_n=3)
            out = capsys.readouterr().out
            # Should print both sections.
            assert "inductor_stats" in out
            assert "compile_stats" in out
        finally:
            os.environ.pop("TORCH_VULKAN_INDUCTOR_STATS", None)

    def test_dump_waterfall_disabled_writes_empty(self, tmp_path):
        os.environ.pop("TORCH_VULKAN_INDUCTOR_STATS", None)
        from torch_vulkan.inductor.inductor_stats import dump_waterfall, reset_stats

        reset_stats()
        out = tmp_path / "empty.json"
        payload = dump_waterfall(str(out))
        assert payload["n_kernels"] == 0
        assert payload["kernels"] == []
        assert out.exists()


class TestCompileStats:
    """`inductor_stats.compile_stats()` exposes always-on slangc / cache
    counters so production debugging can answer "where did the cold compile
    time go?" without a re-run with extra env vars. P4.1.
    """

    def test_compile_stats_counts_cold_compile(self):
        from torch_vulkan.inductor.inductor_stats import (
            compile_stats,
            reset_compile_stats,
        )
        from torch_vulkan.inductor.runtime import compile_slang_to_spirv

        reset_compile_stats()
        # Unique source so we force a cold compile (cache miss).
        pid = os.getpid()
        src = (
            "[[vk::binding(0)]] StructuredBuffer<float> in_ptr0;\n"
            "[[vk::binding(1)]] RWStructuredBuffer<float> out_ptr0;\n"
            '[shader("compute")] [numthreads(64,1,1)]\n'
            "void computeMain(uint3 gtid : SV_DispatchThreadID) {\n"
            f"  out_ptr0[gtid.x] = in_ptr0[gtid.x] + {pid}.0;\n"
            "}\n"
        )
        compile_slang_to_spirv(
            src, "computeMain", cache_key=f"_test_compile_stats_{pid}"
        )
        s = compile_stats()
        assert s["cold_compiles"] >= 1
        assert s["cold_compile_us"] > 0.0
        # Second compile of the same key hits the in-memory cache.
        compile_slang_to_spirv(
            src, "computeMain", cache_key=f"_test_compile_stats_{pid}"
        )
        s2 = compile_stats()
        assert s2["in_memory_hits"] >= 1
        assert s2["cache_hit_rate"] > 0.0


class TestExprPrinterSimplify:
    """`VulkanExprPrinter` filters trivial 0*x / 1*x / 0+x patterns so the
    emitted Slang does not ship dead-code arithmetic the driver would
    otherwise have to fold.
    """

    def test_mul_with_zero_collapses(self):
        import sympy
        from torch_vulkan.inductor.expr_printer import VulkanExprPrinter

        x = sympy.Symbol("x")
        expr = sympy.Mul(sympy.S.Zero, x, evaluate=False)
        assert VulkanExprPrinter().doprint(expr) == "0"

    def test_mul_with_one_drops_unit(self):
        import sympy
        from torch_vulkan.inductor.expr_printer import VulkanExprPrinter

        x = sympy.Symbol("x")
        expr = sympy.Mul(sympy.S.One, x, evaluate=False)
        assert VulkanExprPrinter().doprint(expr) == "x"

    def test_add_with_zero_drops_unit(self):
        import sympy
        from torch_vulkan.inductor.expr_printer import VulkanExprPrinter

        x = sympy.Symbol("x")
        expr = sympy.Add(sympy.S.Zero, x, evaluate=False)
        assert VulkanExprPrinter().doprint(expr) == "x"

    def test_floordiv_by_one_drops_to_x(self):
        """P11.5 / P6.6: `FloorDiv(x, 1)` is the identity; emitting it as
        a branchless conditional is dead arithmetic. `keepdim=True`
        reductions can construct `FloorDiv(_, 1)` with evaluate=False."""
        import sympy
        from torch._inductor.utils import sympy_subs
        from torch._inductor.virtualized import V
        from torch_vulkan.inductor.expr_printer import VulkanExprPrinter

        x = sympy.Symbol("x")
        FloorDiv = sympy.Function("FloorDiv")
        # Hand-build via the Inductor sympy class to match printer dispatch.
        from torch.utils._sympy.functions import FloorDiv as InductorFloorDiv

        expr = InductorFloorDiv(x, sympy.S.One)
        out = VulkanExprPrinter().doprint(expr)
        assert out == "x", f"expected 'x', got {out!r}"

    def test_modular_indexing_mod_one_is_zero(self):
        """P11.5: `x % 1 = 0` for any x. ModularIndexing(_, _, 1) is dead."""
        import sympy
        from torch._inductor.virtualized import V
        from torch.utils._sympy.functions import ModularIndexing
        from torch_vulkan.inductor.expr_printer import VulkanExprPrinter

        x = sympy.Symbol("x")
        expr = ModularIndexing(x, sympy.S.One, sympy.S.One)
        out = VulkanExprPrinter().doprint(expr)
        assert out == "0", f"expected '0', got {out!r}"


class TestMatmulTemplateCompiles:
    """The Slang matmul Jinja template must produce slangc-compilable SPIR-V
    for every (num_stages, has_bias) combination the runtime ships. Regression
    for L0 — a pre-existing bug where helpers referenced `lid` outside the
    entry point and double-buffered tiles were declared as 2-D arrays but
    indexed flatly. Both were silent for months because the loader filename
    mismatch (P1.4) made the entire template path unreachable.
    """

    def _try_render_and_compile(
        self,
        *,
        num_stages: int,
        has_bias: bool,
        m_per_thread: int = 4,
        n_per_thread: int = 4,
    ) -> int:
        import subprocess
        import tempfile

        from torch_vulkan.inductor.runtime import _SHADERS_LIB_DIR
        from torch_vulkan.inductor.vulkan_template_caller import _render_mm_slang

        slangc = os.environ.get("SLANGC")
        if not slangc:
            pytest.skip("SLANGC env var not set")

        # 64x64 tile_m*tile_n=4096 outputs/group must register-tile (M_PER=4
        # N_PER=4 → workgroup=256 ≤ 1024) to fit Vulkan's max workgroup limit.
        src = _render_mm_slang(
            64,
            64,
            16,
            num_stages=num_stages,
            has_bias=has_bias,
            m_per_thread=m_per_thread,
            n_per_thread=n_per_thread,
        )
        with tempfile.TemporaryDirectory() as td:
            slang = os.path.join(td, "k.slang")
            spv = os.path.join(td, "k.spv")
            with open(slang, "w") as f:
                f.write(src)
            r = subprocess.run(
                [
                    slangc,
                    slang,
                    "-target",
                    "spirv",
                    "-entry",
                    "computeMain<OpIdentity>",
                    "-o",
                    spv,
                    "-matrix-layout-row-major",
                    "-I",
                    _SHADERS_LIB_DIR,
                ],
                capture_output=True,
                text=True,
            )
            assert r.returncode == 0, (
                f"slangc failed for num_stages={num_stages} has_bias={has_bias}: "
                f"{r.stderr}"
            )
            return os.path.getsize(spv)

    def test_template_compiles_ns1_no_bias(self):
        assert self._try_render_and_compile(num_stages=1, has_bias=False) > 0

    def test_template_compiles_ns1_with_bias(self):
        assert self._try_render_and_compile(num_stages=1, has_bias=True) > 0

    def test_template_compiles_ns2_no_bias(self):
        assert self._try_render_and_compile(num_stages=2, has_bias=False) > 0

    def test_template_compiles_ns2_with_bias(self):
        assert self._try_render_and_compile(num_stages=2, has_bias=True) > 0


class TestMatmulTileConfigsFitWorkgroupLimit:
    """All shipped (TILE_M, TILE_N, TILE_K) and (TILE_M, TILE_N, TILE_K,
    M_PER_THREAD, N_PER_THREAD) configs must produce a workgroup size ≤ the
    Vulkan max_workgroup_invocations limit on RDNA1 (1024). Tiles that
    over-shoot this would fail at vkCreateComputePipeline (silently dropped
    by the autotune, falling back to aten_mm). This regression locks the
    upfront filter so a future config bump can't silently disable the
    template path."""

    def test_legacy_configs_fit_1024(self):
        from torch_vulkan.inductor.vulkan_template import _MM_TILE_CONFIGS

        for tm, tn, tk in _MM_TILE_CONFIGS:
            assert tm * tn <= 1024, (
                f"legacy config ({tm},{tn},{tk}) wg={tm * tn} exceeds 1024"
            )

    def test_register_tile_configs_fit_1024(self):
        from torch_vulkan.inductor.vulkan_template import _MM_REGISTER_TILE_CONFIGS

        for tm, tn, tk, mpt, npt in _MM_REGISTER_TILE_CONFIGS:
            wg = (tm // mpt) * (tn // npt)
            assert tm % mpt == 0 and tn % npt == 0, (
                f"reg config ({tm},{tn},{tk},{mpt},{npt}) tile not divisible by per-thread"
            )
            assert wg <= 1024, (
                f"reg config ({tm},{tn},{tk},{mpt},{npt}) wg={wg} exceeds 1024"
            )


class TestRegisterTileMatmul:
    """The register-tiled Slang matmul path: each thread accumulates an
    (M_PER_THREAD x N_PER_THREAD) sub-tile in registers. Required to use
    tile_m * tile_n > 1024 within Vulkan's max_workgroup_invocations limit
    AND amortize K-loop loads across many outputs (the standard hardware-
    friendly mm pattern)."""

    def _ref(self, M, K, N, mpt, npt, num_stages):
        from torch_vulkan.inductor.vulkan_template_caller import _SlangTileMM

        torch.manual_seed(0)
        a = torch.randn(M, K, device="vulkan:0")
        b = torch.randn(K, N, device="vulkan:0")
        ref = a.cpu() @ b.cpu()
        # Pick tile_m, tile_n so wg ≤ 1024
        tile_m, tile_n, tile_k = 64, 64, 16
        mm = _SlangTileMM(
            tile_m,
            tile_n,
            tile_k,
            num_stages=num_stages,
            m_per_thread=mpt,
            n_per_thread=npt,
        )
        out = mm(a, b)
        return out.cpu(), ref

    def test_correctness_64x64x16_r4x4(self):
        out, ref = self._ref(M=64, K=96, N=96, mpt=4, npt=4, num_stages=1)
        torch.testing.assert_close(out, ref, rtol=1e-3, atol=1e-4)

    def test_correctness_with_stages_2(self):
        out, ref = self._ref(M=64, K=96, N=96, mpt=4, npt=4, num_stages=2)
        torch.testing.assert_close(out, ref, rtol=1e-3, atol=1e-4)

    def test_correctness_unaligned_shape(self):
        """Non-multiples of tile_m/tile_n must still produce correct results
        via the per-output bounds check inside the epilogue store loop."""
        out, ref = self._ref(M=127, K=200, N=130, mpt=4, npt=4, num_stages=1)
        torch.testing.assert_close(out, ref, rtol=1e-3, atol=1e-3)

    def test_correctness_addmm_register_tile(self):
        from torch_vulkan.inductor.vulkan_template_caller import _SlangTileAddMM

        torch.manual_seed(0)
        a = torch.randn(64, 96, device="vulkan:0")
        b = torch.randn(96, 96, device="vulkan:0")
        bias = torch.randn(96, device="vulkan:0")
        ref = a.cpu() @ b.cpu() + bias.cpu()
        addmm = _SlangTileAddMM(
            64, 64, 16, num_stages=1, m_per_thread=4, n_per_thread=4
        )
        out = addmm(bias, a, b).cpu()
        torch.testing.assert_close(out, ref, rtol=1e-3, atol=1e-4)

    def test_arange_linspace_fuse_to_one_dispatch(self):
        """P10 — `aten.arange.*` and `aten.linspace` factory ops chained with
        a pointwise op compile to a single dispatch via stock Inductor codegen.
        (`aten.eye` is *not* covered — see the multi-axis-iota gap entry.)
        """
        import torch_vulkan

        @torch.compile(backend="inductor", dynamic=False)
        def fn_arange():
            return torch.arange(64, device="vulkan:0", dtype=torch.float32) * 2.0

        @torch.compile(backend="inductor", dynamic=False)
        def fn_linspace():
            return torch.linspace(0.0, 1.0, 64, device="vulkan:0") * 2.0

        fn_arange()
        torch_vulkan._c_ext._reset_perf_counters()
        out = fn_arange()
        d = torch_vulkan._c_ext._get_dispatch_count()
        assert d <= 1, f"arange*2: expected ≤1 dispatch, got {d}"
        torch.testing.assert_close(
            out.cpu(),
            torch.arange(64, dtype=torch.float32) * 2.0,
            rtol=1e-5,
            atol=1e-5,
        )

        fn_linspace()
        torch_vulkan._c_ext._reset_perf_counters()
        out2 = fn_linspace()
        d2 = torch_vulkan._c_ext._get_dispatch_count()
        assert d2 <= 1, f"linspace*2: expected ≤1 dispatch, got {d2}"
        torch.testing.assert_close(
            out2.cpu(),
            torch.linspace(0.0, 1.0, 64) * 2.0,
            rtol=1e-5,
            atol=1e-5,
        )

    def test_lerp_fuses_to_one_dispatch(self):
        """P10 — `torch.lerp(a, b, t)` should compile to a single dispatch
        through Inductor's stock decomposition + Vulkan pointwise fusion.
        """
        import torch_vulkan

        a = torch.randn(64, 64, device="vulkan:0")
        b = torch.randn(64, 64, device="vulkan:0")

        @torch.compile(backend="inductor", dynamic=False)
        def fn_scalar(a, b):
            return torch.lerp(a, b, 0.3)

        fn_scalar(a, b)
        torch_vulkan._c_ext._reset_perf_counters()
        fn_scalar(a, b)
        d_scalar = torch_vulkan._c_ext._get_dispatch_count()
        assert d_scalar <= 1, f"lerp.Scalar: expected ≤1 dispatch, got {d_scalar}"

        @torch.compile(backend="inductor", dynamic=False)
        def fn_tensor(a, b, w):
            return torch.lerp(a, b, w)

        w = torch.randn(64, 64, device="vulkan:0")
        fn_tensor(a, b, w)
        torch_vulkan._c_ext._reset_perf_counters()
        fn_tensor(a, b, w)
        d_tensor = torch_vulkan._c_ext._get_dispatch_count()
        assert d_tensor <= 1, f"lerp.Tensor: expected ≤1 dispatch, got {d_tensor}"

        # Correctness vs CPU eager.
        ref = torch.lerp(a.cpu(), b.cpu(), 0.3)
        torch.testing.assert_close(fn_scalar(a, b).cpu(), ref, rtol=1e-3, atol=1e-4)
        ref_t = torch.lerp(a.cpu(), b.cpu(), w.cpu())
        torch.testing.assert_close(
            fn_tensor(a, b, w).cpu(), ref_t, rtol=1e-3, atol=1e-4
        )

    def test_unroll_capped_at_16_for_large_tile_k(self):
        """P11.10 — Inner-product loop in `mma_tile` is `[unroll(N)]` with
        `N = min(tile_k, 16)`. Full unroll on tile_k > 16 with a 4×4 register
        tile blows VGPR budget on RDNA1; the cap keeps occupancy stable.
        """
        from torch_vulkan.inductor.vulkan_template_caller import _render_mm_slang

        # tile_k=8 → expect `[unroll(8)]`
        src_small = _render_mm_slang(
            tile_m=64,
            tile_n=64,
            tile_k=8,
            dtype_a="float",
            dtype_b="float",
            dtype_c="float",
            dtype_acc="float",
            num_stages=1,
            m_per_thread=4,
            n_per_thread=4,
        )
        assert "[unroll(8)]" in src_small, (
            f"expected [unroll(8)] for tile_k=8 in mma_tile; got:\n{src_small[:500]}"
        )
        # tile_k=32 → expect `[unroll(16)]`, never `[unroll(32)]`
        src_large = _render_mm_slang(
            tile_m=64,
            tile_n=64,
            tile_k=32,
            dtype_a="float",
            dtype_b="float",
            dtype_c="float",
            dtype_acc="float",
            num_stages=1,
            m_per_thread=4,
            n_per_thread=4,
        )
        assert "[unroll(16)]" in src_large, (
            "expected [unroll(16)] cap for tile_k=32 in mma_tile"
        )
        assert "[unroll(32)]" not in src_large, (
            "tile_k=32 should not produce a full [unroll(32)] — cap is 16"
        )


