class TestTemplateCallerTrustInductor:
    """P6.2: under `TORCH_VULKAN_TRUST_INDUCTOR=1`, the matmul template
    callers skip per-dispatch `is_contiguous()` checks. Inductor's wrapper
    pre-arranges contiguous tensors before reaching the extern; the checks
    are pure overhead in trust mode."""

    def test_trust_flag_captured_at_module_load(self, monkeypatch):
        from torch_vulkan.inductor import vulkan_template_caller as vtc

        monkeypatch.setenv("TORCH_VULKAN_TRUST_INDUCTOR", "1")
        vtc._reset_trust_inductor_cache()
        assert vtc._TRUST_INDUCTOR is True
        monkeypatch.delenv("TORCH_VULKAN_TRUST_INDUCTOR", raising=False)
        vtc._reset_trust_inductor_cache()
        assert vtc._TRUST_INDUCTOR is False

    def test_contiguous_check_skipped_under_trust(self, monkeypatch):
        """Under trust mode, `_slang_tile_mm` must NOT call `is_contiguous()`
        on its tensor inputs (Inductor already guarantees it). We use a
        Tensor subclass that records `is_contiguous` calls to observe."""
        import contextlib

        from torch_vulkan.inductor import vulkan_template_caller as vtc

        monkeypatch.setenv("TORCH_VULKAN_TRUST_INDUCTOR", "1")
        vtc._reset_trust_inductor_cache()

        # Stub `compile_and_dispatch` so we don't actually JIT a shader.
        from torch_vulkan.inductor import runtime as rt

        orig_dispatch = rt.compile_and_dispatch

        def noop_dispatch(*args, **kwargs):
            return None

        # Patch via the module attribute the function imports lazily.
        from torch_vulkan.inductor import runtime

        monkeypatch.setattr(runtime, "compile_and_dispatch", noop_dispatch)

        n_contig_calls = {"v": 0}
        orig_is_contig = torch.Tensor.is_contiguous

        def counting_is_contig(self, *args, **kwargs):
            n_contig_calls["v"] += 1
            return orig_is_contig(self, *args, **kwargs)

        try:
            torch.Tensor.is_contiguous = counting_is_contig
            a = torch.randn(8, 16, device="vulkan:0")
            b = torch.randn(16, 8, device="vulkan:0")
            out = torch.empty(8, 8, device="vulkan:0")
            vtc._slang_tile_mm(
                8, 8, 16, 1, a, b, out, src="dummy_src", cache_key="dummy_key"
            )
            assert n_contig_calls["v"] == 0, (
                f"trust mode should skip is_contiguous(); "
                f"saw {n_contig_calls['v']} calls"
            )
        finally:
            torch.Tensor.is_contiguous = orig_is_contig
            monkeypatch.setattr(runtime, "compile_and_dispatch", orig_dispatch)
            monkeypatch.delenv("TORCH_VULKAN_TRUST_INDUCTOR", raising=False)
            vtc._reset_trust_inductor_cache()


class TestSlangTilePerDtypeCache:
    """P6.2: _SlangTile{MM,AddMM,BMM} cache the rendered Slang source +
    cache_key per dtype on the instance so the per-dispatch hot path skips
    the Jinja-render dict lookup and cache_key f-string."""

    def test_mm_per_dtype_cache_populated(self):
        from torch_vulkan.inductor.vulkan_template_caller import _SlangTileMM

        fn = _SlangTileMM(64, 64, 16, num_stages=1)
        assert fn._per_dtype == {}
        src1, key1 = fn._src_and_key("float")
        assert "float" in src1 or "(float)" in src1 or src1.count("float") > 0
        assert key1 == "slang_mm_64_64_16_s1_r1x1_float"
        # Second call: must hit the per-dtype cache (same identity).
        src2, key2 = fn._src_and_key("float")
        assert src2 is src1 and key2 is key1
        # Different dtype: separate cache entry.
        src3, key3 = fn._src_and_key("half")
        assert src3 is not src1
        assert key3 == "slang_mm_64_64_16_s1_r1x1_half"
        assert set(fn._per_dtype.keys()) == {"float", "half"}

    def test_addmm_per_dtype_cache_populated(self):
        from torch_vulkan.inductor.vulkan_template_caller import _SlangTileAddMM

        fn = _SlangTileAddMM(64, 64, 16, num_stages=2)
        src, key = fn._src_and_key("float")
        assert key == "slang_addmm_64_64_16_s2_r1x1_float"
        assert fn._src_and_key("float") == (src, key)

    def test_bmm_per_dtype_cache_populated(self):
        from torch_vulkan.inductor.vulkan_template_caller import _SlangTileBMM

        # 32x32x16 r1x1 is in `_MM_TILE_CONFIGS` (legacy 1-output-per-thread,
        # workgroup 1024 ≤ device limit). 64x64 r1x1 would be invalid (wg=4096).
        fn = _SlangTileBMM(32, 32, 16)
        src, key = fn._src_and_key("float")
        assert key == "slang_bmm_32_32_16_r1x1_float"
        # cache_key matches the prewarm spec collector format
        from torch_vulkan.inductor.vulkan_template_caller import (
            _collect_matmul_prewarm_specs,
        )

        keys = {k for k, _ in _collect_matmul_prewarm_specs()}
        assert key in keys
        # Register-tiled variant must also appear (64x64x16 r4x4 — 256-thread
        # wg with 16 outs/thread).
        fn_rt = _SlangTileBMM(64, 64, 16, m_per_thread=4, n_per_thread=4)
        _, rt_key = fn_rt._src_and_key("float")
        assert rt_key == "slang_bmm_64_64_16_r4x4_float"
        assert rt_key in keys

    def test_per_dtype_cache_resets_after_pickle_roundtrip(self):
        """`__reduce__` reconstructs from constructor params; `_per_dtype`
        must start empty after unpickle (the cached strings can't be reused
        across processes)."""
        import pickle

        from torch_vulkan.inductor.vulkan_template_caller import _SlangTileMM

        fn = _SlangTileMM(64, 64, 16, num_stages=1)
        fn._src_and_key("float")
        assert fn._per_dtype  # populated
        restored = pickle.loads(pickle.dumps(fn))
        assert restored._per_dtype == {}
        assert restored.__name__ == fn.__name__


class TestTrustInductor:
    """P0.4 (post P5.11.a.1): TORCH_VULKAN_TRUST_INDUCTOR no-ops
    assert_size_stride / assert_alignment in the wrapper preamble.
    Default flipped ON in P5.11.a.1; opt-OUT via `=0`. The default-on
    contract has its own three-lock class `TestTrustInductorDefaultOn`."""

    def test_trust_inductor_flag_round_trip(self, monkeypatch):
        from torch_vulkan.inductor.wrapper import _trust_inductor

        monkeypatch.setenv("TORCH_VULKAN_TRUST_INDUCTOR", "1")
        assert _trust_inductor() is True
        monkeypatch.setenv("TORCH_VULKAN_TRUST_INDUCTOR", "0")
        assert _trust_inductor() is False

    def test_compiled_graph_runs_with_trust(self, monkeypatch):
        """End-to-end: a compiled graph still produces correct results when
        the asserts are no-op'd. The compiled wrapper executes — if our
        substituted `assert_size_stride` swallowed everything correctly,
        the function still returns the right tensor."""
        import torch
        import torch_vulkan

        monkeypatch.setenv("TORCH_VULKAN_TRUST_INDUCTOR", "1")
        # Force a fresh codecache so the new header is regenerated.
        import shutil

        cache = os.environ.get("TORCHINDUCTOR_CACHE_DIR", "/tmp/torchinductor_amit")
        shutil.rmtree(cache, ignore_errors=True)

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.relu(x * 0.5 + 0.1)

        x = torch.randn(8, 16, device="vulkan:0")
        y = fn(x)
        torch.testing.assert_close(
            y.cpu(), torch.relu(x.cpu() * 0.5 + 0.1), rtol=1e-4, atol=1e-5
        )


class TestTrustInductorDefaultOn:
    """P5.11.a.1 — `TORCH_VULKAN_TRUST_INDUCTOR` defaults to ON (was opt-IN
    via `=1`).

    Three-lock contract:
      1. Default unset → `_trust_inductor()` returns True.
      2. Explicit `=0` → opt-OUT survives (debugging engineers can
         re-enable the asserts when chasing an Inductor codegen bug).
      3. Emitted wrapper Python source contains zero `assert_size_stride`
         calls under the new default — the structural contract that
         the µs/step gain (452→302 in roadmap §P5.11) follows from. A
         future refactor leaving `_trust_inductor()=True` but
         re-emitting asserts elsewhere fails this test loud.

    `_BUG_ROOT_COMPONENT="wrapper-codegen"`.
    """

    def test_default_is_on_in_wrapper(self, monkeypatch):
        from torch_vulkan.inductor.wrapper import _trust_inductor

        monkeypatch.delenv("TORCH_VULKAN_TRUST_INDUCTOR", raising=False)
        assert _trust_inductor() is True, (
            "P5.11.a.1: TORCH_VULKAN_TRUST_INDUCTOR must default to ON "
            "when env is unset"
        )

    def test_explicit_off_disables_trust(self, monkeypatch):
        from torch_vulkan.inductor.wrapper import _trust_inductor

        monkeypatch.setenv("TORCH_VULKAN_TRUST_INDUCTOR", "0")
        assert _trust_inductor() is False, (
            "P5.11.a.1: explicit TORCH_VULKAN_TRUST_INDUCTOR=0 must "
            "still suppress trust (opt-OUT preserved for debugging)"
        )

    def test_no_assert_size_stride_in_emitted_wrapper(self, monkeypatch):
        # Structural contract: under default-ON, the emitted wrapper Python
        # must not retain any `assert_size_stride` call sites. The
        # `write_header` splice replaces the upstream definitions with
        # no-op shims, so any `assert_size_stride(...)` line in the body
        # becomes dead code — but the line itself must not be there in
        # the first place if we're going to claim the assertion is elided.
        # A future refactor leaving _trust_inductor()=True but
        # re-emitting asserts elsewhere fails this test loud.
        import shutil

        import torch
        import torch_vulkan  # noqa: F401
        import torch_vulkan.inductor  # noqa: F401

        monkeypatch.delenv("TORCH_VULKAN_TRUST_INDUCTOR", raising=False)

        cache = os.environ.get("TORCHINDUCTOR_CACHE_DIR", "/tmp/torchinductor_amit")
        shutil.rmtree(cache, ignore_errors=True)

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.relu(x * 0.5 + 0.1)

        x = torch.randn(8, 16, device="vulkan:0")
        _ = fn(x)

        # Walk the inductor codecache looking for the most recently
        # emitted wrapper. The wrapper file is the only one with a
        # ``call(args)`` entry point and the empty_strided_vulkan import.
        emitted_sources: list[str] = []
        for root, _dirs, files in os.walk(cache):
            for name in files:
                if not name.endswith(".py"):
                    continue
                path = os.path.join(root, name)
                try:
                    with open(path) as f:
                        src = f.read()
                except OSError:
                    continue
                if "empty_strided_vulkan" in src or "_vk_make_kernel" in src:
                    emitted_sources.append(src)

        assert emitted_sources, (
            "P5.11.a.1: could not find any emitted Vulkan wrapper Python "
            f"source under {cache!r} after compile — test infrastructure "
            "issue (the inductor codecache may have moved)"
        )
        # Under default-ON, no emitted wrapper should contain a literal
        # `assert_size_stride(` call site. (`def assert_size_stride` —
        # the no-op shim spliced by write_header — is permitted; the
        # contract is on call sites, not definitions.)
        offenders = []
        for src in emitted_sources:
            for ln_no, ln in enumerate(src.splitlines(), 1):
                if "assert_size_stride(" in ln and "def assert_size_stride" not in ln:
                    offenders.append((ln_no, ln.strip()))
        assert not offenders, (
            f"P5.11.a.1: emitted wrapper still contains "
            f"{len(offenders)} `assert_size_stride(...)` call site(s) "
            f"under default-ON — TRUST flip did not elide them:\n  - "
            + "\n  - ".join(f"line {ln_no}: {ln}" for ln_no, ln in offenders[:10])
        )


class TestSpirvCacheGC:
    """P5.7: gc_spirv_cache trims the on-disk SPIR-V cache to a byte budget,
    deleting LRU entries first."""

    def test_gc_trims_to_budget(self, tmp_path, monkeypatch):
        import os
        import time

        monkeypatch.setattr(
            "torch_vulkan.inductor.runtime._DISK_CACHE_DIR", str(tmp_path)
        )
        # Create three shards of varying age. Each is 1 KiB.
        for i, name in enumerate(["aa/old.spv", "bb/mid.spv", "cc/new.spv"]):
            path = tmp_path / name
            path.parent.mkdir(parents=True, exist_ok=True)
            path.write_bytes(b"x" * 1024)
            os.utime(path, (1000.0 + i * 100, 1000.0 + i * 100))
            time.sleep(0)
        from torch_vulkan.inductor.runtime import gc_spirv_cache

        result = gc_spirv_cache(max_mib=0)  # delete everything
        assert result["removed"] == 3
        assert result["kept"] == 0
        assert result["bytes_after"] == 0

    def test_gc_keeps_newest(self, tmp_path, monkeypatch):
        import os

        monkeypatch.setattr(
            "torch_vulkan.inductor.runtime._DISK_CACHE_DIR", str(tmp_path)
        )
        for i, name in enumerate(["aa/old.spv", "bb/new.spv"]):
            path = tmp_path / name
            path.parent.mkdir(parents=True, exist_ok=True)
            path.write_bytes(b"x" * (1024 * 1024))  # 1 MiB each
            os.utime(path, (1000.0 + i * 100, 1000.0 + i * 100))
        from torch_vulkan.inductor.runtime import gc_spirv_cache

        result = gc_spirv_cache(max_mib=1)
        assert result["removed"] == 1
        assert result["kept"] == 1
        # The newest must survive.
        assert (tmp_path / "bb/new.spv").exists()
        assert not (tmp_path / "aa/old.spv").exists()

    def test_gc_missing_dir_is_safe(self, tmp_path, monkeypatch):
        monkeypatch.setattr(
            "torch_vulkan.inductor.runtime._DISK_CACHE_DIR",
            str(tmp_path / "nonexistent"),
        )
        from torch_vulkan.inductor.runtime import gc_spirv_cache

        result = gc_spirv_cache(max_mib=10)
        assert result == {"removed": 0, "kept": 0, "bytes_before": 0, "bytes_after": 0}


