class TestSlangcAvailableCached:
    """P6.1: `_slangc_available()` probes the slangc binary via subprocess.run
    once and caches the result for the lifetime of the module. A previous
    behavior re-probed on every cold compile, multiplying ~1 ms per kernel."""

    def test_slangc_available_caches_result(self, monkeypatch):
        from torch_vulkan.inductor import runtime as rt

        rt._reset_slangc_available_cache()
        n_calls = {"v": 0}
        orig = rt.subprocess.run

        def counting_run(*args, **kwargs):
            n_calls["v"] += 1
            return orig(*args, **kwargs)

        monkeypatch.setattr(rt.subprocess, "run", counting_run)

        first = rt._slangc_available()
        first_n = n_calls["v"]
        for _ in range(5):
            rt._slangc_available()
        assert n_calls["v"] == first_n, (
            "expected the slangc availability probe to be cached; "
            f"got {n_calls['v']} subprocess calls (was {first_n})"
        )
        # Reset hook lets subsequent re-probes succeed (used by tests).
        rt._reset_slangc_available_cache()
        rt._slangc_available()
        assert n_calls["v"] == first_n + 1

    def test_slangc_available_returns_bool(self):
        from torch_vulkan.inductor import runtime as rt

        rt._reset_slangc_available_cache()
        assert isinstance(rt._slangc_available(), bool)


class TestAsyncCompileSinglePass:
    """P6.1: Under `TORCH_VULKAN_ASYNC_COMPILE=1`, `compile_slang_to_spirv` must
    invoke the inner compile **exactly once** per cold key. Previously the
    sync-block path called `pool.submit(...).result()` (compiles), then read
    from `_cache_by_hash`, and on cache miss fell through to a *second* inline
    compile. The fall-through silently doubled the work and swallowed real
    errors. Locked here so the silent double-compile doesn't grow back."""

    def test_async_compile_path_does_not_double_compile(self, monkeypatch):
        from torch_vulkan.inductor import runtime as rt

        # Snapshot+clear caches so we definitely take the cold path.
        saved_by_key = dict(rt._cache_by_key)
        saved_by_hash = dict(rt._cache_by_hash)
        rt._cache_by_key.clear()
        rt._cache_by_hash.clear()
        try:
            n_inner = {"v": 0}
            sentinel = b"FAKE_SPIRV"

            def fake_inner(src, entry, hash_key, include_paths=()):
                n_inner["v"] += 1
                rt._cache_by_hash[hash_key] = sentinel
                return sentinel

            monkeypatch.setattr(rt, "_compile_slang_to_spirv_inner", fake_inner)
            monkeypatch.setattr(rt, "_ASYNC_COMPILE", True)

            spv = rt.compile_slang_to_spirv("dummy", cache_key="dummy_key")
            assert spv is sentinel
            assert n_inner["v"] == 1, (
                f"expected exactly one inner compile, got {n_inner['v']}"
            )

            # Second call must hit the in-memory cache, no extra inner compile.
            rt.compile_slang_to_spirv("dummy", cache_key="dummy_key")
            assert n_inner["v"] == 1
        finally:
            rt._cache_by_key.clear()
            rt._cache_by_key.update(saved_by_key)
            rt._cache_by_hash.clear()
            rt._cache_by_hash.update(saved_by_hash)

    def test_async_compile_path_propagates_errors(self, monkeypatch):
        from torch_vulkan.inductor import runtime as rt

        saved_by_key = dict(rt._cache_by_key)
        saved_by_hash = dict(rt._cache_by_hash)
        rt._cache_by_key.clear()
        rt._cache_by_hash.clear()
        try:

            def boom(src, entry, hash_key, include_paths=()):
                raise RuntimeError("simulated slangc failure")

            monkeypatch.setattr(rt, "_compile_slang_to_spirv_inner", boom)
            monkeypatch.setattr(rt, "_ASYNC_COMPILE", True)

            import pytest as _pt

            with _pt.raises(RuntimeError, match="simulated slangc failure"):
                rt.compile_slang_to_spirv("dummy", cache_key="err_key")
        finally:
            rt._cache_by_key.clear()
            rt._cache_by_key.update(saved_by_key)
            rt._cache_by_hash.clear()
            rt._cache_by_hash.update(saved_by_hash)


class TestInductorCacheNamespace:
    """P5.7: backend bumps TORCHINDUCTOR_CACHE_DIR to a vulkan-versioned
    sibling so cross-checkout cache reuse can't silently happen."""

    def test_namespace_function_sets_versioned_dir(self, monkeypatch):
        import os

        from torch_vulkan.inductor import _namespace_inductor_cache

        monkeypatch.delenv("TORCHINDUCTOR_CACHE_DIR", raising=False)
        monkeypatch.delenv("TORCH_VULKAN_NO_CACHE_NS", raising=False)
        _namespace_inductor_cache()
        cache_dir = os.environ.get("TORCHINDUCTOR_CACHE_DIR", "")
        assert "vulkan_" in cache_dir, (
            f"expected vulkan-namespaced cache dir, got {cache_dir!r}"
        )

    def test_namespace_respects_user_override(self, monkeypatch):
        import os

