    def test_scatter_reduce_mean_xfail_op_2_t4_11(self):
        """``scatter_reduce(reduce='mean')`` — T4.11 atomic add+count CAS shipped."""

        @torch.compile(backend="inductor")
        def fn(x, idx, src):
            return torch.scatter_reduce(x, 0, idx, src, reduce="mean")

        x = torch.zeros(5, 3, device="vulkan:0")
