class TestForeachAudit:
    """P10: `_foreach_*` combo-kernel coverage audit. After P1.4 re-enabled
    `BackendFeature.FOREACH` and shipped the combo rewrite, audit which
    ops fuse. `_foreach_add`, `_foreach_mul`, `_foreach_addcmul` all
    collapse to 1 combo dispatch."""

    def _two_lists(self):
        return (
            torch.randn(8, device="vulkan:0"),
            torch.randn(8, device="vulkan:0"),
            torch.randn(8, device="vulkan:0"),
            torch.randn(8, device="vulkan:0"),
        )

