class TestGeluBackwardOverloadAudit:
    """P10: every activation backward overload (`.default` and
    `.grad_input`) must be registered in the inductor lowering table.
    `gelu_backward` was missing — the upstream decomposition still fired,
    but the overload-coverage audit treated this as a gap. Lock both
    overloads so a future regression reproduces."""

    OVERLOADS_TO_CHECK = (
        "tanh_backward",
        "sigmoid_backward",
        "silu_backward",
        "gelu_backward",
        "threshold_backward",
        "leaky_relu_backward",
        "elu_backward",
        "softplus_backward",
        "hardswish_backward",
        "hardsigmoid_backward",
    )

    def test_every_activation_backward_overload_registered(self):
        import torch_vulkan
        from torch._inductor import lowering
        from torch_vulkan.inductor import register

        register()
        for op_name in self.OVERLOADS_TO_CHECK:
            op = getattr(torch.ops.aten, op_name)
            for ovr in op.overloads():
                full = getattr(op, ovr)
                assert full in lowering.lowerings, (
                    f"{op_name}.{ovr} not registered in Inductor lowering table"
                )


class TestDeterministicCompile:
    """P5.6: `torch.use_deterministic_algorithms(True)` must not break the
    Vulkan inductor backend. Pointwise + reduction kernels deterministic
    by construction — verify they compile + execute under the deterministic
    flag and produce correct results."""

    def test_deterministic_pointwise_compile(self):
        prev = torch.are_deterministic_algorithms_enabled()
        torch.use_deterministic_algorithms(True)
        try:

            @torch.compile(backend="inductor")
            def fn(x):
                return torch.relu(x * 0.5) + 1.0

            x = torch.randn(8, 16, device="vulkan:0")
            y = fn(x).cpu()
            expected = torch.relu(x.cpu() * 0.5) + 1.0
            torch.testing.assert_close(y, expected, rtol=1e-5, atol=1e-5)
        finally:
            torch.use_deterministic_algorithms(prev)

    def test_deterministic_reduction_compile(self):
        prev = torch.are_deterministic_algorithms_enabled()
        torch.use_deterministic_algorithms(True)
        try:

            @torch.compile(backend="inductor")
            def fn(x):
                return x.sum(dim=-1)

            x = torch.randn(8, 256, device="vulkan:0")
            y = fn(x).cpu()
            expected = x.cpu().sum(dim=-1)
            torch.testing.assert_close(y, expected, rtol=1e-4, atol=1e-4)
        finally:
            torch.use_deterministic_algorithms(prev)


