class TestSmallStaticReductionUnroll:
    """P1.6: when the multistage-reduction per-thread iteration count is a
    statically-known small integer (≤16), the emitted Slang carries
    `[unroll(N)]` on the reduction loop so slangc folds the load chain
    into independent VGPRs.

    Spy on `runtime.compile_slang_to_spirv` to capture the rendered Slang
    and assert the `[unroll(...)]` attribute is present for a sum kernel
    over a small static reduction dim."""

    def test_small_reduction_carries_unroll_attribute(self):
        from torch_vulkan.inductor import runtime

        captured: list[str] = []
        orig = runtime.compile_slang_to_spirv

        def spy(src, entry="computeMain", cache_key=None, config_key=None):
            captured.append(src)
            return orig(src, entry, cache_key)

        runtime.compile_slang_to_spirv = spy
        try:
            # rnumel = 1024 reduces, with numthreads=256 → loop_size=4 — in
            # the small-static unroll range. (rnumel < 256 hits the
            # persistent-reduction path, not the multistage loop.)
            @torch.compile(backend="inductor", dynamic=False)
            def fn(x):
                return x.sum(dim=-1)

            x = torch.randn(8, 1024, device="vulkan:0")
            fn(x)  # triggers compile + capture
            assert any(
                "[unroll(4)]" in src
                or "[unroll(2)]" in src
                or "[unroll(8)]" in src
                or "[unroll(16)]" in src
                for src in captured
            ), (
                "expected [unroll(N)] on the multistage reduction loop, "
                f"captured {len(captured)} kernels"
            )
        finally:
            runtime.compile_slang_to_spirv = orig


