class TestRedundantCopyRemoval:
    """`_remove_redundant_copy` FX pass deletes copy_ over view aliases.
    Verify a copy_ whose source is a view of dest is removed."""

    @pytest.fixture(autouse=True)
    def _ensure_inductor_loaded(self):
        # PF.55 — view symint pyimpl that fixes these tests is registered
        # at import of ``torch_vulkan.inductor``. The top-level fixture
        # only loads ``torch_vulkan``.
        import torch_vulkan.inductor  # noqa: F401

    def test_view_then_copy_no_extra_dispatch(self):
        """Compiling `out.copy_(out.view(out.shape))` should not emit
        a real copy dispatch — the view target IS the dest. The exact
        zero-dispatch behavior depends on the FX pass firing."""
        x = torch.randn(8, 16, device="vulkan:0")

        @torch.compile(backend="inductor")
        def fn(x):
            y = x + 1.0
            return y.view(8, 16)

        y = fn(x)
        torch.testing.assert_close(y.cpu(), x.cpu() + 1.0, rtol=1e-5, atol=1e-6)

    def test_reshape_after_pointwise(self):
        x = torch.randn(8, 16, device="vulkan:0")

        @torch.compile(backend="inductor")
        def fn(x):
            return (x + 1.0).reshape(8, 16)

        y = fn(x)
        torch.testing.assert_close(y.cpu(), x.cpu() + 1.0, atol=1e-5, rtol=1e-5)

    def test_pointwise_no_view_correct(self):
        """Sanity check: plain `x + 1` (no view) must produce correct values
        — establishes the pointwise codegen baseline that the view xfail
        cases above need to match."""
        x = torch.randn(8, 16, device="vulkan:0")

        @torch.compile(backend="inductor")
        def fn(x):
            return x + 1.0

        y = fn(x)
        torch.testing.assert_close(y.cpu(), x.cpu() + 1.0, rtol=1e-5, atol=1e-6)


