    def test_bmm_chain_correctness(self):
        """`bmm(a, b) * 2 + gelu(bmm(a, b))`: 5 dispatches (2 bmm + 1 fused
        epilogue + 2 alloc/copy). Locks correctness; fusing the duplicate bmm
        would need CSE across extern kernels (P17.12 territory)."""
        import torch.nn.functional as F
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x, y):
            return torch.bmm(x, y) * 2.0 + F.gelu(torch.bmm(x, y))

