class TestP12FactoryAndPointwiseBreadth:
    """P12 — factory + breadth pointwise coverage. Locks 1-dispatch contract
    on the most common scalar-pointwise patterns so a future codegen change
    that splits any of them surfaces here."""

    def test_factory_like_chain_one_dispatch(self):
        """`zeros_like + ones_like + full_like + x` — 1 dispatch (all factory
        constants inlined as scalar literals into the pointwise body)."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x):
            z = torch.zeros_like(x)
            o = torch.ones_like(x)
            f = torch.full_like(x, 3.14)
            return z + o + f + x

        a = torch.randn(8, 16, device="vulkan:0")
        fn(a)
        fn(a)
        _tv._c_ext._reset_perf_counters()
        out = fn(a)
        d = _tv._c_ext._get_dispatch_count()
        assert d <= 1, f"factory chain expected ≤1 dispatch, got {d}"
        expected = (
            torch.zeros_like(a.cpu())
            + torch.ones_like(a.cpu())
            + torch.full_like(a.cpu(), 3.14)
            + a.cpu()
        )
        torch.testing.assert_close(out.cpu(), expected, rtol=1e-5, atol=1e-5)

