    def test_mean_std_var_combo_one_dispatch(self):
        """`mean(x) - std(x) + sqrt(var(x))` — 3 reductions over the same
        axis fuse into a single welford-driven dispatch."""
        import torch_vulkan as _tv

        @torch.compile(backend="inductor")
        def fn(x):
            return x.mean(dim=-1) - x.std(dim=-1) + x.var(dim=-1).sqrt()

