class TestP12ScatterGatherTemplate:
    """T4.5 — scatter/gather/index_put correctness via the scatter_atomic
    Slang template. Tests the template directly via ``_dispatch_scatter_atomic``
    (not via ``torch.compile``, which routes gather/scatter through Inductor's
    stock decomposition and does not exercise the template).

    Covers gather, scatter, scatter_add, index_put, and index_put_accumulate
    on float32 with int64 indices."""

    # ── gather ────────────────────────────────────────────────────────

    def test_gather_1d_direct(self):
        """gather: out[i] = src[indices[i]] — 1D float32 / int64 indices."""
