class TestAutotuneCacheDiscipline:
    """P5.6 — repeat compiles of the same kernel hit the cache.

    `cache_hit_rate()` returns hits / (hits + cold_compiles); after
    warmup, dispatch the same kernel twice and assert the second
    invocation hits the in-memory cache. Locks the contract that
    cache keys are stable enough not to fragment per-shape (which
    would force a slangc cold compile every step).
    """

    def test_repeat_compile_hits_cache(self):
        from torch_vulkan.inductor.runtime import (
            cache_hit_rate,
            compile_slang_to_spirv,
            reset_compile_stats,
        )

        src = """
        [[vk::binding(0, 0)]] StructuredBuffer<float> in_x;
        [[vk::binding(1, 0)]] RWStructuredBuffer<float> out_y;
        [[vk::push_constant]] cbuffer Push { uint n; };
        [shader("compute")]
        [numthreads(64, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID) {
            if (tid.x < n) out_y[tid.x] = in_x[tid.x] + 1.0f;
        }
        """
        # Warmup pass populates the cache.
        compile_slang_to_spirv(src, cache_key="p56_disc_v1")
        reset_compile_stats()
        for _ in range(8):
            compile_slang_to_spirv(src, cache_key="p56_disc_v1")
        # All 8 must be cache hits — none cold.
        assert cache_hit_rate() == 1.0, cache_hit_rate()


class TestInductorOpCoverageAudit:
    """P7.4 — `scripts/audit_inductor_op_coverage.py` summarizes which
    aten ops have lowering / meta / override coverage in the Inductor
    backend.

    Locks the contract that the audit script runs and reports a
    self-consistent summary; future extensions (cross-checking
    against the Inductor decomposition table to find gaps) extend
    this baseline.
    """

    def test_audit_reports_self_consistent_summary(self):
        # Run the audit script as a subprocess and parse its summary
        # output (cleanest way to verify the CLI surface stays usable).
        import subprocess
        import sys

        script = os.path.join(
            os.path.dirname(__file__),
            "..",
            "scripts",
            "audit_inductor_op_coverage.py",
        )
        r = subprocess.run(
            [sys.executable, script],
            capture_output=True,
            text=True,
            check=True,
        )
        out = r.stdout
        assert "Inductor op-coverage audit" in out
        assert "total_ops" in out
        assert "lowered" in out
        # Pull total_ops out of the summary line.
        for line in out.splitlines():
            if line.strip().startswith("total_ops"):
                total = int(line.split("=")[1].strip())
                assert total >= 50, f"unexpectedly low op count: {total}"
                break
        else:
            raise AssertionError("audit output missing total_ops line")


class TestInductorWrapperEmitImports:
    """P7.4 extension — wrapper-emit import audit (PF.54-era class).

    The Inductor wrapper-codegen header (`wrapper.py:write_header`)
    splices Python `from <module> import <name>` lines into every
    compiled-graph wrapper. If a re-export from the package surface is
    silently stripped (the bug class that broke MLP/CNN compile until
    `_empty_strided_vulkan` was re-added), the failure shows up only
    at `torch.compile` runtime when the wrapper module first imports.

    This test catches the failure at static-analysis time. Runs the
    audit's `emit_import_summary()` and asserts every emitted import
    resolves. A non-zero `broken` count names the offending file:line
    and the symbol that's missing.

    `_BUG_ROOT_COMPONENT="package-surface"` (per §"Bug-Rooting Protocol":
    fix is a re-export in the relevant package's `__init__.py`).
    """

    def _import_audit(self):
        import os
        import sys

        scripts_dir = os.path.normpath(
            os.path.join(
                os.path.dirname(__file__),
                "..",
                "scripts",
            )
        )
        if scripts_dir not in sys.path:
            sys.path.insert(0, scripts_dir)
        import audit_inductor_op_coverage as a

        return a

    def test_every_emitted_import_resolves(self):
        a = self._import_audit()
        s = a.emit_import_summary()
        assert s["broken"] == 0, (
            f"P7.4 wrapper-emit audit found {s['broken']} broken "
            f"import(s) in wrapper-codegen header(s) — every compiled "
            f"graph would fail at wrapper-import time:\n  - "
            + "\n  - ".join(
                f"{r['file']}:{r['line']} "
                f"`from {r['module']} import {r['name']}` — {r['error']}"
                for r in s["broken_rows"]
            )
        )

    def test_audit_finds_at_least_one_emitted_import(self):
        # Sanity: if the regex falls behind the wrapper's emission
        # syntax (e.g. someone refactors `header.splice` to use
        # f-strings), the audit silently reports `total_imports=0`
        # and the broken-count check above degenerates. Assert we're
        # actually scanning *something*.
        a = self._import_audit()
        s = a.emit_import_summary()
        assert s["total_imports"] >= 1, (
            "P7.4 wrapper-emit audit scanned 0 imports — regex "
            "likely fell behind wrapper.py's emission syntax. Update "
            "`_EMIT_IMPORT_RE` in audit_inductor_op_coverage.py."
        )

    def test_cli_section_runs(self):
        # CLI path: the audit script's `main()` prints a "Wrapper-emit
        # import audit" section. Locks the surface so a future refactor
        # of the script keeps the section visible to humans inspecting
        # the audit output.
        import os
        import subprocess
        import sys

        script = os.path.join(
            os.path.dirname(__file__),
            "..",
            "scripts",
            "audit_inductor_op_coverage.py",
        )
        r = subprocess.run(
            [sys.executable, script],
            capture_output=True,
            text=True,
            check=True,
        )
        out = r.stdout
        assert "Wrapper-emit import audit" in out, (
            "audit CLI dropped the wrapper-emit section"
        )


class TestSlangcSmokeAudit:
    """P7.4.b — slangc-smoke audit catches the PF.5-era class.

    The wrapper-emit import audit (`TestInductorWrapperEmitImports`)
    catches the *Python-import* class of teammate-introduced
    breakage. The slangc-smoke audit catches the *shader-compile*
    class: a teammate change that breaks slangc compile of a
    canonical kernel pattern (e.g. helpers.slang loses a `public`
    export, or an mm-template mutation tickles a slangc bug) makes
    every inductor-emitted kernel of that shape fail at compile
    time inside `torch.compile`.

    Three canonical snippets cover today's emit shapes:
      - bare pointwise relu (no `import`, no helpers)
      - pointwise gelu using `import helpers;` + `c10_vulkan_erf`
      - mm-epilogue with push-constant struct + bias + erf
        (mirrors PF.5's `addmm_gelu_fused` codegen)

    The audit invokes slangc via the runtime entry point
    (`compile_slang_to_spirv`) so the same module-cache resolution
    Inductor uses at runtime is exercised — a stale
    `helpers.slang-module` cache surfaces here just as it would in
    a compiled-graph run.

    Skips when slangc is unavailable (CI without the binary).
    `_BUG_ROOT_COMPONENT="slang-shader-pipeline"`.
    """

    def _import_audit(self):
        import os
        import sys

        scripts_dir = os.path.normpath(
            os.path.join(
                os.path.dirname(__file__),
                "..",
                "scripts",
            )
        )
        if scripts_dir not in sys.path:
            sys.path.insert(0, scripts_dir)
        import audit_inductor_op_coverage as a

        return a

    def test_every_canonical_snippet_compiles(self):
        a = self._import_audit()
        s = a.slangc_smoke_summary()
        if s["unavailable"] >= s["total"] and s["total"] > 0:
            import pytest

            pytest.skip("slangc unavailable — smoke audit needs slangc")
        assert s["broken"] == 0, (
            f"P7.4.b slangc smoke audit found {s['broken']} canonical "
            f"snippet(s) that no longer compile — every "
            f"inductor-emitted kernel of a similar shape will fail at "
            f"`torch.compile` runtime:\n  - "
            + "\n  - ".join(f"{r['name']}: {r['error']}" for r in s["broken_rows"])
        )

    def test_audit_covers_at_least_one_helpers_module_path(self):
        # Sanity: at least one canonical snippet must exercise
        # `import helpers;` so a regression that breaks the
        # module-resolution path is caught (the exact PF.5 symptom).
        a = self._import_audit()
        snippets = a._SLANGC_SMOKE_SNIPPETS
        assert any("import helpers" in src for src in snippets.values()), (
            "slangc smoke audit must include at least one snippet "
            "exercising `import helpers;` to catch helpers-module "
            "regressions (PF.5 class). Add an entry to "
            "`_SLANGC_SMOKE_SNIPPETS` in audit_inductor_op_coverage.py."
        )

