class TestGradientReleaseE2ECompiled:
    """PF.42 e2e floor — gradient-class release fires in compiled training.

    RESOLVED (2026-05-06): After a pool-enabled compiled training step,
    ``release_count_for_class('gradient')`` is ≥ 1, confirming that
    ``_install_zero_grad_release_hook`` fires at runtime.

    Stage tag: ``BUG_ROOT="runtime"``.
    """

    _BUG_ROOT_COMPONENT = "runtime"

    def test_gradient_class_releases_on_compiled_zero_grad(self):
        """Pool-enabled compiled training: ``release_count_for_class(
        'gradient') >= 1`` after 2 steps confirms the hook fired."""
        import torch.nn as nn
        from torch_vulkan.inductor import buffer_pool

        buffer_pool._reset_disabled_cache()
        buffer_pool.reset_pool()
        try:
            model = (
                nn.Sequential(
                    nn.Linear(64, 128),
                    nn.ReLU(),
                    nn.Linear(128, 10),
                )
                .to("vulkan:0")
                .train()
            )
            opt = torch.optim.SGD(model.parameters(), lr=1e-3)
            comp = torch.compile(model, backend="inductor")
            x = torch.randn(8, 64, device="vulkan:0")

            for _ in range(2):
                opt.zero_grad()
                loss = comp(x).sum()
                loss.backward()
                opt.step()

            count = buffer_pool.release_count_for_class("gradient")
            assert count >= 1, (
                f"PF.42: release_count_for_class('gradient') = {count} "
                f"after 2 compiled training steps with pool enabled; "
                f"expected ≥ 1. The step-end gradient-class release hook "
                f"did not fire."
            )
        finally:
            buffer_pool._reset_disabled_cache()


class TestTrack6Survival:
    """T6.2 floor — runtime ``Optimizer.zero_grad`` patch fires
    ``release_class("gradient")`` every training step.

    The FX-pass-time hook in :func:`_install_zero_grad_release_hook` only
    fires once per joint-graph compile. Real training keeps re-using the
    cached compile, so without a runtime hook the gradient buckets pile
    up across steps and OOM the 6 GB RDNA1 GPU. The runtime hook installs
    a ``torch.optim.Optimizer.zero_grad`` monkey-patch at module-import
    time; this test exercises a 5-step MLP loop and asserts the
    ``release_count_for_class('gradient')`` counter advances per step
    *and* the buffer pool's gradient bucket is empty after each
    ``optimizer.zero_grad()``.

    Stage tag: ``BUG_ROOT="runtime"``.
    """

    _BUG_ROOT_COMPONENT = "runtime"

    @pytest.fixture(autouse=True)
    def _reset_pool_state(self):
        from torch_vulkan.inductor import buffer_pool

        buffer_pool._reset_disabled_cache()
        buffer_pool.reset_pool()
        yield
        buffer_pool._reset_disabled_cache()
        buffer_pool.reset_pool()

    def test_gradient_release_runtime_hook(self):
        """5-step eager MLP training loop: every ``optimizer.zero_grad()``
        call must advance ``release_count_for_class('gradient')`` and
        leave the gradient bucket empty.

        Drives the loop in eager mode (not torch.compile) so the test
        isolates the runtime hook from the FX-pass-time hook — eager
        execution never trips ``annotate_lifetime_classes`` and therefore
        never fires the FX-pass release. Any counter advance here can
        only come from the ``Optimizer.zero_grad`` patch.
        """
        import torch.nn as nn
        from torch_vulkan.inductor import buffer_pool
        from torch_vulkan.inductor.lifetime import (
            install_zero_grad_runtime_hook,
        )

        # Confirm the hook is installed (idempotent — auto-installed at
        # import time; this just makes the dependency explicit).
        install_zero_grad_runtime_hook()

        model = (
            nn.Sequential(
                nn.Linear(64, 128),
                nn.ReLU(),
                nn.Linear(128, 64),
                nn.ReLU(),
                nn.Linear(64, 10),
            )
            .to("vulkan:0")
            .train()
        )
        opt = torch.optim.SGD(model.parameters(), lr=1e-3)
        x = torch.randn(8, 64, device="vulkan:0")
        target = torch.randint(0, 10, (8,), device="vulkan:0")
        loss_fn = nn.CrossEntropyLoss()

        # Pre-seed the gradient bucket so the release call has something
        # to drop. Without this the eager training loop never produces
        # pool-tracked gradient tensors (eager allocations bypass the
        # Inductor wrapper that keys on lifetime_class), and we'd be
        # asserting against an empty bucket.
        def _seed_gradient_bucket():
            t = torch.empty_strided((4,), (1,), dtype=torch.float32, device="vulkan:0")
            buffer_pool.vulkan_pool_release(t, lifetime_class="gradient")

        counts = []
        bucket_sizes_after_zero_grad = []
        for step in range(5):
            _seed_gradient_bucket()
            # Sanity: the bucket holds the seeded tensor before zero_grad.
            assert any(k[2] == "gradient" for k in buffer_pool._buckets), (
                f"step {step}: failed to seed gradient bucket"
            )

            opt.zero_grad()

            # Post-zero_grad, the gradient bucket must be empty (released)
            # and the counter must have advanced.
            counts.append(buffer_pool.release_count_for_class("gradient"))
            bucket_sizes_after_zero_grad.append(
                sum(
                    len(v)
                    for k, v in buffer_pool._buckets.items()
                    if k[2] == "gradient"
                )
            )

            # Run the rest of the step so zero_grad's own semantics
            # (zeroing/None-ing the .grad attrs) get exercised end-to-end.
            out = model(x)
            loss = loss_fn(out, target)
            loss.backward()
            opt.step()

        # Counter must advance once per zero_grad call (5 calls).
        assert counts == [1, 2, 3, 4, 5], (
            f"T6.2: release_count_for_class('gradient') sequence = {counts}; "
            f"expected [1, 2, 3, 4, 5]. The Optimizer.zero_grad runtime "
            f"hook is not firing release_class('gradient') per step."
        )
        # Gradient bucket must be empty after every zero_grad call.
        assert all(s == 0 for s in bucket_sizes_after_zero_grad), (
            f"T6.2: gradient bucket sizes after zero_grad = "
            f"{bucket_sizes_after_zero_grad}; expected all zeros. "
            f"release_class('gradient') is firing but not draining the "
            f"bucket — possible counter-only patch."
        )
        # zero_grad's user-facing semantics still hold: model params have
        # the optimizer's gradient state managed correctly. With the
        # default set_to_none=True, .grad is None right after zero_grad —
        # but here we observe AFTER backward+step, so .grad is populated
        # by the most recent backward pass. The contract: zero_grad did
        # not crash and the loop ran to completion.
        for p in model.parameters():
            assert p.grad is not None, (
                "T6.2: optimizer.zero_grad's user-facing semantics broken "
                "— parameter has no .grad after backward+step. Did the "
                "patch swallow zero_grad's normal behavior?"
            )


class TestTrack6FiftyStepPlateau:
    """T6.4 — 50-step training-survival regression test with ± 5% pool plateau.

    Distinct from ``TestMultiStepTrainingMemoryPlateau`` (PF.63 / 1.25× cap on
    ``torch_vulkan.memory_cached()``): this gate watches the **buffer pool's
    own** byte total (``buffer_pool.pool_total_bytes()``) rather than the
    device allocator, which is the right signal for lifetime-class leaks.
    Now possible after T6.1 (pool default-on), T6.2 (zero_grad gradient
    release), T6.6 (sub-alloc dead code deleted), T6.7 (workspace scratch
    routed through pool — the last leak). A sample at step 10 establishes
    the baseline; samples every 5 steps from step 15-50 must stay within
    ± 5% of that baseline.

    Stage tag: ``BUG_ROOT="runtime"``.
    """

    _BUG_ROOT_COMPONENT = "runtime"

    @pytest.fixture(autouse=True)
    def _reset_pool_state(self):
        from torch_vulkan.inductor import buffer_pool

        buffer_pool._reset_disabled_cache()
        buffer_pool.reset_pool()
        yield
        buffer_pool._reset_disabled_cache()
        buffer_pool.reset_pool()

    def test_50_step_memory_plateau(self):
        """Drive 50 training steps of a 2-layer MLP through ``torch.compile``;
        sample ``buffer_pool.pool_total_bytes()`` at step 10 (baseline) and
        every 5 steps from 15-50; assert no sample exceeds ± 5% of baseline.
        """
        import torch.nn as nn
        from torch_vulkan.inductor import buffer_pool

        torch._dynamo.reset()
        torch.manual_seed(0)

        # Small MLP: keeps the test fast and exercises every lifetime
        # class (parameter/save_for_backward/gradient/transient/output
        # plus T6.7's scratch via the matmul extern path).
        model = (
            nn.Sequential(
                nn.Linear(64, 64),
                nn.GELU(),
                nn.Linear(64, 64),
            )
            .to("vulkan:0")
            .train()
        )
        opt = torch.optim.SGD(model.parameters(), lr=0.01)

        # T5.14 (fixed 2026-05-08) closed the fused reduction-elementwise
        # codegen bug (`r0__linear_idx` undefined in partitioned-2D
        # reduction kernels), so the loss + backward path is now
        # compileable in the same graph as the forward. We keep the
        # optimizer outside the compile boundary because foreach optimizer
        # template routing is on its own track (T4.8 / P1.6); the gate
        # stays focused on lifetime-class plateau, not optimizer fusion.
        @torch.compile(backend="inductor")
        def fwd_bwd(x, y):
            yhat = model(x)
            loss = (yhat - y).pow(2).sum()
            return loss

        def step(x, y):
            opt.zero_grad()
            loss = fwd_bwd(x, y)
            loss.backward()
            opt.step()
            return loss.detach()

        x = torch.randn(8, 64, device="vulkan:0")
        y = torch.randn(8, 64, device="vulkan:0")

        # Warmup: 10 steps to populate every bucket and lock in the
        # compiled cache. Pool size after the first 1-2 steps reflects
        # the cold-compile fill phase, not the steady state.
        for _ in range(10):
            step(x, y)
            # Force a flush so released-then-cached pool tensors settle
            # before the next sample (sync point — buffer_pool is bytes
            # in Python objects, but the C++ allocator is async).
            torch.empty(1, device="vulkan:0").cpu()

        baseline = buffer_pool.pool_total_bytes()

        # 40 more steps; sample every 5 to get 8 datapoints across the
        # tail. Each sample is the pool's bucketed-bytes total — strictly
        # a lifetime-class signal, independent of the device allocator's
        # caching behavior.
        samples: list[tuple[int, int]] = []  # (step_index, bytes)
        for i in range(40):
            step(x, y)
            torch.empty(1, device="vulkan:0").cpu()
            if (i + 1) % 5 == 0:
                samples.append((10 + i + 1, buffer_pool.pool_total_bytes()))

        # Assert ± 5% plateau across every sample.
        worst_step, worst_ratio = -1, 0.0
        for step_idx, s in samples:
            ratio = abs(s - baseline) / max(baseline, 1)
            if ratio > worst_ratio:
                worst_ratio = ratio
                worst_step = step_idx
        assert worst_ratio < 0.05, (
            f"T6.4: buffer_pool.pool_total_bytes() did not plateau ± 5% "
            f"across steps 10-50. baseline (step 10) = {baseline} B; "
            f"worst sample at step {worst_step} = {dict(samples).get(worst_step)} B "
            f"({worst_ratio:.1%} drift). Full samples = {samples}. "
            f"A drifting bucket means a lifetime class is leaking — most "
            f"likely save_for_backward (PF.41 hold-across-fwd-bwd), "
            f"gradient (T6.2 zero_grad release), or scratch (T6.7 workspace)."
        )


class TestT63ExternKernelPoolRouting:
    """T6.3 — Extern-kernel allocator hook: mm/conv/SDPA/Philox outputs
    must route through the buffer pool instead of bypassing it via
    ``torch.empty`` directly.

    The wrapper's ``generate_extern_kernel_alloc`` pre-allocates output
    buffers via ``empty_strided_vulkan`` (which consults the pool) and
    passes them as ``out=`` kwargs to the extern kernel. Template callers
    (mm, addmm, bmm, flash attention, Philox) accept ``out=`` and skip
    their internal ``torch.empty`` fallback when a pre-allocated buffer
    is provided. The wrapper's ``make_buffer_free`` returns every buffer
    to the pool at end-of-life.

    Floors locked here:
      - test_mm_output_uses_pool: matmul through pool → pool size grows
        then stabilizes across repeated compiled calls.
      - test_philox_output_uses_pool: Philox RNG output routes through
        pool (was the last holdout — ``__call__`` had a bare
        ``torch.empty`` without ``pool_acquire``).
      - test_50_step_mm_training_pool_plateau: 50-step MLP training
        with all extern outputs through pool plateaus memory.

    Stage tag: ``BUG_ROOT="runtime"``.
    """

    _BUG_ROOT_COMPONENT = "runtime"

    @pytest.fixture(autouse=True)
    def _reset_pool_state(self):
        from torch_vulkan.inductor import buffer_pool

        buffer_pool._reset_disabled_cache()
        buffer_pool.reset_pool()
        yield
        buffer_pool._reset_disabled_cache()
        buffer_pool.reset_pool()

    def test_mm_output_uses_pool(self):
        """Compiled matmul must route its output through the pool.

        Strategy: compile a single ``torch.mm`` call, run it twice, and
        assert the pool's hit counter advances — proving the second call
        recycled the first call's output buffer rather than allocating
        fresh via ``torch.empty``.
        """
        from torch_vulkan.inductor import buffer_pool

        buffer_pool.reset_pool()

        @torch.compile(backend="inductor")
        def mm(x, w):
            return torch.mm(x, w)

        x = torch.randn(32, 64, device="vulkan:0")
        w = torch.randn(64, 32, device="vulkan:0")

        # First call: cold pool, output allocated fresh (miss).
        out1 = mm(x, w)
        s1 = buffer_pool.pool_stats()

        # Second call: the first output was released to the pool by
        # ``make_buffer_free``; this call should hit the pool.
        out2 = mm(x, w)
        s2 = buffer_pool.pool_stats()

        # After two calls we should see at least one pool hit (the second
        # call recycling the first call's output buffer).
        assert s2["hits"] > s1["hits"], (
            f"T6.3: mm output did not route through pool. "
            f"stats after 1st call: {s1}, after 2nd call: {s2}"
        )
        # Also verify the pool was consulted (acquires > 0).
        assert s2["acquires"] >= 2, (
            f"T6.3: pool was not consulted for mm outputs. stats={s2}"
        )

    def test_philox_output_uses_pool(self):
        """Compiled Philox RNG (aten.rand) must route output through pool.

        Before T6.3, ``_SlangPhiloxRNG.__call__`` allocated the primary
        output via bare ``torch.empty`` without consulting the pool.
        After T6.3, ``pool_acquire`` is tried first, and only on miss
        does it fall back to ``torch.empty``.
        """
        from torch_vulkan.inductor import buffer_pool

        buffer_pool.reset_pool()
        torch._dynamo.reset()

        @torch.compile(backend="inductor")
        def rand_vulkan(size):
            return torch.rand(size, device="vulkan:0")

        # First call: cold pool, output via pool_acquire miss → torch.empty.
        out1 = rand_vulkan([64, 64])
        s1 = buffer_pool.pool_stats()

        # Second call: output from first call released to pool, should hit.
        out2 = rand_vulkan([64, 64])
        s2 = buffer_pool.pool_stats()

        assert s2["hits"] > s1["hits"], (
            f"T6.3: Philox output did not route through pool. "
            f"stats after 1st call: {s1}, after 2nd call: {s2}"
        )
        assert s2["acquires"] >= 2, (
            f"T6.3: pool was not consulted for Philox outputs. stats={s2}"
        )

    def test_50_step_mm_training_pool_plateau(self):
        """50-step MLP training with all extern outputs through pool plateaus.

        Distinct from ``TestTrack6FiftyStepPlateau.test_50_step_memory_plateau``
        (T6.4): that gate watches the pool's byte-total; this gate
        additionally asserts that after the cold-fill phase (first 5 steps),
        the pool's hit-rate stays at 100% — every subsequent acquire is
        satisfied from the pool, proving zero ``torch.empty`` fallback
        allocations for extern-kernel outputs.
        """
        import torch.nn as nn
        from torch_vulkan.inductor import buffer_pool

        torch._dynamo.reset()
        torch.manual_seed(42)
        buffer_pool.reset_pool()

        model = (
            nn.Sequential(
                nn.Linear(64, 64),
                nn.GELU(),
                nn.Linear(64, 64),
            )
            .to("vulkan:0")
            .train()
        )
        opt = torch.optim.SGD(model.parameters(), lr=0.01)

        @torch.compile(backend="inductor")
        def fwd_bwd(x, y):
            yhat = model(x)
            loss = (yhat - y).pow(2).sum()
            return loss

        def step(x, y):
            opt.zero_grad()
            loss = fwd_bwd(x, y)
            loss.backward()
            opt.step()
            return loss.detach()

        x = torch.randn(8, 64, device="vulkan:0")
        y = torch.randn(8, 64, device="vulkan:0")

        # Warmup: 5 steps to populate buckets and lock compiled cache.
        for _ in range(5):
            step(x, y)
            torch.empty(1, device="vulkan:0").cpu()

        # Reset pool stats after warmup so we measure steady-state only.
        buffer_pool.reset_pool()

        # 45 more steps; sample pool stats every 15 steps.
        samples: list[dict] = []
        for i in range(45):
            step(x, y)
            torch.empty(1, device="vulkan:0").cpu()
            if (i + 1) % 15 == 0:
                samples.append(buffer_pool.pool_stats())

        # After warmup, every acquire should be a hit (steady-state pool
        # should have all needed buffer sizes cached).
        for idx, s in enumerate(samples):
            step_num = 5 + (idx + 1) * 15
            misses = s["misses"]
            acquires = s["acquires"]
            # Allow a small number of misses (cold-start for new buffer
            # shapes that weren't in the warmup set), but the hit rate
            # must be >= 90% in steady state.
            hit_rate = (acquires - misses) / max(acquires, 1)
            assert hit_rate >= 0.90, (
                f"T6.3: pool hit rate below 90% at step ~{step_num}. "
                f"acquires={acquires}, misses={misses}, "
                f"hit_rate={hit_rate:.1%}. stats={s}"
            )

        # Final sanity: pool byte-total should be stable.
        pool_bytes = buffer_pool.pool_total_bytes()
        assert pool_bytes >= 0, f"pool_total_bytes negative: {pool_bytes}"


class TestMultiStepTrainingMemoryPlateau:
    """PF.63 floor — multi-step training OOM survival gate on RDNA1 6 GB
    (TA15, filed 2026-04-30). Drives ≥ 50 training steps of a small
    transformer block on Vulkan compiled mode and asserts
    ``memory_cached()`` plateaus by step 10 (no monotonic growth across
    steps thereafter).

    RESOLVED (2026-05-06): All 3 blockers cleared —
    PF.13.b.4 (bwd grad_fn loss) ✓, PF.33 (extern allocator hook) ✓,
    combo-kernel duplicate-binding crash (GAP-1.1-B) ✓.

    Stage tag: ``BUG_ROOT="runtime"``.
    """

    _BUG_ROOT_COMPONENT = "runtime"

    _STEPS = 50
    _BASELINE_AT = 10

    # GAP-1.1-B: Combo-kernel buffer dedup fixed (2026-05-06).
    # PF.13.b.4 (bwd grad_fn loss) was already resolved; PF.33 (extern
    # allocator hook) is wired via generate_extern_kernel_alloc; the
    # combo-kernel duplicate-binding crash was the last blocker.
    def test_50_step_miniqwen3_2l_plateaus(self):
        import torch.nn as nn
        import torch_vulkan
        from torch_vulkan.inductor import buffer_pool

        buffer_pool._reset_disabled_cache()
        buffer_pool.reset_pool()
        try:
            # MiniQwen3-2L proxy: 2 transformer-style blocks (RMSNorm +
            # MLP), B=2, S=64, D=256. The full GQA attention path lights
            # up extern aten ops we don't want gating PF.63 (PF.13.b.4
            # owns matmul+softmax bwd). The norm + MLP block alone
            # exercises every save_for_backward / gradient class on the
            # compiled training step and is sufficient to reproduce the
            # multi-step plateau failure today.
            class Block(nn.Module):
                def __init__(self, d=256):
                    super().__init__()
                    self.norm1 = nn.RMSNorm(d)
                    self.norm2 = nn.RMSNorm(d)
                    self.mlp = nn.Sequential(
                        nn.Linear(d, d * 4),
                        nn.GELU(),
                        nn.Linear(d * 4, d),
                    )

                def forward(self, x):
                    x = x + self.mlp(self.norm1(x))
                    x = x + self.mlp(self.norm2(x))
                    return x

            model = Block().to("vulkan:0").train()
            comp = torch.compile(model, backend="inductor")
            opt = torch.optim.SGD(model.parameters(), lr=1e-4)
            x = torch.randn(2, 64, 256, device="vulkan:0")

            cached = []
            for step in range(self._STEPS):
                opt.zero_grad()
                out = comp(x)
                loss = out.sum()
                loss.backward()
                opt.step()
                # Force a flush so memory_cached() reflects post-step.
                torch.empty(1, device="vulkan:0").cpu()
                cached.append(torch_vulkan.memory_cached())

            baseline = cached[self._BASELINE_AT]
            tail = cached[self._BASELINE_AT + 1 :]
            max_tail = max(tail) if tail else baseline
            ratio = (max_tail / baseline) if baseline > 0 else 1.0
            # PF.63 contract: ≤ 25% growth from step-10 baseline through
            # step-49. A leak of one tensor per step would push this
            # well past 2× over 40 steps.
            assert ratio <= 1.25, (
                f"PF.63: memory_cached() did not plateau by step "
                f"{self._BASELINE_AT}. baseline={baseline}, "
                f"max_tail={max_tail}, ratio={ratio:.3f}, "
                f"all_cached={cached}. The PF-E activation pool is not "
                f"releasing save_for_backward/gradient buckets at the "
                f"step boundary."
            )
        finally:
            buffer_pool._reset_disabled_cache()
            buffer_pool.reset_pool()


class TestGradientLifetimeReleaseOnZeroGrad:
    """PF.42 regression-guard — born GREEN (TA15 step-end release hook).

    The PF.42 detection chain has two coupled invariants:

    1. PF.40's :func:`annotate_lifetime_classes` tags the gradient seed
       node (the parameter whose grad is being zeroed) with
       ``lifetime_class="gradient"``.
    2. :func:`_install_zero_grad_release_hook` walks the joint graph for
       ``aten.zero_.default`` call_function nodes whose first positional
       arg carries that ``"gradient"`` annotation and, on detecting
       ``sites >= 1``, fires a single ``release_class("gradient")`` call
       into the buffer pool.

    Both halves are required: a regression in (1) yields ``sites == 0``
    and a confusing zero counter; a regression in (2) yields no release
    even when (1) is fine. This test asserts both *belt-and-suspenders*
    via an annotation precheck **before** invoking the hook, then
    asserts both ``sites >= 1`` and ``release_count_for_class("gradient")
    >= 1`` post-invoke.

    PF.42 effective only when the buffer pool is enabled (default-on,
    opt-out via ``TORCH_VULKAN_BUFFER_POOL=0``); end-to-end ratchet remains gated on PF.63's
    3-gate dependency chain (PF.13.b.4 / PF.33 / storage-clone). This
    test is a synthetic-FX regression-guard that proves the detection
    chain is demonstrably installed, without requiring a compiled
    training-loop dispatch.

    `_BUG_ROOT_COMPONENT="runtime"`.
    """

    _BUG_ROOT_COMPONENT = "runtime"

    def test_zero_grad_pattern_fires_release_class(self):
        import torch.fx as fx
        from torch_vulkan.inductor import buffer_pool
        from torch_vulkan.inductor.lifetime import (
            _install_zero_grad_release_hook,
            annotate_lifetime_classes,
        )

        buffer_pool._reset_disabled_cache()
        buffer_pool.reset_pool()
        try:
            # Synthetic joint-graph fragment: a parameter (gradient seed)
            # threaded through aten.zero_.default, mirroring what the
            # optimizer's zero_grad lowering produces. PF.40 annotates
            # the seed as ``lifetime_class="gradient"``; PF.42's hook
            # fires release_class once the zero_ site is observed.
            graph = fx.Graph()
            grad = graph.placeholder("grad")
            grad.meta["lifetime_class"] = "gradient"
            graph.call_function(torch.ops.aten.zero_.default, args=(grad,))
            graph.output(grad)

            # Belt-and-suspenders precheck — runs BEFORE the hook so a
            # PF.40 annotation regression yields a clean assertion
            # failure rather than a confusing 0-counter from the hook.
            seed_nodes = [
                n for n in graph.nodes if n.meta.get("lifetime_class") == "gradient"
            ]
            assert seed_nodes, (
                "PF.42 precheck: no node carries "
                'lifetime_class="gradient" — PF.40 annotation regressed. '
                "Hook would silently report sites=0; failing loudly here."
            )

            sites = _install_zero_grad_release_hook(graph)

            assert sites >= 1, (
                f"PF.42 detection: _install_zero_grad_release_hook "
                f"returned sites={sites} on a graph with one "
                f"aten.zero_.default(grad) call where grad is annotated "
                f'lifetime_class="gradient". The hook is not detecting '
                f"the zero-on-gradient pattern."
            )
            assert buffer_pool.release_count_for_class("gradient") >= 1, (
                f"PF.42 release: hook detected sites={sites} but "
                f"release_count_for_class('gradient') = "
                f"{buffer_pool.release_count_for_class('gradient')}. "
                f"The hook is not invoking release_class on the buffer "
                f"pool."
            )
        finally:
            buffer_pool._reset_disabled_cache()
            buffer_pool.reset_pool()


