# T.5 — Slang Source Validator (in-process, no GPU / no slangc)
# ═══════════════════════════════════════════════════════════════════════════


class TestSlangSourceValidator:
    """T.5 — Lightweight in-process Slang source validation.

    Every check runs purely against the generated source string — no slangc
    subprocess, no SPIR-V compilation, no GPU.  The validator catches
    common codegen bugs early in CI."""

    @staticmethod
    def _validate(src: str) -> list:
        from torch_vulkan.inductor.slang_validator import validate_slang_source

        return validate_slang_source(src)

    # ── each injected-error type ──────────────────────────────────────

    def test_clean_source_passes(self):
        """A well-formed shader produces zero issues."""
        clean = """\
[shader("compute")]
[numthreads(64, 1, 1)]
void computeMain(uint3 gtid : SV_DispatchThreadID,
                 uint3 lid : SV_GroupThreadID,
                 uint3 gid : SV_GroupID) {
    float x = (float)gtid.x;
    float y = x * 2.0;
}
"""
        issues = self._validate(clean)
        assert len(issues) == 0, f"Expected 0 issues, got: {issues}"

    def test_brace_balance_caught(self):
        src = """\
[shader("compute")]
[numthreads(64, 1, 1)]
void computeMain(uint3 gtid : SV_DispatchThreadID) {
    float x = (float)gtid.x;
    if (x > 0.0) {
        x = x * 2.0;
    // missing closing brace for if
    // missing closing brace for function
"""
        issues = self._validate(src)
        assert any(i.category == "brace" for i in issues), (
            f"Expected brace issue, got: {issues}"
        )

    def test_binding_contiguity_caught(self):
        src = """\
[shader("compute")]
[numthreads(64, 1, 1)]
[[vk::binding(0)]] StructuredBuffer<float> a;
[[vk::binding(2)]] RWStructuredBuffer<float> b;
[[vk::binding(5)]] StructuredBuffer<float> c;
void computeMain(uint3 gtid : SV_DispatchThreadID) {
    b[gtid.x] = a[gtid.x] + c[gtid.x];
}
"""
        issues = self._validate(src)
        assert any(i.category == "binding" for i in issues), (
            f"Expected binding contiguity issue, got: {issues}"
        )

    def test_unclosed_string_caught(self):
        src = """\
[shader("compute")]
[numthreads(64, 1, 1)]
void computeMain(uint3 gtid : SV_DispatchThreadID) {
    // This string is never closed:
    float3x3 a = "unclosed;
}
"""
        issues = self._validate(src)
        assert any(
            i.category == "brace" and "string" in i.message.lower() for i in issues
        ), f"Expected unclosed string issue, got: {issues}"

    def test_unclosed_comment_caught(self):
        src = """\
[shader("compute")]
[numthreads(64, 1, 1)]
/* This block comment is never closed.
void computeMain(uint3 gtid : SV_DispatchThreadID) {
    float x = (float)gtid.x;
}
"""
        issues = self._validate(src)
        assert any(
            i.category == "brace" and "comment" in i.message.lower() for i in issues
        ), f"Expected unclosed comment issue, got: {issues}"

    def test_numthreads_exceeded_caught(self):
        src = """\
[shader("compute")]
[numthreads(2048, 2, 1)]
void computeMain(uint3 gtid : SV_DispatchThreadID) {
    float x = (float)gtid.x;
}
"""
        issues = self._validate(src)
        assert any(i.category == "numthreads" for i in issues), (
            f"Expected numthreads issue, got: {issues}"
        )

    def test_groupshared_budget_exceeded_caught(self):
        src = """\
[shader("compute")]
[numthreads(64, 1, 1)]
groupshared float big[16384];
groupshared float also_big[16384];
void computeMain(uint3 gtid : SV_DispatchThreadID) {
    big[gtid.x] = also_big[gtid.x];
}
"""
        issues = self._validate(src)
        assert any(i.category == "groupshared" for i in issues), (
            f"Expected groupshared budget issue, got: {issues}"
        )

    def test_undefined_identifier_caught(self):
        """A single-use non-keyword identifier like `s27` should be flagged."""
        src = """\
[shader("compute")]
[numthreads(64, 1, 1)]
void computeMain(uint3 gtid : SV_DispatchThreadID) {
    float x = (float)gtid.x;
    float y = s27;  // s27 never declared — single-use = typo
    float z = x + y;
}
"""
        issues = self._validate(src)
        assert any(i.category == "identifier" for i in issues), (
            f"Expected identifier issue for 's27', got: {issues}"
        )

    def test_inject_and_validate_catches_5_errors(self):
        """Exit gate: the `inject_and_validate()` harness catches all
        7 injected error types without GPU or slangc."""
        from torch_vulkan.inductor.slang_validator import inject_and_validate

        results, report = inject_and_validate()
        caught = sum(1 for v in results.values() if v)
        total = len(results)
        assert caught >= 5, (
            f"Exit gate: expected ≥5 of {total} injected errors caught, "
            f"got {caught}.\n{report}"
        )

    def test_clean_philox_template_passes(self):
        """The rendered Philox uniform template passes validation."""
        from torch_vulkan.inductor.vulkan_template_caller import _render_philox_rng

        src = _render_philox_rng(output_dtype="float", rng_mode="uniform")
        issues = self._validate(src)
        assert len(issues) == 0, (
            f"Philox uniform template should pass validation, got: {issues}"
        )

    def test_clean_foreach_sgd_template_passes(self):
        """The rendered foreach SGD template passes validation."""
        from torch_vulkan.inductor.vulkan_template_caller import (
            _render_foreach_optimizer_slang,
        )

        src = _render_foreach_optimizer_slang(
            algorithm="sgd", batch_size=7, output_dtype="float"
        )
        issues = self._validate(src)
        assert len(issues) == 0, (
            f"Foreach SGD template should pass validation, got: {issues}"
        )


