# T.2 — Systematic test fixes: newly-wired template regression tests
# ═══════════════════════════════════════════════════════════════════════════


class TestTrackT2TemplateWiring:
    """T.2 — Regression tests for the newly-wired Track-4 templates.

    Each test creates a small model/graph, runs it under
    ``torch.compile(backend="inductor")``, compares output against a CPU
    reference, and asserts a dispatch-count ceiling."""

    # ── Philox RNG ────────────────────────────────────────────────────

    def test_philox_rng_uniform_compiled(self):
        """Compiled `torch.rand` routes through Philox template, matches
        CPU bounds (0..1), and stays under the dispatch ceiling."""
        import torch_vulkan

        @torch.compile(backend="inductor")
        def fn(size):
            return torch.rand(size, device="vulkan:0")

        size = (64, 64)
        torch.manual_seed(1234)
        out = fn(size)

        torch_vulkan._c_ext._reset_perf_counters()
        torch.manual_seed(1234)
        out = fn(size)
        d = torch_vulkan._c_ext._get_dispatch_count()
        assert d <= 5, f"Philox uniform: expected ≤5 dispatches, got {d}"
        # Check output is in [0, 1)
        cpu_out = out.cpu()
        assert cpu_out.min() >= 0.0, f"min={cpu_out.min()} < 0"
        assert cpu_out.max() < 1.0, f"max={cpu_out.max()} >= 1"

    def test_philox_rng_normal_compiled(self):
        """Compiled `torch.randn` routes through Philox normal template,
        stays under the dispatch ceiling."""
        import torch_vulkan

        @torch.compile(backend="inductor")
        def fn(size):
            return torch.randn(size, device="vulkan:0")

        size = (64, 64)
        torch.manual_seed(5678)
        out = fn(size)

        torch_vulkan._c_ext._reset_perf_counters()
        torch.manual_seed(5678)
        out = fn(size)
        d = torch_vulkan._c_ext._get_dispatch_count()
        assert d <= 5, f"Philox normal: expected ≤5 dispatches, got {d}"
        # Check output has reasonable variance (not all zeros)
        cpu_out = out.cpu()
        assert cpu_out.std() > 0.1, (
            f"Philox normal output std={cpu_out.std():.4f} too low"
        )

    def test_philox_fused_dropout_compiled(self):
        """Compiled `F.dropout(…, training=True)` produces output with
        correct sparsity pattern (some zeros, some scaled values) and
        stays under the dispatch ceiling."""
        import torch.nn.functional as F
        import torch_vulkan

        @torch.compile(backend="inductor")
        def fn(x):
            return F.dropout(x, p=0.5, training=True)

        x = torch.ones(128, 64, device="vulkan:0")
        torch.manual_seed(42)
        fn(x)  # warm-up

        torch_vulkan._c_ext._reset_perf_counters()
        torch.manual_seed(42)
        out = fn(x)
        d = torch_vulkan._c_ext._get_dispatch_count()
        assert d <= 5, f"Dropout: expected ≤5 dispatches, got {d}"

        cpu_out = out.cpu()
        total = cpu_out.numel()
        zeros = (cpu_out == 0.0).sum().item()
        scaled = (cpu_out == 2.0).sum().item()  # keep = 0.5 → scale = 2.0
        # Allow some tolerance: 40%–60% dropout
        assert 0.2 * total <= zeros <= 0.8 * total, (
            f"Dropout: {zeros}/{total} zeros (expected ~50%)"
        )
        assert zeros + scaled == total, (
            f"Dropout: {zeros} zeros + {scaled} scaled ≠ {total}"
        )

    # ── Flash Attention ───────────────────────────────────────────────

    @pytest.mark.xfail(
        strict=False,
        reason=(
            "Flash attention template has known algorithmic issues "
            "(online softmax two-pass tiling not yet numerically correct). "
            "T4.7 in-progress. Remove xfail once the algorithm passes."
        ),
    )
    def test_flash_attention_fwd_compiled(self):
        """Compiled SDPA with causal mask produces correct output vs CPU
        reference."""
        import torch.nn.functional as F

        @torch.compile(backend="inductor")
        def fn(q, k, v):
            return F.scaled_dot_product_attention(q, k, v, is_causal=True)

        q = torch.randn(1, 2, 8, 64, device="vulkan:0")
        k = torch.randn(1, 2, 8, 64, device="vulkan:0")
        v = torch.randn(1, 2, 8, 64, device="vulkan:0")
        result = fn(q, k, v)
        expected = F.scaled_dot_product_attention(
            q.cpu(), k.cpu(), v.cpu(), is_causal=True
        )
        torch.testing.assert_close(result.cpu(), expected, rtol=1e-2, atol=1e-2)

    # ── Foreach optimizer ─────────────────────────────────────────────

    def test_foreach_sgd_step_compiled(self):
        """Compiled SGD step via foreach ops matches CPU reference and
        stays under the dispatch ceiling."""
        import torch_vulkan

        @torch.compile(backend="inductor")
        def sgd_step(params, grads, lr, wd):
            torch._foreach_mul_(params, 1.0 - lr * wd)
            torch._foreach_add_(params, grads, alpha=-lr)
            return params

        n_params = 4
        params = [torch.randn(32, 32, device="vulkan:0") for _ in range(n_params)]
        grads = [torch.randn(32, 32, device="vulkan:0") for _ in range(n_params)]
        params_cpu = [p.cpu().clone() for p in params]
        grads_cpu = [g.cpu().clone() for g in grads]

        lr = 0.01
        wd = 0.0

        with torch.no_grad():
            sgd_step(params, grads, lr, wd)
            torch_vulkan._c_ext._reset_perf_counters()
            sgd_step(params, grads, lr, wd)
            d = torch_vulkan._c_ext._get_dispatch_count()

        assert d <= 3, f"SGD foreach: expected ≤3 dispatches, got {d}"

        # CPU reference
        for p_cpu, g_cpu in zip(params_cpu, grads_cpu):
            p_cpu.mul_(1.0 - lr * wd).add_(g_cpu, alpha=-lr)

        for vk, cpu in zip(params, params_cpu):
            torch.testing.assert_close(vk.cpu(), cpu, rtol=1e-4, atol=1e-4)

    def test_foreach_adamw_step_compiled(self):
        """Compiled AdamW-style step (foreach_mul + foreach_add) matches
        CPU reference and stays under the dispatch ceiling."""
        import torch_vulkan

        @torch.compile(backend="inductor")
        def adamw_step(params, grads, m_vals, v_vals, lr, beta1, beta2, eps, wd):
            # Simplified AdamW: m = β₁*m + (1-β₁)*g; v = β₂*v + (1-β₂)*g²
            # p = p - lr * (m_hat / (√v_hat + ε) + wd * p)
            # Implemented as foreach ops (the FX pass may fuse these).
            one_minus_beta1 = 1.0 - beta1
            one_minus_beta2 = 1.0 - beta2

            # m = beta1 * m + (1-beta1) * g
            torch._foreach_mul_(m_vals, beta1)
            torch._foreach_add_(m_vals, grads, alpha=one_minus_beta1)

            # v = beta2 * v + (1-beta2) * g * g
            torch._foreach_mul_(v_vals, beta2)
            g2 = [g * g for g in grads]
            torch._foreach_add_(v_vals, g2, alpha=one_minus_beta2)

            # p = p - lr * (m / (sqrt(v) + eps) + wd * p)
            for i in range(len(params)):
                denom = v_vals[i].sqrt() + eps
                update = m_vals[i] / denom + wd * params[i]
                params[i].sub_(lr * update)

            return params

        n_params = 4
        params = [torch.randn(16, 16, device="vulkan:0") for _ in range(n_params)]
        grads = [torch.randn(16, 16, device="vulkan:0") for _ in range(n_params)]
        m_vals = [torch.zeros(16, 16, device="vulkan:0") for _ in range(n_params)]
        v_vals = [torch.zeros(16, 16, device="vulkan:0") for _ in range(n_params)]

        params_cpu = [p.cpu().clone() for p in params]
        grads_cpu = [g.cpu().clone() for g in grads]
        m_cpu = [m.cpu().clone() for m in m_vals]
        v_cpu = [v.cpu().clone() for v in v_vals]

        lr = 0.001
        beta1 = 0.9
        beta2 = 0.999
        eps = 1e-8
        wd = 0.0

        with torch.no_grad():
            adamw_step(params, grads, m_vals, v_vals, lr, beta1, beta2, eps, wd)

            # CPU reference
            one_minus_beta1 = 1.0 - beta1
            one_minus_beta2 = 1.0 - beta2
            for i in range(n_params):
                m_cpu[i].mul_(beta1).add_(grads_cpu[i], alpha=one_minus_beta1)
                v_cpu[i].mul_(beta2).add_(
                    grads_cpu[i] * grads_cpu[i], alpha=one_minus_beta2
                )
                denom = v_cpu[i].sqrt() + eps
                update = m_cpu[i] / denom + wd * params_cpu[i]
                params_cpu[i].sub_(lr * update)

        for vk, cpu in zip(params, params_cpu):
            torch.testing.assert_close(vk.cpu(), cpu, rtol=1e-3, atol=1e-4)

    def test_foreach_adamw_dispatch_count(self):
        """AdamW foreach pattern stays under the dispatch ceiling."""
        import torch_vulkan

        @torch.compile(backend="inductor")
        def step(params, grads, m_vals, v_vals):
            # Minimal AdamW foreach pattern (4 foreach ops)
            torch._foreach_mul_(m_vals, 0.9)
            torch._foreach_add_(m_vals, grads, alpha=0.1)
            torch._foreach_mul_(v_vals, 0.999)
            g2 = [g * g for g in grads]
            torch._foreach_add_(v_vals, g2, alpha=0.001)
            return params

        n = 7  # triggers FX pass foreach fusion
        params = [torch.randn(8, 8, device="vulkan:0") for _ in range(n)]
        grads = [torch.randn(8, 8, device="vulkan:0") for _ in range(n)]
        m_vals = [torch.randn(8, 8, device="vulkan:0") for _ in range(n)]
        v_vals = [torch.randn(8, 8, device="vulkan:0") for _ in range(n)]

        with torch.no_grad():
            step(params, grads, m_vals, v_vals)  # warm-up
            torch_vulkan._c_ext._reset_perf_counters()
            step(params, grads, m_vals, v_vals)
            d = torch_vulkan._c_ext._get_dispatch_count()

        assert d <= 5, f"AdamW foreach: expected ≤5 dispatches, got {d}"

    # ── Scan (cumsum) ─────────────────────────────────────────────────

    def test_cumsum_dim_last_compiled(self):
        """Compiled `torch.cumsum(x, dim=-1)` produces correct output
        vs CPU reference."""

        @torch.compile(backend="inductor", fullgraph=True)
        def fn(x):
            return torch.cumsum(x, dim=-1)

        x = torch.randn(8, 64, device="vulkan:0")
        result = fn(x)
        expected = torch.cumsum(x.cpu(), dim=-1)
        torch.testing.assert_close(result.cpu(), expected, rtol=1e-4, atol=1e-4)

    def test_cumsum_dim_last_dispatch_count(self):
        """cumsum stays under the dispatch ceiling."""
        import torch_vulkan

        @torch.compile(backend="inductor", fullgraph=True)
        def fn(x):
            return torch.cumsum(x, dim=-1)

        x = torch.randn(8, 64, device="vulkan:0")
        fn(x)  # warm-up
        torch_vulkan._c_ext._reset_perf_counters()
        fn(x)
        d = torch_vulkan._c_ext._get_dispatch_count()
        assert d <= 5, f"cumsum dim=-1: expected ≤5 dispatches, got {d}"

    # ── Sort (topk) ───────────────────────────────────────────────────

    def test_topk_basic_compiled(self):
        """Compiled `torch.topk(x, k)` produces correct output vs CPU
        reference (values only, not indices)."""

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.topk(x, k=4, dim=-1)[0]

        x = torch.randn(8, 16, device="vulkan:0")
        result = fn(x)
        expected = torch.topk(x.cpu(), k=4, dim=-1)[0]
        torch.testing.assert_close(result.cpu(), expected, rtol=1e-3, atol=1e-3)

    def test_topk_dispatch_count(self):
        """topk stays under the dispatch ceiling."""
        import torch_vulkan

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.topk(x, k=4, dim=-1)[0]

        x = torch.randn(8, 16, device="vulkan:0")
        fn(x)  # warm-up
        torch_vulkan._c_ext._reset_perf_counters()
        fn(x)
        d = torch_vulkan._c_ext._get_dispatch_count()
        assert d <= 10, f"topk: expected ≤10 dispatches, got {d}"


class TestArgsort:
    """OP.8: ``aten.argsort`` compiles and matches CPU.

    Decomposes to ``aten.sort`` + index extraction, routed through
    ``kernel/reduction.py:sort()`` → ``wg_bitonic_sort_float2``.
    """

    def test_argsort_compiles(self):
        """Compiled argsort produces correct indices vs CPU."""

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.argsort(x, dim=-1, descending=False)

        x = torch.randn(8, 16, device="vulkan:0")
        result = fn(x)
        expected = torch.argsort(x.cpu(), dim=-1, descending=False)
        torch.testing.assert_close(result.cpu(), expected)

    def test_argsort_descending(self):
        """Compiled argsort descending=True."""

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.argsort(x, dim=-1, descending=True)

        x = torch.randn(8, 16, device="vulkan:0")
        result = fn(x)
        expected = torch.argsort(x.cpu(), dim=-1, descending=True)
        torch.testing.assert_close(result.cpu(), expected)

    def test_argsort_dispatch_count(self):
        """argsort stays under the dispatch ceiling."""
        import torch_vulkan

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.argsort(x, dim=-1)

        x = torch.randn(8, 16, device="vulkan:0")
        fn(x)  # warm-up
        torch_vulkan._c_ext._reset_perf_counters()
        fn(x)
        d = torch_vulkan._c_ext._get_dispatch_count()
        assert d <= 10, f"argsort: expected ≤10 dispatches, got {d}"


class TestM20BankConflictPadding:
    """M20 — Bank-conflict padding for groupshared arrays ≥256 elements.

    Every groupshared array in ``reduction.slang`` and ``mm_tiled.slang``
    that is ≥256 elements carries +32 padding so that strided access
    patterns (reduction-tree stride, column-major tile loads) land on
    different memory banks on RDNA1's 32-bank LDS. The padding elements
    are never accessed — they only shift the bank mapping for elements
    past offset 32. Indices are unchanged; results must be bit-exact.

    Tests exercise the key padded arrays:
      - ``_wg_reduce_smem`` / ``_wg_wave_smem`` (single-axis sum with
        large reduction dimension ≥256 elements)
      - Tile arrays ``_tile_a`` / ``_tile_b`` (matmul with ≥256-element
        tiles, e.g. TILE_M=64 × TILE_K=16 → 1024 elements)
    """

    def test_sum_single_axis_large_reduction(self):
        """Single-axis sum over a large reduction dim (1024 elements)
        exercises the padded ``_wg_reduce_smem`` / ``_wg_wave_smem``
        code paths. rtol=1e-4 vs CPU."""
        x = torch.randn(8, 1024, device="vulkan:0")

        @torch.compile(backend="inductor")
        def fn(x):
            return x.sum(dim=-1)

        with torch.no_grad():
            out = fn(x).cpu()

        expected = x.cpu().sum(dim=-1)
        torch.testing.assert_close(out, expected, rtol=1e-4, atol=1e-4)

    def test_sum_full_reduction_large(self):
        """Full reduction on a large tensor (32×512 = 16384 elements)
        exercises the padded reduction smem paths for the all-reduce
        dispatch. rtol=1e-4 vs CPU."""
        x = torch.randn(32, 512, device="vulkan:0")

        @torch.compile(backend="inductor")
        def fn(x):
            return x.sum()

        with torch.no_grad():
            out = fn(x).cpu()

        expected = x.cpu().sum()
        torch.testing.assert_close(out, expected, rtol=1e-4, atol=1e-4)

    def test_matmul_large_tile_correctness(self):
        try:
            torch.empty(1, device="vulkan:0")
        except Exception:
            pytest.skip("Vulkan GPU not available")
        """Matmul with dimensions that produce a tile ≥256 elements
        exercises the padded ``_tile_a`` / ``_tile_b`` arrays.
        TILE_M=64, TILE_K=16 → TILE_A_ELEMS=1024."""
        m, k, n = 128, 64, 128
        a = torch.randn(m, k, device="vulkan:0")
        b = torch.randn(k, n, device="vulkan:0")

        @torch.compile(backend="inductor")
        def fn(a, b):
            return torch.mm(a, b)

        with torch.no_grad():
            out = fn(a, b).cpu()

        expected = torch.mm(a.cpu(), b.cpu())
        torch.testing.assert_close(out, expected, rtol=1e-4, atol=1e-4)


class TestDR6MemoryLayoutAudit:
    """DR.6 — Memory layout audit + LDS bank-padding.

    Two coverage targets:
      1. Reduction kernels emit groupshared arrays with +32 padding
         so that strided accesses avoid RDNA1 bank conflicts.
      2. When TORCH_VULKAN_VEC4_AUDIT=1, the vectorization audit
         reports a non-zero hit rate after vec4/packed16 rewriting.
    """

    def test_dr6_reduction_smem_has_bank_padding(self):
        """Reduction with bank-padding enabled (default) and disabled
        both produce correct results.  The +32 padding shifts bank
        mappings without changing access indices, so numeric output
        must be unchanged."""
        import torch_vulkan

        x = torch.randn(8, 1024, device="vulkan:0")
        expected = x.cpu().sum(dim=-1)

        # Padding ON (default)
        os.environ["TORCH_VULKAN_BANK_CONFLICT_PAD"] = "1"
        try:
            torch._dynamo.reset()

            @torch.compile(backend="inductor")
            def fn_on(x):
                return x.sum(dim=-1)

            result_on = fn_on(x).cpu()
            torch.testing.assert_close(result_on, expected, rtol=1e-4, atol=1e-4)
        finally:
            os.environ.pop("TORCH_VULKAN_BANK_CONFLICT_PAD", None)

        # Padding OFF
        os.environ["TORCH_VULKAN_BANK_CONFLICT_PAD"] = "0"
        try:
            torch._dynamo.reset()

            @torch.compile(backend="inductor")
            def fn_off(x):
                return x.sum(dim=-1)

            result_off = fn_off(x).cpu()
            torch.testing.assert_close(result_off, expected, rtol=1e-4, atol=1e-4)
        finally:
            os.environ.pop("TORCH_VULKAN_BANK_CONFLICT_PAD", None)

    def test_dr6_vec4_audit_reports_hit_rate(self):
        """With TORCH_VULKAN_VEC4_AUDIT=1, the audit reports hit rate > 0
        for a simple pointwise kernel that triggers vec4 rewriting."""
        os.environ["TORCH_VULKAN_VEC4_AUDIT"] = "1"
        os.environ["TORCH_VULKAN_INDUCTOR_STATS"] = "1"
        os.environ.pop("TORCH_VULKAN_NO_VEC4_POINTWISE", None)
        try:
            # Clear any prior stats so we get a clean reading.
            from torch_vulkan.inductor.inductor_stats import (
                _get_stats_dict,
                reset_stats,
            )

            reset_stats()

            # Use a kernel where numel % (max_threadgroup_size * 4) == 0
            # so the vec4 path activates.  max_threadgroup_size ≤ 256,
            # so we need numel % 1024 == 0.  A 1024-element relu is ideal.
            @torch.compile(backend="inductor")
            def fn(x):
                return torch.relu(x * 0.5 + 0.1)

            x = torch.randn(1024, device="vulkan:0")
            result = fn(x)
            expected = torch.relu(x.cpu() * 0.5 + 0.1)
            torch.testing.assert_close(result.cpu(), expected, rtol=1e-4, atol=1e-4)

            # The audit runs during compilation; check stats storage.
            stats = _get_stats_dict()
            audit_entry = stats.get("vec4_audit")
            assert audit_entry is not None, "Expected vec4_audit entry in stats"
            assert audit_entry["call_count"] >= 1, f"Got {audit_entry}"
        finally:
            os.environ.pop("TORCH_VULKAN_VEC4_AUDIT", None)
            os.environ.pop("TORCH_VULKAN_INDUCTOR_STATS", None)


class TestModelTrainingE2E:
    """End-to-end model training tests.

    These verify that real models compile, produce non-zero gradients,
    and can train for multiple steps on GPU hardware.  They are gated on
    ``--gpu`` because software Vulkan (Lavapipe) currently has known
    issues (GPU.1 — bool compare+select kernel produces zero gradients).

    Stage tags: ``BUG_ROOT="GPU.1"`` (software-Vulkan zero-grad),
    ``BUG_ROOT="codegen"`` (hardware-only correctness).
    """

    _BUG_ROOT_COMPONENT = "codegen"

    @pytest.mark.gpu
    def test_conv_relu_fc_3step(self, gpu_device):
        """conv→relu→fc model trains 3 steps, gradients non-zero."""
        import torch.nn as nn
        import torch.nn.functional as F

        class ConvReluFC(nn.Module):
            def __init__(self):
                super().__init__()
                self.conv = nn.Conv2d(3, 8, 3, padding=1)
                self.fc = nn.Linear(8 * 8 * 8, 10)

            def forward(self, x):
                x = F.relu(self.conv(x))
                x = x.view(x.size(0), -1)
                return self.fc(x)

        torch.manual_seed(42)
        dev = gpu_device
        model = ConvReluFC().to(dev)
        model.train()
        compiled = torch.compile(model, backend="inductor")
        opt = torch.optim.SGD(model.parameters(), lr=0.01)

        x = torch.randn(4, 3, 8, 8, device=dev)
        losses = []

        for step in range(3):
            opt.zero_grad()
            out = compiled(x)
            loss = out.sum()
            loss.backward()

            # Verify non-zero gradients on all parameters
            for name, p in model.named_parameters():
                assert p.grad is not None, f"step {step}: {name} grad is None"
                assert p.grad.abs().sum() > 0, f"step {step}: {name} grad is zero"

            losses.append(loss.item())
            opt.step()

        # Loss must change across steps (training is happening)
        assert losses[0] != losses[2], f"loss did not change over 3 steps: {losses}"

    @pytest.mark.gpu
    def test_conv_bn_relu_fc_3step(self, gpu_device):
        """conv→bn→relu→fc model trains 3 steps, gradients non-zero."""
        import torch.nn as nn
        import torch.nn.functional as F

        class ConvBNReluFC(nn.Module):
            def __init__(self):
                super().__init__()
                self.conv = nn.Conv2d(3, 8, 3, padding=1)
                self.bn = nn.BatchNorm2d(8)
                self.fc = nn.Linear(8 * 8 * 8, 10)

            def forward(self, x):
                x = self.conv(x)
                x = self.bn(x)
                x = F.relu(x)
                x = x.view(x.size(0), -1)
                return self.fc(x)

        torch.manual_seed(42)
        dev = gpu_device
        model = ConvBNReluFC().to(dev)
        model.train()
        compiled = torch.compile(model, backend="inductor")
        opt = torch.optim.SGD(model.parameters(), lr=0.01)

        x = torch.randn(4, 3, 8, 8, device=dev)
        losses = []

        for step in range(3):
            opt.zero_grad()
            out = compiled(x)
            loss = out.sum()
            loss.backward()

            for name, p in model.named_parameters():
                assert p.grad is not None, f"step {step}: {name} grad is None"
                assert p.grad.abs().sum() > 0, f"step {step}: {name} grad is zero"

            losses.append(loss.item())
            opt.step()

        assert losses[0] != losses[2], f"loss did not change over 3 steps: {losses}"

    @pytest.mark.gpu
    def test_small_resnet_block_1step(self, gpu_device):
        """ResNet block (conv→bn→relu→conv→bn→add→relu) trains 1 step."""
        import torch.nn as nn
        import torch.nn.functional as F

        class ResNetBlock(nn.Module):
            def __init__(self, channels=8):
                super().__init__()
                self.conv1 = nn.Conv2d(channels, channels, 3, padding=1)
                self.bn1 = nn.BatchNorm2d(channels)
                self.conv2 = nn.Conv2d(channels, channels, 3, padding=1)
                self.bn2 = nn.BatchNorm2d(channels)
                # 1x1 conv for residual projection in case of dimension
                # mismatch — not needed here since channels==channels, but
                # included for completeness.
                self.proj = nn.Identity()

            def forward(self, x):
                identity = self.proj(x)
                out = self.conv1(x)
                out = self.bn1(out)
                out = F.relu(out)
                out = self.conv2(out)
                out = self.bn2(out)
                out = out + identity
                return F.relu(out)

        torch.manual_seed(42)
        dev = gpu_device
        model = ResNetBlock(channels=8).to(dev)
        model.train()
        compiled = torch.compile(model, backend="inductor")
        opt = torch.optim.SGD(model.parameters(), lr=0.01)

        x = torch.randn(4, 8, 8, 8, device=dev)
        opt.zero_grad()
        out = compiled(x)
        loss = out.sum()
        loss.backward()

        for name, p in model.named_parameters():
            assert p.grad is not None, f"{name} grad is None"
            assert p.grad.abs().sum() > 0, f"{name} grad is zero"

        opt.step()

    @pytest.mark.sw_vulkan
    def test_conv_relu_sum_backward_sw(self, sw_vulkan):
        """On software Vulkan, verify codegen succeeds for
        ``conv→relu.sum().backward()`` (gradients may be zero —
        GPU.1 bool compare+select kernel bug)."""
        import torch.nn.functional as F

        dev = sw_vulkan

        @torch.compile(backend="inductor")
        def fn(x, w):
            return F.relu(F.conv2d(x, w)).sum()

        x = torch.randn(1, 3, 8, 8, device=dev, requires_grad=True)
        w = torch.randn(8, 3, 3, 3, device=dev, requires_grad=True)

        # This must compile and dispatch without crashing.
        loss = fn(x, w)
        loss.backward()

        # On software Vulkan, gradients may be zero (GPU.1), but
        # grad tensors must exist (no None).
        assert x.grad is not None, "codegen failure: x.grad is None"
        assert w.grad is not None, "codegen failure: w.grad is None"


class TestBNBackwardDispatchCurrent:
    """BN backward dispatch-count baseline with combo kernel re-enabled.

    GPU.1 fix (bool compare+select kernel on RDNA1) and subsequent
    GPU.2/GPU.3 fixes allow tighter fusion; until then the rolling
    ceiling is ≤18 dispatches.  Target is ≤10 once all three GPU
    issues are resolved.

    Stage tag: ``BUG_ROOT="lowering"``.
    """

    _BUG_ROOT_COMPONENT = "lowering"

    def test_batchnorm_backward_dispatch_count_current(self):
        """BN backward currently produces ≤18 dispatches with combo
        kernel.  Target ≤10 once GPU.1-3 are resolved."""
        import torch_vulkan

        try:
            torch.empty(1, device="vulkan:0")
        except Exception:
            pytest.skip("Vulkan GPU not available")

        N, C, H, W = 8, 16, 4, 4
        x_cpu = torch.randn(N, C, H, W)
        w_cpu = torch.randn(C)
        b_cpu = torch.randn(C)
        rm_cpu = torch.zeros(C)
        rv_cpu = torch.ones(C)
        g_cpu = torch.randn(N, C, H, W)

        # Compute save_mean / save_invstd on CPU
        _, sm_cpu, siv_cpu = torch.ops.aten.native_batch_norm.default(
            x_cpu, w_cpu, b_cpu, rm_cpu, rv_cpu, True, 0.1, 1e-5
        )

        x = x_cpu.to("vulkan:0")
        w = w_cpu.to("vulkan:0")
        b = b_cpu.to("vulkan:0")
        rm = rm_cpu.to("vulkan:0")
        rv = rv_cpu.to("vulkan:0")
        sm = sm_cpu.to("vulkan:0")
        siv = siv_cpu.to("vulkan:0")
        g = g_cpu.to("vulkan:0")

        @torch.compile(backend="inductor", dynamic=False)
        def fn(go, inp, wt, rmean, rvar, smean, siv):
            return torch.ops.aten.native_batch_norm_backward.default(
                go,
                inp,
                wt,
                rmean,
                rvar,
                smean,
                siv,
                True,
                1e-5,
                [True, True, True],
            )

        # warmup
        fn(g, x, w, rm, rv, sm, siv)
        torch_vulkan._c_ext._reset_perf_counters()
        fn(g, x, w, rm, rv, sm, siv)
        d = torch_vulkan._c_ext._get_dispatch_count()

        assert d <= 18, (
            f"BN backward dispatch count regressed: {d} > 18 ceiling. "
            f"Target is ≤10 once GPU.1-3 are resolved."
        )


