class TestN1bFastSearchsorted:
    """N.1.b-fast: GPU-native searchsorted via parallel binary search.

    Replaces the CPU roundtrip in lowerings/searchsorted.py with a
    Slang compute shader from bucket.slang.  Each thread handles one
    output element via binary search — log2(seq_len) iterations,
    no shared memory.
    """

    def test_n1b_fast_searchsorted_matches_cpu(self):
        """GPU-native searchsorted matches CPU reference."""

        @torch.compile(backend="inductor")
        def fn(s, v):
            return torch.searchsorted(s, v)

        s = torch.tensor([1.0, 3.0, 5.0, 7.0, 9.0], device="vulkan:0")
        v = torch.tensor([2.0, 4.0, 6.0, 8.0], device="vulkan:0")
        y = fn(s, v)
        expected = torch.tensor([1, 2, 3, 4], dtype=y.dtype)
        torch.testing.assert_close(y.cpu(), expected)

    def test_n1b_fast_searchsorted_right_matches_cpu(self):
        """GPU-native searchsorted right=True matches CPU reference."""

        @torch.compile(backend="inductor")
        def fn(s, v):
            return torch.searchsorted(s, v, right=True)

        s = torch.tensor([1.0, 3.0, 5.0, 7.0, 9.0], device="vulkan:0")
        v = torch.tensor([2.0, 4.0, 6.0, 8.0], device="vulkan:0")
        y = fn(s, v)
        expected = torch.tensor([1, 2, 3, 4], dtype=y.dtype)
        torch.testing.assert_close(y.cpu(), expected)

    def test_n1b_fast_searchsorted_large(self):
        """GPU-native searchsorted on larger tensors."""

        @torch.compile(backend="inductor")
        def fn(s, v):
            return torch.searchsorted(s, v)

        torch.manual_seed(42)
        s = torch.linspace(0.0, 100.0, 1000, device="vulkan:0")
        v = torch.rand(2000, device="vulkan:0") * 100.0
        y = fn(s, v)
        # Check all values are in valid range
        assert (y.cpu() >= 0).all() and (y.cpu() <= 1000).all()
        # Check monotonic: if v[i] <= v[j], then y[i] <= y[j]
        # ... spot check a few known values
        assert y[0].item() >= 0

    def test_n1b_fast_searchsorted_int32_output(self):
        """GPU-native searchsorted with out_int32=True."""

        @torch.compile(backend="inductor")
        def fn(s, v):
            return torch.searchsorted(s, v, out_int32=True)

        s = torch.tensor([1.0, 3.0, 5.0, 7.0, 9.0], device="vulkan:0")
        v = torch.tensor([2.0, 4.0, 6.0, 8.0], device="vulkan:0")
        y = fn(s, v)
        assert y.dtype == torch.int32
        expected = torch.tensor([1, 2, 3, 4], dtype=torch.int32)
        torch.testing.assert_close(y.cpu(), expected)


