# ── DR.3: Reflection-driven cache key + workgroup heuristic tests ──


class _DR3MockKernel:
    """Minimal mock of VulkanKernel for DR.3 unit tests.

    Populates only the attributes needed by _compute_config_key
    (→ config_key property), _estimate_vgprs, _pick_threadgroup_size,
    _max_unroll_factor, and the shared helpers introduced in DR.3.
    """

    def __init__(
        self,
        *,
        n_in: int = 1,
        n_out: int = 1,
        inside_reduction: bool = False,
        has_welford: bool = False,
        packed16: bool = False,
        reduction_type: str | None = None,
        partitioned_2d_active: bool = False,
        simd_group_size: int = 64,
        max_workgroup_size: int = 256,
        numels: dict | None = None,
        range_trees: list | None = None,
        cooperative_reduction: bool = True,
        groupshared_bytes_used: int = 0,
        groupshared_budget_bytes: int = 64 * 1024,
        force_vgprs: int | None = None,
    ):
        self.simd_group_size = simd_group_size
        self._packed16 = packed16
        self._reduction_type = reduction_type
        self._partitioned_2d_active = partitioned_2d_active
        self.inside_reduction = inside_reduction
        self.has_welford = has_welford
        self._groupshared_bytes_used = groupshared_bytes_used
        self._groupshared_budget_bytes = groupshared_budget_bytes
        self.max_threadgroup_size = max_workgroup_size
        self._force_vgprs = force_vgprs

        class _MockArgs:
            pass

        _ma = _MockArgs()
        _ma.input_buffers = list(range(n_in))
        _ma.output_buffers = list(range(n_out))
        self.args = _ma

        self._range_trees = range_trees or []
        self._cooperative_reduction = cooperative_reduction
        self._numels = numels or {"x": 256}

    @property
    def range_trees(self):
        return self._range_trees

    @property
    def numels(self):
        return self._numels

    def should_use_cooperative_reduction(self) -> bool:
        return self._cooperative_reduction

    def _get_actual_vgprs(self):
        """Mock: always returns None (fall back to heuristic)."""
        return None

    def _estimate_vgprs(self) -> int:
        """Mock: simple heuristic matching VulkanKernel._estimate_vgprs."""
        if self._force_vgprs is not None:
            return self._force_vgprs
        base = 4
        n_io = len(self.args.input_buffers) + len(self.args.output_buffers)
        acc_cost = 0
        if self.inside_reduction:
            acc_cost = 7 if self.has_welford else 2
            acc_cost += 4  # loop overhead
        return base + n_io + acc_cost

    def _get_cached_shared_mem(self):
        """Mock: always returns None."""
        return None

    def _get_cached_loop_depth(self):
        """Mock: always returns None."""
        return None

    def _estimate_loop_depth(self) -> int:
        """Mock: delegates to VulkanKernel._estimate_loop_depth."""
        from torch_vulkan.inductor.kernel.main import VulkanKernel

        return VulkanKernel._estimate_loop_depth(self)

    def _classify_vgpr_pressure(self, dtype_bytes: int):
        """Mock: delegates to VulkanKernel._classify_vgpr_pressure."""
        from torch_vulkan.inductor.kernel.main import VulkanKernel

        return VulkanKernel._classify_vgpr_pressure(self, dtype_bytes)

    def _compute_config_key(self) -> str:
        """Mock: delegates to VulkanKernel.config_key property."""
        from torch_vulkan.inductor.kernel.main import VulkanKernel

        return VulkanKernel.config_key.fget(self)


class _DR3RangeTree:
    """Minimal range tree entry for DR.3 tests."""

    def __init__(self, is_reduction: bool = False):
        self.is_reduction = is_reduction


class TestDR3ReflectionCacheKey:
    """DR.3: Reflection-driven cache key + workgroup heuristic.

    Verifies:
    - cache keys differ for kernels with different loop depths
    - pointwise and reduction get different WG sizes for same numel
    - heavy kernels (welford, deep loops) get fewer threads
    """

    def test_dr3_cache_key_includes_loop_depth(self):
        """Cache keys differ for kernels with different structural
        loop-depth proxies."""
        from torch_vulkan.inductor.kernel.main import VulkanKernel

        k_a = _DR3MockKernel(
            inside_reduction=True,
            range_trees=[_DR3RangeTree(is_reduction=True)],
            cooperative_reduction=False,
        )
        key_a = VulkanKernel.config_key.fget(k_a)

        k_b = _DR3MockKernel(
            inside_reduction=True,
            range_trees=[
                _DR3RangeTree(is_reduction=True),
                _DR3RangeTree(is_reduction=True),
            ],
            cooperative_reduction=False,
        )
        key_b = VulkanKernel.config_key.fget(k_b)

        assert key_a != key_b, (
            f"DR.3 fail: config keys should differ for kernels with "
            f"different loop-depth proxies, but both got {key_a}"
        )

    def test_dr3_cache_key_includes_subgroup_size(self):
        """Cache keys differ for wave32 vs wave64 subgroup sizes."""
        from torch_vulkan.inductor.kernel.main import VulkanKernel

        k_wave32 = _DR3MockKernel(simd_group_size=32)
        k_wave64 = _DR3MockKernel(simd_group_size=64)

        key_32 = VulkanKernel.config_key.fget(k_wave32)
        key_64 = VulkanKernel.config_key.fget(k_wave64)

        assert key_32 != key_64, (
            f"DR.3 fail: config keys should differ for different "
            f"subgroup sizes (32 vs 64), but both got {key_32}"
        )

    def test_dr3_pointwise_vs_reduction_threadgroup_differs(self):
        """Pointwise and reduction kernels get different WG sizes
        for equivalent total numel when VGPR pressure differs."""
        # Pointwise: light VGPR (6), large numel → gets 256.
        k_pw = _DR3MockKernel(
            inside_reduction=False,
            numels={"x": 500000},
            range_trees=[_DR3RangeTree(is_reduction=False)],
        )
        # Reduction: heavy VGPR (forced 40), smaller rnumel → gets <= 128.
        k_red = _DR3MockKernel(
            inside_reduction=True,
            has_welford=True,
            force_vgprs=40,
            numels={"r0": 4096},
            range_trees=[
                _DR3RangeTree(is_reduction=True),
                _DR3RangeTree(is_reduction=True),
            ],
            cooperative_reduction=False,
        )

        wg_pw = self._simulate_wg_pick(k_pw)
        wg_red = self._simulate_wg_pick(k_red)

        # Pointwise should have larger (or equal) WG.
        assert wg_pw > wg_red, (
            f"DR.3 fail: pointwise WG ({wg_pw}) should be > "
            f"reduction WG ({wg_red}) for heavy reduction"
        )

    def test_dr3_heavy_kernel_gets_fewer_threads(self):
        """Welford/multi-axis reduction with heavy VGPR pressure gets
        fewer threads than a simple pointwise kernel."""

        k_light = _DR3MockKernel(
            inside_reduction=False,
            numels={"x": 131072},
            range_trees=[_DR3RangeTree(is_reduction=False)],
        )

        # Heavy: welford + 3-axis reduction + forced high VGPR.
        k_heavy = _DR3MockKernel(
            inside_reduction=True,
            has_welford=True,
            force_vgprs=48,
            numels={"r0": 64, "r1": 64, "r2": 16},
            range_trees=[
                _DR3RangeTree(is_reduction=True),
                _DR3RangeTree(is_reduction=True),
                _DR3RangeTree(is_reduction=True),
            ],
            cooperative_reduction=False,
        )

        wg_light = self._simulate_wg_pick(k_light)
        wg_heavy = self._simulate_wg_pick(k_heavy)

        assert wg_heavy < wg_light, (
            f"DR.3 fail: heavy kernel WG ({wg_heavy}) should be "
            f"strictly less than light kernel WG ({wg_light})"
        )

    def test_dr3_max_unroll_factor_heavy_kernel_capped(self):
        """_max_unroll_factor returns <= 4 for heavy (welford, deep loop)
        kernels."""
        from torch_vulkan.inductor.kernel.main import VulkanKernel

        k = _DR3MockKernel(
            inside_reduction=True,
            has_welford=True,
            range_trees=[
                _DR3RangeTree(is_reduction=True),
                _DR3RangeTree(is_reduction=True),
            ],
            cooperative_reduction=False,
        )
        max_unroll = VulkanKernel._max_unroll_factor(k)
        assert max_unroll <= 4, (
            f"DR.3 fail: heavy kernel unroll cap should be <= 4, got {max_unroll}"
        )

    def test_dr3_max_unroll_factor_light_kernel_high(self):
        """_max_unroll_factor returns 16 for light pointwise kernels."""
        from torch_vulkan.inductor.kernel.main import VulkanKernel

        k = _DR3MockKernel(
            inside_reduction=False,
            range_trees=[_DR3RangeTree(is_reduction=False)],
        )
        max_unroll = VulkanKernel._max_unroll_factor(k)
        assert max_unroll == 16, (
            f"DR.3 fail: light kernel unroll cap should be 16, got {max_unroll}"
        )

    @staticmethod
    def _simulate_wg_pick(k: _DR3MockKernel) -> int:
        """Simulate the WG pick by running shared helpers manually."""
        from torch_vulkan.inductor.kernel.main import VulkanKernel

        max_wg = k.max_threadgroup_size
        sgs = k.simd_group_size
        dtype_bytes = 2 if k._packed16 else 4

        vgpr_class, estimated_vgprs = VulkanKernel._classify_vgpr_pressure(
            k, dtype_bytes
        )
        max_wg = VulkanKernel._apply_vgpr_cap(k, max_wg, estimated_vgprs, sgs)
        max_wg = VulkanKernel._apply_shared_mem_cap(k, max_wg, dtype_bytes, sgs)
        loop_depth = VulkanKernel._estimate_loop_depth(k)
        max_wg = VulkanKernel._apply_loop_depth_penalty(
            k, max_wg, vgpr_class, loop_depth
        )

        total = 1
        for v in k.numels.values():
            total *= int(v) if not isinstance(v, int) else v

        if k.inside_reduction:
            rnumel = total
            effective_rn = rnumel if dtype_bytes >= 4 else max(rnumel // 2, 1)
            rn_caps = {
                "light": (sgs * 4, sgs * 2, sgs),
                "normal": (sgs * 2, sgs, sgs),
                "heavy": (sgs, sgs // 2, max(sgs // 2, 32)),
            }
            cap_large, cap_medium, cap_small = rn_caps.get(
                vgpr_class, (sgs * 2, sgs, sgs)
            )
            if effective_rn > cap_large:
                return min(max_wg, 256)
            if effective_rn > cap_medium:
                return min(max_wg, cap_medium)
            return min(max_wg, cap_small)
        else:
            caps = {"light": 512, "normal": 384, "heavy": 256}
            cap = caps.get(vgpr_class, 256)
            scale = 4 // dtype_bytes
            if total > scale * 256 * 1024:
                return min(max_wg, cap)
            if total > scale * 64 * 1024:
                return min(max_wg, min(384, cap))
            if 0 < total < 256:
                if total <= sgs:
                    return min(max_wg, sgs)
                n = 1
                while n < total:
                    n <<= 1
                return min(max_wg, n)
            pt_caps = {"light": 256, "normal": 256, "heavy": 128}
            return min(max_wg, pt_caps.get(vgpr_class, 256))


class TestN112ReflectionThreading:
    """N+1.12: Thread loop_depth and subgroup_size through autotune.

    Verifies:
    - loop_depth >= 3 drops one unroll tier, loop_depth >= 5 drops two
    - subgroup_size in cache keys distinguishes wave32 vs wave64
    - tile config picker filters by subgroup_size
    - different VGPR classes produce distinct autotune config keys
    """

    def test_n112_loop_depth_affects_unroll(self):
        """Deep loops (>=3 or >=5) reduce the unroll factor cap."""
        from torch_vulkan.inductor.kernel.main import VulkanKernel

        # Shallow loop (loop_depth=1) → light pointwise → unroll=16
        k_shallow = _DR3MockKernel(
            inside_reduction=False,
            range_trees=[_DR3RangeTree(is_reduction=False)],
        )
        unroll_shallow = VulkanKernel._max_unroll_factor(k_shallow)
        assert unroll_shallow == 16, (
            f"N+1.12 fail: shallow kernel unroll should be 16, got {unroll_shallow}"
        )

        # Medium loop (loop_depth=3: two reduction axes + persistent)
        # Should drop one tier from the VGPR-class base.
        k_med = _DR3MockKernel(
            inside_reduction=True,
            has_welford=False,
            range_trees=[
                _DR3RangeTree(is_reduction=True),
                _DR3RangeTree(is_reduction=True),
            ],
            cooperative_reduction=False,
        )
        unroll_med = VulkanKernel._max_unroll_factor(k_med)
        # VGPR class for this config should be "normal" (8), loop_depth=3
        # drops one tier → 4
        assert unroll_med <= 8, (
            f"N+1.12 fail: medium-depth kernel unroll should be <= 8, got {unroll_med}"
        )

        # Deep loop (loop_depth=5: three reduction axes + persistent + 2d)
        # Should drop two tiers.
        k_deep = _DR3MockKernel(
            inside_reduction=True,
            has_welford=True,
            partitioned_2d_active=True,
            range_trees=[
                _DR3RangeTree(is_reduction=True),
                _DR3RangeTree(is_reduction=True),
                _DR3RangeTree(is_reduction=True),
            ],
            cooperative_reduction=False,
        )
        unroll_deep = VulkanKernel._max_unroll_factor(k_deep)
        # VGPR class should be "heavy" (4), loop_depth=5 drops two tiers
        # but floor is 4, so should be 4.
        assert unroll_deep == 4, (
            f"N+1.12 fail: deep-loop kernel unroll should be 4, got {unroll_deep}"
        )

        # Verify strict ordering: shallow > medium >= deep
        assert unroll_shallow > unroll_med, (
            f"N+1.12 fail: shallow unroll ({unroll_shallow}) should be > "
            f"medium unroll ({unroll_med})"
        )
        assert unroll_med >= unroll_deep, (
            f"N+1.12 fail: medium unroll ({unroll_med}) should be >= "
            f"deep unroll ({unroll_deep})"
        )

    def test_n112_subgroup_size_in_cache_key(self):
        """Wave32 vs wave64 produce different autotune cache keys."""
        from torch_vulkan.inductor.kernel.main import VulkanKernel

        k_wave32 = _DR3MockKernel(simd_group_size=32)
        k_wave64 = _DR3MockKernel(simd_group_size=64)

        key_32 = VulkanKernel.config_key.fget(k_wave32)
        key_64 = VulkanKernel.config_key.fget(k_wave64)

        assert key_32 != key_64, (
            f"N+1.12 fail: config keys should differ for wave32 vs wave64, "
            f"but both got {key_32}"
        )

    def test_n112_tile_picker_respects_subgroup_size(self):
        """Tile configs vary by subgroup size: wave32 filters large tiles."""
        from unittest import mock

        from torch_vulkan.inductor.vulkan_template_caller import (
            _get_device_subgroup_size,
            _pick_register_tile_configs,
            _pick_tile_configs,
        )

        # Patch _get_device_subgroup_size to simulate wave32
        with mock.patch(
            "torch_vulkan.inductor.vulkan_template_caller._get_device_subgroup_size",
            return_value=32,
        ):
            tiles_wave32 = _pick_tile_configs()
            reg_tiles_wave32 = _pick_register_tile_configs()

        # Patch _get_device_subgroup_size to simulate wave64
        with mock.patch(
            "torch_vulkan.inductor.vulkan_template_caller._get_device_subgroup_size",
            return_value=64,
        ):
            tiles_wave64 = _pick_tile_configs()
            reg_tiles_wave64 = _pick_register_tile_configs()

        # wave32 should have fewer or equal legacy tiles (filters large tiles)
        assert len(tiles_wave32) <= len(tiles_wave64), (
            f"N+1.12 fail: wave32 tiles ({len(tiles_wave32)}) should be <= "
            f"wave64 tiles ({len(tiles_wave64)})"
        )

        # wave32 should have fewer register tiles (filters register-heavy)
        assert len(reg_tiles_wave32) <= len(reg_tiles_wave64), (
            f"N+1.12 fail: wave32 register tiles ({len(reg_tiles_wave32)}) "
            f"should be <= wave64 register tiles ({len(reg_tiles_wave64)})"
        )

        # wave32 legacy tiles should all have max dim <= 32
        for tm, tn, tk in tiles_wave32:
            assert max(tm, tn) <= 32, (
                f"N+1.12 fail: wave32 legacy tile ({tm},{tn},{tk}) has dim > 32"
            )

        # wave32 register tiles should all have m_per_thread * n_per_thread <= 16
        for tm, tn, tk, mpt, npt in reg_tiles_wave32:
            assert mpt * npt <= 16, (
                f"N+1.12 fail: wave32 register tile ({tm},{tn},{tk},r{mpt}x{npt}) "
                f"has {mpt * npt} regs/thread > 16"
            )

        # wave64 should include at least one register tile with > 16 regs/thread
        if reg_tiles_wave64:
            has_large = any(c[3] * c[4] > 16 for c in reg_tiles_wave64)
            assert has_large, (
                f"N+1.12 fail: wave64 has no register tiles with > 16 regs/thread"
            )

    def test_n112_reflection_metrics_in_autotune_key(self):
        """Different VGPR classes produce distinct config keys."""
        from torch_vulkan.inductor.kernel.main import VulkanKernel

        # Light VGPR kernel
        k_light = _DR3MockKernel(
            inside_reduction=False,
            range_trees=[_DR3RangeTree(is_reduction=False)],
            force_vgprs=8,
        )
        # Heavy VGPR kernel
        k_heavy = _DR3MockKernel(
            inside_reduction=True,
            has_welford=True,
            force_vgprs=48,
            range_trees=[
                _DR3RangeTree(is_reduction=True),
                _DR3RangeTree(is_reduction=True),
            ],
            cooperative_reduction=False,
        )

        key_light = VulkanKernel.config_key.fget(k_light)
        key_heavy = VulkanKernel.config_key.fget(k_heavy)

        assert key_light != key_heavy, (
            f"N+1.12 fail: config keys should differ for light vs heavy VGPR, "
            f"but both got {key_light}"
        )

        # Also verify the keys differ by subgroup_size (wave32 vs wave64)
        k_wave32 = _DR3MockKernel(
            inside_reduction=True,
            has_welford=True,
            force_vgprs=48,
            simd_group_size=32,
            range_trees=[
                _DR3RangeTree(is_reduction=True),
                _DR3RangeTree(is_reduction=True),
            ],
            cooperative_reduction=False,
        )
        key_wave32 = VulkanKernel.config_key.fget(k_wave32)
        assert key_heavy != key_wave32, (
            f"N+1.12 fail: cache keys should differ for wave32 vs wave64, "
            f"but both got {key_heavy}"
        )

        # Verify that two kernels with the same config produce same key
        k_a = _DR3MockKernel(
            inside_reduction=True,
            has_welford=True,
            force_vgprs=48,
            simd_group_size=64,
            range_trees=[
                _DR3RangeTree(is_reduction=True),
                _DR3RangeTree(is_reduction=True),
            ],
            cooperative_reduction=False,
        )
        k_b = _DR3MockKernel(
            inside_reduction=True,
            has_welford=True,
            force_vgprs=48,
            simd_group_size=64,
            range_trees=[
                _DR3RangeTree(is_reduction=True),
                _DR3RangeTree(is_reduction=True),
            ],
            cooperative_reduction=False,
        )
        key_a = VulkanKernel.config_key.fget(k_a)
        key_b = VulkanKernel.config_key.fget(k_b)
        assert key_a == key_b, (
            f"N+1.12 fail: identical configs should produce same key, "
            f"got {key_a} vs {key_b}"
        )


class TestDR4SpecConstantsDefault:
    """DR.4: Enable ``[[vk::specialization_constant]]`` by default.

    Verifies:
    - ``spec_constants()`` returns True by default (no env var set)
    - Spec-constant kernels produce smaller SPIR-V than push-constant
      equivalents (slangc constant-folds bound checks)
    """

    def test_dr4_spec_constants_default_on(self):
        """spec_constants() returns True by default (DR.4 flip).

        Tests the env-var default logic directly without reloading
        the config module (which would poison state for other tests).
        """
        old_val = os.environ.pop("TORCH_VULKAN_SPEC_CONSTANTS", None)
        try:
            # Simulate the module-level logic: default is "1", so != "0" → True.
            val = os.environ.get("TORCH_VULKAN_SPEC_CONSTANTS", "1")
            assert val != "0", f"DR.4 fail: default should be '1' (truthy), got {val!r}"
            assert val == "1", f"DR.4 fail: default should be '1', got {val!r}"
        finally:
            if old_val is not None:
                os.environ["TORCH_VULKAN_SPEC_CONSTANTS"] = old_val

    def test_dr4_spec_constants_can_be_disabled(self):
        """TORCH_VULKAN_SPEC_CONSTANTS=0 disables the path (backward compat)."""
        os.environ["TORCH_VULKAN_SPEC_CONSTANTS"] = "0"
        try:
            val = os.environ.get("TORCH_VULKAN_SPEC_CONSTANTS", "1")
            assert val == "0", (
                f"DR.4 fail: with env=0, value should be '0', got {val!r}"
            )
        finally:
            os.environ.pop("TORCH_VULKAN_SPEC_CONSTANTS", None)

    def test_dr4_spec_constants_produces_smaller_spv(self):
        """Spec-constant shader compiles and SPIR-V contains OpSpecConstant
        decorations, proving the specialization-constant path is active."""
        from torch_vulkan.inductor.runtime import (
            compile_slang_to_spirv,
            parse_spec_constants,
        )

        # Shader that references a known-at-compile-time numel.
        # spec_constant form: [[vk::constant_id(0)]] const uint xnumel;
        # static const form: static const uint xnumel = 65536;
        src_spec = """
        [[vk::constant_id(0)]] const uint xnumel = 65536;
        [[vk::binding(0, 0)]] StructuredBuffer<float> in_x;
        [[vk::binding(1, 0)]] RWStructuredBuffer<float> out_y;
        [shader("compute")]
        [numthreads(256, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID) {
            if (tid.x < xnumel)
                out_y[tid.x] = in_x[tid.x] * 2.0f;
        }
        """

        src_static = """
        static const uint xnumel = 65536;
        [[vk::binding(0, 0)]] StructuredBuffer<float> in_x;
        [[vk::binding(1, 0)]] RWStructuredBuffer<float> out_y;
        [shader("compute")]
        [numthreads(256, 1, 1)]
        void computeMain(uint3 tid : SV_DispatchThreadID) {
            if (tid.x < xnumel)
                out_y[tid.x] = in_x[tid.x] * 2.0f;
        }
        """

        spv_spec = compile_slang_to_spirv(src_spec, cache_key="dr4_spec_v3")
        spv_static = compile_slang_to_spirv(src_static, cache_key="dr4_static_v3")

        # Both must compile to valid SPIR-V (magic number check).
        for label, spv in (("spec", spv_spec), ("static", spv_static)):
            assert spv[:4] == b"\x03\x02\x23\x07", (
                f"DR.4 fail: {label} SPIR-V missing magic number"
            )

        # Spec-constant form must have OpSpecConstant decorations.
        spec = parse_spec_constants(spv_spec)
        assert len(spec) == 1, f"DR.4 fail: expected 1 spec constant, got {spec}"
        assert spec[0] == (0, 65536), f"DR.4 fail: expected (0, 65536), got {spec[0]}"

        # Static-const form must NOT have spec constants.
        spec_static = parse_spec_constants(spv_static)
        assert len(spec_static) == 0, (
            f"DR.4 fail: static-const should have 0 spec constants, got {spec_static}"
        )

    def test_dr4_pointwise_kernel_emits_spec_constants(self):
        """A real Inductor pointwise kernel compiles and produces correct
        results with spec_constants enabled (default)."""
        import torch_vulkan

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.relu(x * 0.5 + 0.1)

        x = torch.randn(64, 128, device="vulkan:0")
        result = fn(x)
        expected = torch.relu(x.cpu() * 0.5 + 0.1)
        torch.testing.assert_close(result.cpu(), expected, rtol=1e-2, atol=1e-2)

    def test_dr4_reduction_kernel_emits_spec_constants(self):
        """A reduction kernel (sum) uses spec constants for static numels."""
        import torch_vulkan

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.sum(x, dim=-1)

        x = torch.randn(16, 256, device="vulkan:0")

        result = fn(x)
        expected = torch.sum(x.cpu(), dim=-1)
        torch.testing.assert_close(result.cpu(), expected, rtol=1e-2, atol=1e-2)

    def test_dr4_template_mm_kernel_compiles(self):
        """Matrix multiply template compiles and produces correct results
        with spec constants enabled by default."""
        import torch_vulkan

        @torch.compile(backend="inductor")
        def fn(x, w):
            return torch.nn.functional.linear(x, w)

        x = torch.randn(4, 32, device="vulkan:0")
        w = torch.randn(64, 32, device="vulkan:0")

        result = fn(x, w)
        expected = torch.nn.functional.linear(x.cpu(), w.cpu())
        torch.testing.assert_close(result.cpu(), expected, rtol=1e-2, atol=1e-2)


class TestN17StaticSpecialization:
    """N+1.7 — Static shape specialization for fully-static kernels.

    When ALL dimensions and numels are static (known sympy.Integer),
    the push-constant struct is skipped entirely and all sizevars are
    emitted as ``static const uint`` module-scope declarations. Slangc
    constant-folds loop bounds and eliminates dead branches.
    """

    def test_n17_feature_gate_default_on(self):
        """static_specialization() returns True by default."""
        from torch_vulkan.inductor.config import static_specialization

        assert static_specialization(), (
            "N+1.7 fail: static_specialization() should be True by default"
        )

    def test_n17_feature_gate_can_be_disabled(self):
        """TORCH_VULKAN_STATIC_SPECIALIZATION=0 disables the path."""
        old = os.environ.get("TORCH_VULKAN_STATIC_SPECIALIZATION")
        os.environ["TORCH_VULKAN_STATIC_SPECIALIZATION"] = "0"
        try:
            # Force reload of config to pick up env var change.
            import importlib

            from torch_vulkan.inductor import config

            importlib.reload(config)
            assert not config.static_specialization(), (
                "N+1.7 fail: with env=0, static_specialization() should be False"
            )
        finally:
            if old is not None:
                os.environ["TORCH_VULKAN_STATIC_SPECIALIZATION"] = old
            else:
                os.environ.pop("TORCH_VULKAN_STATIC_SPECIALIZATION", None)
            # Restore default config
            import importlib

            from torch_vulkan.inductor import config

            importlib.reload(config)

    def test_n17_static_kernel_has_no_push_constant_struct(self):
        """A fully-static kernel's Slang source must NOT contain 'struct PC'."""
        import torch_vulkan
        from torch_vulkan.inductor.config import static_specialization

        # Only run when specialization is enabled.
        if not static_specialization():
            return

        captured_src: list[str] = []

        original = None
        try:
            from torch_vulkan.inductor.kernel import header as header_mod

            original = header_mod.HeaderMixin.codegen_kernel

            def _patched_codegen_kernel(self, name=None):
                result = original(self, name)
                captured_src.append(result)
                return result

            header_mod.HeaderMixin.codegen_kernel = _patched_codegen_kernel

            @torch.compile(backend="inductor")
            def fn(x):
                return torch.relu(x * 0.5 + 0.1)

            x = torch.randn(64, 128, device="vulkan:0")
            result = fn(x)
            expected = torch.relu(x.cpu() * 0.5 + 0.1)
            torch.testing.assert_close(result.cpu(), expected, rtol=1e-2, atol=1e-2)

            assert len(captured_src) >= 1, "N+1.7 fail: no kernel source captured"
            for src in captured_src:
                # Fully-static kernel must NOT have a push-constant struct.
                assert "struct PC" not in src, (
                    f"N+1.7 fail: fully-static kernel should not emit 'struct PC', "
                    f"but found it in:\n{src}"
                )
        finally:
            if original is not None:
                header_mod.HeaderMixin.codegen_kernel = original

    def test_n17_static_kernel_emits_static_const_for_sizevars(self):
        """A fully-static kernel emits 'static const uint' for sizevars,
        not 'pc.' references."""
        import torch_vulkan
        from torch_vulkan.inductor.config import static_specialization

        if not static_specialization():
            return

        captured_src: list[str] = []

        def spy_on_header(src):
            captured_src.append(src)
            return src

        original = None
        try:
            from torch_vulkan.inductor.kernel import header as header_mod

            original = header_mod.HeaderMixin.codegen_kernel

            def _patched_codegen_kernel(self, name=None):
                result = original(self, name)
                captured_src.append(result)
                return result

            header_mod.HeaderMixin.codegen_kernel = _patched_codegen_kernel

            @torch.compile(backend="inductor")
            def fn(x):
                return torch.relu(x * 0.5 + 0.1)

            x = torch.randn(64, 128, device="vulkan:0")
            result = fn(x)
            expected = torch.relu(x.cpu() * 0.5 + 0.1)
            torch.testing.assert_close(result.cpu(), expected, rtol=1e-2, atol=1e-2)

            assert len(captured_src) >= 1, "N+1.7 fail: no kernel source captured"
            for src in captured_src:
                # Must contain static const uint declarations for sizevars.
                has_static_const = "static const uint" in src
                # Must NOT have pc. references (push constant reads).
                has_pc_read = "pc." in src or "= pc." in src
                assert has_static_const, (
                    f"N+1.7 fail: fully-static kernel should emit "
                    f"'static const uint' for sizevars, but found none in:\n{src}"
                )
                assert not has_pc_read, (
                    f"N+1.7 fail: fully-static kernel should NOT have 'pc.' "
                    f"references, but found them in:\n{src}"
                )
        finally:
            if original is not None:
                header_mod.HeaderMixin.codegen_kernel = original

    def test_n17_static_kernel_correctness(self):
        """A fully-static kernel produces correct results with N+1.7 enabled."""
        import torch_vulkan

        @torch.compile(backend="inductor")
        def fn(x):
            return torch.relu(x * 0.5 + 0.1)

        x = torch.randn(64, 128, device="vulkan:0")
        result = fn(x)
        expected = torch.relu(x.cpu() * 0.5 + 0.1)
        torch.testing.assert_close(result.cpu(), expected, rtol=1e-2, atol=1e-2)

    def test_n17_dynamic_kernel_still_uses_push_constants(self):
        """When dynamic shapes are enabled, the PC path is still used."""
        import torch_vulkan

        captured_src: list[str] = []

        original = None
        try:
            from torch_vulkan.inductor.kernel import header as header_mod

            original = header_mod.HeaderMixin.codegen_kernel

            def _patched_codegen_kernel(self, name=None):
                result = original(self, name)
                captured_src.append(result)
                return result

            header_mod.HeaderMixin.codegen_kernel = _patched_codegen_kernel

            # Enable dynamic shapes to force the PC path.
            old_dynamic = os.environ.get("TORCH_VULKAN_DYNAMIC_SHAPES")
            os.environ["TORCH_VULKAN_DYNAMIC_SHAPES"] = "1"
            try:
                import importlib

                from torch_vulkan.inductor import config

                importlib.reload(config)
            except Exception:
                pass

            try:

                @torch.compile(backend="inductor", dynamic=True)
                def fn(x):
                    return torch.relu(x * 0.5 + 0.1)

                x = torch.randn(64, 128, device="vulkan:0")
                result = fn(x)
                expected = torch.relu(x.cpu() * 0.5 + 0.1)
                torch.testing.assert_close(result.cpu(), expected, rtol=1e-2, atol=1e-2)

                # With dynamic shapes, the kernel should still have a PC struct.
                # (Only applicable if the kernel was actually compiled with
                # dynamic shapes; some inductor configs may still treat it as
                # static.)
                if captured_src:
                    # At least one of the kernels (if multiple) should have PC.
                    any_pc = any("struct PC" in s for s in captured_src)
                    # Not a hard failure, just informational — dynamic shapes
                    # may still resolve to static at compile time.
            finally:
                if old_dynamic is not None:
                    os.environ["TORCH_VULKAN_DYNAMIC_SHAPES"] = old_dynamic
                else:
                    os.environ.pop("TORCH_VULKAN_DYNAMIC_SHAPES", None)
                import importlib

                from torch_vulkan.inductor import config

                importlib.reload(config)
        finally:
            if original is not None:
                header_mod.HeaderMixin.codegen_kernel = original


class TestDR7ReflectionRouting:
    """DR.7 — Compile-time reflection routing.

    Verifies:
    - Feature flag ``TORCH_VULKAN_REFLECTION_ROUTING`` gates the two-pass path
    - Heavy kernels (high VGPR count) get fewer numthreads after re-compile
    - Different numthreads produce different in-memory cache entries
    - Two-pass compilation produces correct numerical results
    """

    def test_dr7_reflection_routing_feature_flag(self):
        """reflection_routing() returns False by default (feature is off)."""
        old_val = os.environ.pop("TORCH_VULKAN_REFLECTION_ROUTING", None)
        try:
            val = os.environ.get("TORCH_VULKAN_REFLECTION_ROUTING", "0")
            assert val == "0", f"DR.7 fail: default should be '0' (off), got {val!r}"
        finally:
            if old_val is not None:
                os.environ["TORCH_VULKAN_REFLECTION_ROUTING"] = old_val

    def test_dr7_reflection_routing_can_be_enabled(self):
        """TORCH_VULKAN_REFLECTION_ROUTING=1 enables the path."""
        os.environ["TORCH_VULKAN_REFLECTION_ROUTING"] = "1"
        try:
            val = os.environ.get("TORCH_VULKAN_REFLECTION_ROUTING", "0")
            assert val == "1", (
                f"DR.7 fail: with env=1, value should be '1', got {val!r}"
            )
        finally:
            os.environ.pop("TORCH_VULKAN_REFLECTION_ROUTING", None)

    def test_dr7_heavy_kernel_gets_fewer_threads(self):
        """A shader with high VGPR count (>64) gets fewer numthreads
        than a shader with low VGPR count (≤32) when the heuristic is
        applied."""
        from torch_vulkan.inductor.runtime import _pick_numthreads_from_reflection

        # Light kernel: 24 VGPRs → should get 256 threads.
        nt_light = _pick_numthreads_from_reflection(
            vgprs=24,
            current_numthreads=(256, 1, 1),
        )
        assert nt_light == (256, 1, 1), (
            f"DR.7 fail: light kernel (24 VGPRs) should get 256 threads, got {nt_light}"
        )

        # Heavy kernel: 80 VGPRs → should get 64 threads.
        nt_heavy = _pick_numthreads_from_reflection(
            vgprs=80,
            current_numthreads=(256, 1, 1),
        )
        assert nt_heavy == (64, 1, 1), (
            f"DR.7 fail: heavy kernel (80 VGPRs) should get 64 threads, got {nt_heavy}"
        )

        # Very heavy kernel: 160 VGPRs → should get 32 threads.
        nt_very_heavy = _pick_numthreads_from_reflection(
            vgprs=160,
            current_numthreads=(256, 1, 1),
        )
        assert nt_very_heavy == (32, 1, 1), (
            f"DR.7 fail: very heavy kernel (160 VGPRs) should get 32 threads, "
            f"got {nt_very_heavy}"
        )

        # Heavy kernel should get fewer threads than light kernel.
        assert nt_heavy[0] < nt_light[0], (
            f"DR.7 fail: heavy ({nt_heavy[0]}) should be < light ({nt_light[0]})"
        )

    def test_dr7_cache_key_includes_numthreads(self):
        """Same shader source with different numthreads produces
        different cache hash keys (because numthreads are part of the
        source text)."""
        src_template = """
        [[vk::binding(0, 0)]] StructuredBuffer<float> in_x;
        [[vk::binding(1, 0)]] RWStructuredBuffer<float> out_y;
        [shader("compute")]
        [numthreads({nt_x}, {nt_y}, {nt_z})]
        void computeMain(uint3 tid : SV_DispatchThreadID) {{
            out_y[tid.x] = in_x[tid.x] * 2.0f;
        }}
        """
        src_256 = src_template.format(nt_x=256, nt_y=1, nt_z=1)
        src_128 = src_template.format(nt_x=128, nt_y=1, nt_z=1)
        src_64 = src_template.format(nt_x=64, nt_y=1, nt_z=1)

        import hashlib

        from torch_vulkan.inductor.runtime import _normalize_slang_source

        h256 = hashlib.sha256(
            ("computeMain\n" + _normalize_slang_source(src_256)).encode()
        ).hexdigest()
        h128 = hashlib.sha256(
            ("computeMain\n" + _normalize_slang_source(src_128)).encode()
        ).hexdigest()
        h64 = hashlib.sha256(
            ("computeMain\n" + _normalize_slang_source(src_64)).encode()
        ).hexdigest()

        assert h256 != h128, (
            f"DR.7 fail: 256 vs 128 threads should differ, both got {h256[:16]}"
        )
        assert h256 != h64, (
            f"DR.7 fail: 256 vs 64 threads should differ, both got {h256[:16]}"
        )
        assert h128 != h64, (
            f"DR.7 fail: 128 vs 64 threads should differ, both got {h128[:16]}"
        )

    def test_dr7_numthreads_parsing(self):
        """_parse_numthreads_from_source correctly extracts numthreads."""
        from torch_vulkan.inductor.runtime import _parse_numthreads_from_source

        src = '[shader("compute")]\n[numthreads(256, 1, 1)]\nvoid main() {}'
        nt = _parse_numthreads_from_source(src)
        assert nt == (256, 1, 1), f"DR.7 fail: expected (256,1,1), got {nt}"

        src2 = '[shader("compute")]\n[numthreads(64, 4, 2)]\nvoid main() {}'
        nt2 = _parse_numthreads_from_source(src2)
        assert nt2 == (64, 4, 2), f"DR.7 fail: expected (64,4,2), got {nt2}"

        # No numthreads → None
        src3 = '[shader("compute")]\nvoid main() {}'
        nt3 = _parse_numthreads_from_source(src3)
        assert nt3 is None, f"DR.7 fail: expected None, got {nt3}"

    def test_dr7_numthreads_rewrite(self):
        """_rewrite_numthreads_in_source replaces numthreads correctly."""
        from torch_vulkan.inductor.runtime import _rewrite_numthreads_in_source

        src = '[shader("compute")]\n[numthreads(256, 1, 1)]\nvoid main() {}'
        new_src = _rewrite_numthreads_in_source(src, (64, 1, 1))
        assert "[numthreads(64, 1, 1)]" in new_src, (
            f"DR.7 fail: rewrite did not produce expected numthreads: {new_src}"
        )
        assert "[numthreads(256, 1, 1)]" not in new_src, (
            f"DR.7 fail: old numthreads still present after rewrite: {new_src}"
        )

    def test_dr7_two_pass_does_not_break_correctness(self):
        """A simple pointwise shader compiles and produces correct
        results with reflection routing enabled."""
        os.environ["TORCH_VULKAN_REFLECTION_ROUTING"] = "1"
        os.environ["TORCH_VULKAN_REFLECTION"] = "1"
        try:
            # Clear caches so we exercise the two-pass path fresh.
            from torch_vulkan.inductor.runtime import (
                _cache_by_hash,
                _cache_by_key,
                _reflection_metrics_by_hash,
                _reflection_metrics_by_key,
                compile_slang_to_spirv,
                reset_per_test_caches,
            )

            reset_per_test_caches()

            src = """
            [[vk::binding(0, 0)]] StructuredBuffer<float> in_x;
            [[vk::binding(1, 0)]] RWStructuredBuffer<float> out_y;
            [shader("compute")]
            [numthreads(256, 1, 1)]
            void computeMain(uint3 tid : SV_DispatchThreadID) {
                out_y[tid.x] = in_x[tid.x] * 2.0f + 1.0f;
            }
            """
            spv = compile_slang_to_spirv(
                src,
                cache_key="dr7_correctness_test",
            )
            # Must produce valid SPIR-V (magic number).
            assert spv[:4] == b"\x03\x02\x23\x07", (
                "DR.7 fail: SPIR-V missing magic number"
            )
            # Should have non-zero size.
            assert len(spv) > 100, f"DR.7 fail: SPIR-V too small ({len(spv)} bytes)"
        finally:
            os.environ.pop("TORCH_VULKAN_REFLECTION_ROUTING", None)
            os.environ.pop("TORCH_VULKAN_REFLECTION", None)

    def test_dr7_pick_numthreads_fallback_on_none(self):
        """_pick_numthreads_from_reflection falls back to current
        numthreads when VGPR count is None."""
        from torch_vulkan.inductor.runtime import _pick_numthreads_from_reflection

        nt = _pick_numthreads_from_reflection(
            vgprs=None,
            current_numthreads=(128, 1, 1),
        )
        assert nt == (128, 1, 1), (
            f"DR.7 fail: fallback should return current (128,1,1), got {nt}"
        )

    def test_dr7_pick_numthreads_boundary_values(self):
        """_pick_numthreads_from_reflection at boundary VGPR values."""
        from torch_vulkan.inductor.runtime import _pick_numthreads_from_reflection

        # Exactly 32 VGPRs → should get 256 (≤32 threshold).
        nt = _pick_numthreads_from_reflection(
            vgprs=32,
            current_numthreads=(256, 1, 1),
        )
        assert nt == (256, 1, 1), f"DR.7 fail: 32 VGPRs → 256, got {nt}"

        # Exactly 33 VGPRs → should get 128 (33-64 range).
        nt = _pick_numthreads_from_reflection(
            vgprs=33,
            current_numthreads=(256, 1, 1),
        )
        assert nt == (128, 1, 1), f"DR.7 fail: 33 VGPRs → 128, got {nt}"

        # Exactly 64 VGPRs → should get 128 (33-64 range).
        nt = _pick_numthreads_from_reflection(
            vgprs=64,
            current_numthreads=(256, 1, 1),
        )
        assert nt == (128, 1, 1), f"DR.7 fail: 64 VGPRs → 128, got {nt}"

        # Exactly 65 VGPRs → should get 64 (65-128 range).
        nt = _pick_numthreads_from_reflection(
            vgprs=65,
            current_numthreads=(256, 1, 1),
        )
        assert nt == (64, 1, 1), f"DR.7 fail: 65 VGPRs → 64, got {nt}"

        # Exactly 128 VGPRs → should get 64 (65-128 range).
        nt = _pick_numthreads_from_reflection(
            vgprs=128,
            current_numthreads=(256, 1, 1),
        )
        assert nt == (64, 1, 1), f"DR.7 fail: 128 VGPRs → 64, got {nt}"

        # Exactly 129 VGPRs → should get 32 (>128).
        nt = _pick_numthreads_from_reflection(
            vgprs=129,
            current_numthreads=(256, 1, 1),
        )
        assert nt == (32, 1, 1), f"DR.7 fail: 129 VGPRs → 32, got {nt}"


class TestD2aDynamicReductionCodegen:
    """D.2.a — Dynamic reduction codegen (HB.3).

    Validates that reductions (sum, mean) over dynamic batch dimensions
    compile without ``DynamicShapeNotImplemented`` and produce results
    matching CPU across multiple batch sizes.
    """

    def test_d2a_dynamic_batch_reduction_compiles(self):
        """Sum over dynamic batch compiles without NotImplementedError."""
        import os

        if not os.environ.get("SLANGC"):
            import pytest

            pytest.skip("SLANGC env var not set")

        os.environ["TORCH_VULKAN_DYNAMIC_SHAPES"] = "1"
        try:

            @torch.compile(backend="inductor", dynamic=True)
            def fn(x):
                return torch.sum(x, dim=0)

            x = torch.randn(4, 128, device="vulkan:0")
            fn(x)  # warmup — must not raise DynamicShapeNotImplemented
        finally:
            del os.environ["TORCH_VULKAN_DYNAMIC_SHAPES"]

    def test_d2a_dynamic_batch_reduction_correct(self):
        """Sum over dynamic batch matches CPU across multiple batch sizes."""
        import os

        if not os.environ.get("SLANGC"):
            import pytest

            pytest.skip("SLANGC env var not set")

        os.environ["TORCH_VULKAN_DYNAMIC_SHAPES"] = "1"
        try:
            torch.manual_seed(0)

            @torch.compile(backend="inductor", dynamic=True)
            def fn(x):
                return torch.sum(x, dim=0)

            # Warmup
            fn(torch.randn(4, 128, device="vulkan:0"))

            for B in [3, 7, 13, 32]:
                x_cpu = torch.randn(B, 128)
                x_vk = x_cpu.to("vulkan:0")
                out_vk = fn(x_vk)
                out_cpu = torch.sum(x_cpu, dim=0)
                torch.testing.assert_close(
                    out_vk.cpu(),
                    out_cpu,
                    rtol=1e-3,
                    atol=1e-3,
                    msg=f"dynamic sum dim=0 batch={B} diverged from CPU",
                )
        finally:
            del os.environ["TORCH_VULKAN_DYNAMIC_SHAPES"]

